-- Poems batch 228
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('3c204a66-3293-45aa-aded-f945bd8b02d6','答人放言','邵雍','宋','宋诗','song-poetry','','[]','經時不見意何如，重出新詩笑語初。',64,'全唐诗/poet.song.21000.json','["經時不見意何如，重出新詩笑語初。", "物理悟來添性淡，天心到後覺情疎。", "已全孟樂君無限，示識蘧非我有餘。", "大率空名如所論，此身甘老在樵漁。"]'),
('0154abe9-3d24-42fa-9444-176e5acc4500','賀人致政','邵雍','宋','宋诗','song-poetry','','[]','人情大率喜爲官，達士可嘗有所牽。',64,'全唐诗/poet.song.21000.json','["人情大率喜爲官，達士可嘗有所牽。", "解印本非嫌薄祿，掛冠殊不爲高年。", "因通物性興衰理，遂悟天心用捨權。", "宜放襟懷在清影，吾鄉況有好林泉。"]'),
('0bbd99d6-d179-48d5-95de-58d61730e314','放言','邵雍','宋','宋诗','song-poetry','','[]','既得希夷樂，曾無寵辱驚。',48,'全唐诗/poet.song.21000.json','["既得希夷樂，曾無寵辱驚。", "泥空終日著，齊物到頭爭。", "忽忽閑拈筆，時時自寫名。", "誰能苦真性，情外更生情。"]'),
('354ab9f3-d9ec-4c49-b371-1be7fb543f36','初秋','邵雍','宋','宋诗','song-poetry','','[]','夏去暑猶在，雨餘凉始來。',48,'全唐诗/poet.song.21000.json','["夏去暑猶在，雨餘凉始來。", "階前已流水，天外尚驚雷。", "曲几靜中隠，衡門閑處開。", "壯心都已矣，何事更裝懷。"]'),
('1ba19c41-b138-4d41-944f-0a7ae6207d29','偶書','邵雍','宋','宋诗','song-poetry','','[]','堪笑又堪嗟，人生果若何。',48,'全唐诗/poet.song.21000.json','["堪笑又堪嗟，人生果若何。", "宜將萬端事，都入一聲歌。", "世態逾翻掌，年光劇逝波。", "靜中真氣味，所得不勝多。"]'),
('2612ea8e-a2ba-4cd5-856f-b203cefd65dd','傷足','邵雍','宋','宋诗','song-poetry','','[]','災由無妄得，爲患固非深。',48,'全唐诗/poet.song.21000.json','["災由無妄得，爲患固非深。", "乖己攝生理，貽親憂慮心。", "乍然艱步履，偶爾阻登臨。", "逾月方能出，難忘樂正箴。"]'),
('e36253b6-65fa-4a92-a576-818340261771','閑行','邵雍','宋','宋诗','song-poetry','','[]','園圃正蕭然，行吟遶澤邊。',48,'全唐诗/poet.song.21000.json','["園圃正蕭然，行吟遶澤邊。", "風驚初社後，葉墜未霜前。", "衰草襯斜日，暮雲扶遠天。", "何當見真象，止可入無言。"]'),
('004dc1ec-0c88-4ac6-9100-3113f198492c','晨起','邵雍','宋','宋诗','song-poetry','','[]','山高水復深，無計奈而今。',48,'全唐诗/poet.song.21000.json','["山高水復深，無計奈而今。", "地盡一時事，天開萬古心。", "輕烟籠曉閣，微雨散青林。", "此景雖平淡，人間何處尋。"]'),
('9d817972-0233-48a2-9088-9af3f28cbb06','月夜','邵雍','宋','宋诗','song-poetry','','[]','雨霽風自好，秋深天未寒。',48,'全唐诗/poet.song.21000.json','["雨霽風自好，秋深天未寒。", "移牀就階下，看月出林端。", "有酒欲共飲，無賓可同歡。", "他時遇良友，此景復求難。"]'),
('e9f56111-2fec-46e6-8f3c-ea3caa3f01d0','盆池','邵雍','宋','宋诗','song-poetry','','[]','三五小圓荷，盆容水不多。',48,'全唐诗/poet.song.21000.json','["三五小圓荷，盆容水不多。", "雖非大藪澤，亦有小風波。", "粗起江湖趣，殊無鴛鷺過。", "幽人興難遏，時遶醉吟哦。"]'),
('a4f81ec5-6a3e-443a-9e11-771b9f9a9ee6','遊山二首  其一','邵雍','宋','宋诗','song-poetry','','[]','洛川多好山，伊川多美竹。',48,'全唐诗/poet.song.21000.json','["洛川多好山，伊川多美竹。", "遊既各有時，雖頻無倦目。", "貪清非傷廉，瀆幽不爲辱。", "麋鹿不害人，心無害麋鹿。"]'),
('50ccfdd8-1f1a-4cbf-8b68-e588fac06bd2','遊山二首  其二','邵雍','宋','宋诗','song-poetry','','[]','二室多好峯，三川多好雲。',48,'全唐诗/poet.song.21000.json','["二室多好峯，三川多好雲。", "看之不知倦，和氣潜生神。", "一慮若動蕩，萬事從紛紜。", "人言無事貴，身爲無事人。"]'),
('f8c688d9-d30d-41cc-b653-9044f7a78e94','龍門道中作','邵雍','宋','宋诗','song-poetry','','[]','物理人情自可明，何嘗慼慼向平生。',64,'全唐诗/poet.song.21000.json','["物理人情自可明，何嘗慼慼向平生。", "卷舒在我有成筭，用捨隨時無定名。", "滿目雲山俱是樂，一毫榮辱不須驚。", "侯門見說深如海，三十年來掉臂行。"]'),
('ad1a75e9-21a1-4404-8746-7417783ca7c0','名利吟','邵雍','宋','宋诗','song-poetry','','[]','名利到頭非樂事，風波終久少安流。',64,'全唐诗/poet.song.21000.json','["名利到頭非樂事，風波終久少安流。", "稍鄰美譽無多取，纔近清歡與賸求。", "美譽既多須有患，清歡雖賸且無憂。", "滔滔天下曾知否，覆轍相尋卒未休。"]'),
('cf4a7229-70bd-40fc-966d-013331d959c8','何事吟','邵雍','宋','宋诗','song-poetry','','[]','何事教人用意深，出塵些子索沉吟。',64,'全唐诗/poet.song.21000.json','["何事教人用意深，出塵些子索沉吟。", "施爲欲似千鈞弩，磨礪當如百鍊金。", "釣水誤持生殺柄，著棋閑動戰爭心。", "一盃美酒聊康濟，林下時時或自斟。"]'),
('19511837-3b5b-4866-8ee6-85cd266b8b0c','三十年吟','邵雍','宋','宋诗','song-poetry','','[]','三十年間更一世，其間堪笑復堪愁。',64,'全唐诗/poet.song.21000.json','["三十年間更一世，其間堪笑復堪愁。", "天生天殺何嘗盡，人是人非殊未休。", "善偶鴛鴦頭早白，能啼杜宇血先流。", "須知却被才爲害，及至無才又却憂。"]'),
('45b4d954-4caa-4820-9f8e-49ef5568adf7','遊洛川初出厚載門','邵雍','宋','宋诗','song-poetry','','[]','初出都門外，西南指洛陬。',48,'全唐诗/poet.song.21000.json','["初出都門外，西南指洛陬。", "山川開遠意，天地掛雙眸。", "村落桑榆晚，田家禾黍秋。", "民間有此樂，何必待封侯。"]'),
('a9435495-e821-4ec7-b6a0-1eb44c9c199f','宿延秋莊','邵雍','宋','宋诗','song-poetry','','[]','驅車入洛川，下馬弄飛泉。',48,'全唐诗/poet.song.21000.json','["驅車入洛川，下馬弄飛泉。", "乍有雲山樂，殊無朝市喧。", "非唯快心志，自可忘形言。", "借問塵中有，誰爲得手先。"]'),
('2634ad05-52df-41e1-96d2-6949e656877a','宿壽安西寺','邵雍','宋','宋诗','song-poetry','','[]','好景信移情，直連毛骨誠。',48,'全唐诗/poet.song.21000.json','["好景信移情，直連毛骨誠。", "爲憐多勝槩，尤喜近都城。", "竹色交山色，松聲亂水聲。", "豈辭終日愛，解榻傍虛楹。"]'),
('2af02997-bb19-4ae8-aeba-7d119b13a72a','過永濟橋二首  其一','邵雍','宋','宋诗','song-poetry','','[]','山背錦幈開，河臨永濟迴。',48,'全唐诗/poet.song.21000.json','["山背錦幈開，河臨永濟迴。", "土田平似掌，桑柘大如槐。", "斜日射虹去，低雲將雨來。", "無涯負清景，長是愧非才。"]'),
('08cb2f98-1d74-445f-add1-39eff19c70f0','過永濟橋二首  其二','邵雍','宋','宋诗','song-poetry','','[]','一水一溪門，溪門雲復屯。',48,'全唐诗/poet.song.21000.json','["一水一溪門，溪門雲復屯。", "珍禽轉喬木，幽鹿走荒榛。", "雨脚拖平地，稻畦扶遠村。", "高城半頹缺，興廢事休論。"]'),
('568146ad-227c-4cd6-8667-b3df7d1685bd','至福昌縣作','邵雍','宋','宋诗','song-poetry','','[]','清景幾人愛，愛之當遠尋。',48,'全唐诗/poet.song.21000.json','["清景幾人愛，愛之當遠尋。", "及臨韓嶽近，始見洛川深。", "縣在雲山腹，民居水竹心。", "無機類閑物，愈覺少知音。"]'),
('11715fe5-2049-433d-99f6-def37ada5ede','燕堂即事','邵雍','宋','宋诗','song-poetry','','[]','川上數峯青，林間一水明。',48,'全唐诗/poet.song.21000.json','["川上數峯青，林間一水明。", "閑雲無定體，幽鳥不知名。", "遊侶既非約，歸期莫計程。", "錙銖人世事，休强作威獰。"]'),
('9d9b2922-9179-49a7-bc4f-cb4510c55c0c','上寺看南山','邵雍','宋','宋诗','song-poetry','','[]','疊疊是峯巒，西連梁雍寬。',48,'全唐诗/poet.song.21000.json','["疊疊是峯巒，西連梁雍寬。", "與其行裏看，不若坐中觀。", "包括經唐漢，并吞歷晉韓。", "消沉事難問，唯爾尚巑岏。"]'),
('34031263-45c9-4ba0-871f-306425b4a9f4','縣尉廨宇蓮池','邵雍','宋','宋诗','song-poetry','','[]','縣尉小齋前，水清池有蓮。',48,'全唐诗/poet.song.21000.json','["縣尉小齋前，水清池有蓮。", "豈唯觀菡萏，兼可聽潺湲。", "宛類江湖上，殊非塵土邊。", "古人用心處，料得不徒然。"]'),
('d3340c7c-ece9-4832-b883-5a6172382040','女几祠','邵雍','宋','宋诗','song-poetry','','[]','西南有高山，山在杳冥間。',48,'全唐诗/poet.song.21000.json','["西南有高山，山在杳冥間。", "神仙不可見，滿目空雲煙。", "千年女几祠，門臨洛水邊。", "但聞霓裳曲，世人猶或傳。"]'),
('a942ba12-caf3-4ea7-a479-8f25b25831ac','故連昌宮','邵雍','宋','宋诗','song-poetry','','[]','洛水來西南，昌水來西北。',48,'全唐诗/poet.song.21000.json','["洛水來西南，昌水來西北。", "二水合流處，宮牆有遺壁。", "行人徒想像，往事皆陳迹。", "空餘女几山，正對三鄉驛。"]'),
('103aa29e-b5ff-4272-b73e-9e07966eed9d','川上懷舊  其一','邵雍','宋','宋诗','song-poetry','','[]','去秋遊洛源，今秋遊洛川。',48,'全唐诗/poet.song.21000.json','["去秋遊洛源，今秋遊洛川。", "川水雖無情，人心剛悄然。", "目亂千萬山，一山一重煙。", "山盡煙不盡，煙與天相連。"]'),
('6124c491-723f-4477-92c5-fc33b8dbf926','川上懷舊  其二','邵雍','宋','宋诗','song-poetry','','[]','田夫忙治禾，水禽閑求魚。',48,'全唐诗/poet.song.21000.json','["田夫忙治禾，水禽閑求魚。", "二者皆苦食，動靜何相殊。", "事過見休慼，時來知卷舒。", "回顧此二物，易地還何如。"]'),
('7418ce61-a44e-4298-ac1c-398dbfe71318','川上懷舊  其三','邵雍','宋','宋诗','song-poetry','','[]','爲今日之山，是昔日之原。',48,'全唐诗/poet.song.21000.json','["爲今日之山，是昔日之原。", "爲今日之原，是昔日之川。", "山川尚如此，人事宜信然。", "幸免紅塵中，隨風浪著鞭。"]'),
('3177938e-66b0-4d34-bcfd-90e33e5a3f69','川上懷舊  其四','邵雍','宋','宋诗','song-poetry','','[]','地逈川原闊，村孤煙水閑。',48,'全唐诗/poet.song.21000.json','["地逈川原闊，村孤煙水閑。", "雷輕龍過浦，雲亂雨移山。", "田者荷鋤去，漁人背網還。", "伊予獨霑濕，猶在道途間。"]'),
('a46da5d0-a1a3-4d47-acb1-715354c58e89','燕堂暑飲','邵雍','宋','宋诗','song-poetry','','[]','燕堂通高明，簷依斷崖嶔。',48,'全唐诗/poet.song.21000.json','["燕堂通高明，簷依斷崖嶔。", "凉風來松梢，清泉飛竹陰。", "佳果間紅綠，旨酒隨淺深。", "却思闤闠間，鬰蒸不可任。"]'),
('e8327ed0-879e-4ff2-a505-141828e8fd5f','燕堂閑坐','邵雍','宋','宋诗','song-poetry','','[]','天網疎難漏，世網密莫通。',48,'全唐诗/poet.song.21000.json','["天網疎難漏，世網密莫通。", "我心久不動，一脫二網中。", "高竹漱清泉，長松迎清風。", "此時逢此景，正與此心同。"]'),
('4fd1d7c1-e96f-4aaf-a7a8-0267535d48e6','立秋日川上作','邵雍','宋','宋诗','song-poetry','','[]','富貴固難愛，貧寒易得愁。',48,'全唐诗/poet.song.21000.json','["富貴固難愛，貧寒易得愁。", "休將少時態，移作老年羞。", "既有非常樂，須防不測憂。", "誰能保終始，長作國公侯。"]'),
('9a53d614-123e-430a-8857-4158e5459fd5','辨熊耳','邵雍','宋','宋诗','song-poetry','','[]','昔禹別九州，導洛自熊耳。',48,'全唐诗/poet.song.21000.json','["昔禹別九州，導洛自熊耳。", "熊耳自有兩，未審孰爲是。", "東者近成周，西者隔丹水。", "書傳稱上洛，斯言得之矣。"]'),
('a0517073-0355-4dca-80c6-ee58f9ed492a','登女几','邵雍','宋','宋诗','song-poetry','','[]','予看山多矣，未嘗逢此奇。',48,'全唐诗/poet.song.21000.json','["予看山多矣，未嘗逢此奇。", "巨崖如格虎，險石若張旗。", "雲意閑舒卷，巖形屢改移。", "丹青難狀處，四面盡如斯。"]'),
('325edd91-cf8c-4c86-a9b8-743183a9bfe6','川上南望伊川','邵雍','宋','宋诗','song-poetry','','[]','山留禹鑿門，川閣堯水痕。',48,'全唐诗/poet.song.21000.json','["山留禹鑿門，川閣堯水痕。", "古人不復見，古跡尚或存。", "歲月易凋謝，善惡難湮淪。", "無作近名事，强邀世俗尊。"]'),
('dc61c0c7-0dad-4e6b-8810-e9c44d6e5343','牧童','邵雍','宋','宋诗','song-poetry','','[]','隨行笠與簑，未始散天和。',48,'全唐诗/poet.song.21000.json','["隨行笠與簑，未始散天和。", "暖戲荒城側，寒偎古塚阿。", "數聲牛背笛，一曲隴頭歌。", "應是無心問，朝廷事若何。"]'),
('2d25393b-2c8f-4712-8daa-1605dd32894c','夢中吟','邵雍','宋','宋诗','song-poetry','','[]','夢中說夢猶能憶，夢覺夢中還又隔。',64,'全唐诗/poet.song.21000.json','["夢中說夢猶能憶，夢覺夢中還又隔。", "今日恩光空喜歡，當年意愛難尋覓。", "水成流處豈無聲，花到謝時安有色。", "過此相逢陌路人，都如元來曾相識。"]'),
('9e1af69e-fddc-474b-9658-89a7fa0efdff','秋懷三十六首  其一','邵雍','宋','宋诗','song-poetry','','[]','七月夜初長，星斗爭煌煌。',48,'全唐诗/poet.song.21000.json','["七月夜初長，星斗爭煌煌。", "庭除經小雨，枕簟生微凉。", "照物無遁形，虛鑑自有光。", "照事無遁情，虛心自有常。"]'),
('a6aff012-d406-4e59-b636-9b8caacd6642','秋懷三十六首  其二','邵雍','宋','宋诗','song-poetry','','[]','晴窗日初曛，幽庭雨乍洗。',48,'全唐诗/poet.song.21000.json','["晴窗日初曛，幽庭雨乍洗。", "紅蘭靜自披，綠竹閑相倚。", "榮利若浮雲，情懷淡如水。", "身非天外人，意從天外起。"]'),
('4852f639-fe43-4745-a794-7e5fb132b9e0','秋懷三十六首  其三','邵雍','宋','宋诗','song-poetry','','[]','明月生海心，凉風起天末。',48,'全唐诗/poet.song.21000.json','["明月生海心，凉風起天末。", "物象自呈露，襟懷驟披豁。", "悟盡周孔道，解開仁義結。", "禮法本防姦，豈爲吾曹設。"]'),
('34b11fcb-97fc-4131-a865-95008fe7c115','秋懷三十六首  其四','邵雍','宋','宋诗','song-poetry','','[]','疎雨滴高梧，微風挼弱柳。',48,'全唐诗/poet.song.21000.json','["疎雨滴高梧，微風挼弱柳。", "此景歲歲同，世人自白首。", "俗慮易縈仍，塵襟難抖擻。", "浮生已夢中，其間强爲有。"]'),
('466ffeab-c549-4f97-b3ee-7b68d03e27d2','秋懷三十六首  其五','邵雍','宋','宋诗','song-poetry','','[]','清湍文鴛鴦，寒潭繡鸂鶒。',48,'全唐诗/poet.song.21000.json','["清湍文鴛鴦，寒潭繡鸂鶒。", "長天凈如水，不廢秋江碧。", "男子一寸心，壯士萬夫敵。", "菡萏香風中，扁舟會相憶。"]'),
('15639134-5d53-404c-b706-13071bb97752','秋懷三十六首  其六','邵雍','宋','宋诗','song-poetry','','[]','昨日思沃漿，今日思去扇。',48,'全唐诗/poet.song.21000.json','["昨日思沃漿，今日思去扇。", "豈止人戈矛，炎凉自交戰。", "利害生乎情，好尚存乎見。", "欲人爲善人，必須自爲善。"]'),
('5d9fc0dc-e22c-4d8c-b6ed-b944bbb5f62c','秋懷三十六首  其七','邵雍','宋','宋诗','song-poetry','','[]','甘瓜青如藍，紅桃鮮若血。',48,'全唐诗/poet.song.21000.json','["甘瓜青如藍，紅桃鮮若血。", "不忍以手拈，而況用齒齧。", "其色已可愛，其味又更絕。", "食此無珍言，哀哉口與舌。"]'),
('ec1d87bc-742c-4b22-8aeb-94a2d33a6a4e','秋懷三十六首  其八','邵雍','宋','宋诗','song-poetry','','[]','國命在乎民，民命在乎食。',48,'全唐诗/poet.song.21000.json','["國命在乎民，民命在乎食。", "聖人雖復生，斯言固不易。", "虛惠豈足尚，教人以姑息。", "虛名豈足高，教人以緣飾。"]'),
('8c4d0b7c-b1d7-432b-8418-f5ce3c3a4e07','秋懷三十六首  其九','邵雍','宋','宋诗','song-poetry','','[]','周詩云娶妻，周易云歸妹。',48,'全唐诗/poet.song.21000.json','["周詩云娶妻，周易云歸妹。", "七夕世俗情，乞巧兒女態。", "日暮雲雨過，人謂牛女會。", "雲雨本無蹤，牛女豈相配。"]'),
('72254c63-9688-4fc8-94a0-55788e161285','秋懷三十六首  其一○','邵雍','宋','宋诗','song-poetry','','[]','清風無人兼，自可入吾手。',48,'全唐诗/poet.song.21000.json','["清風無人兼，自可入吾手。", "明月無人并，自可入吾牖。", "中心既已平，外物何嘗誘。", "餘事豈足論，但恐樽無酒。"]'),
('8332b748-bd4f-45f2-a25f-e65c6115e229','秋懷三十六首  其一一','邵雍','宋','宋诗','song-poetry','','[]','青蕉葉披敷，碧蘆枝偃亞。',48,'全唐诗/poet.song.21000.json','["青蕉葉披敷，碧蘆枝偃亞。", "風雨蕭蕭天，更漏沉沉夜。", "彼物固無嫌，此情又何訝。", "但念征路人，天涯尚留掛。"]'),
('0252df16-2d70-434b-97d3-dda2a31b460a','秋懷三十六首  其一二','邵雍','宋','宋诗','song-poetry','','[]','淡煙羃踈林，輕風裊寒雨。',48,'全唐诗/poet.song.21000.json','["淡煙羃踈林，輕風裊寒雨。", "日暮人已歸，羣鷄猶啄黍。", "此心固不動，此事極難處。", "一言以蔽之，尚恐費言語。"]'),
('f25179cc-6037-4f33-9378-35b81d6d829b','秋懷三十六首  其一三','邵雍','宋','宋诗','song-poetry','','[]','八月炎凉均，氣味亦自好。',48,'全唐诗/poet.song.21000.json','["八月炎凉均，氣味亦自好。", "臨虛喬木低，遠望行人小。", "有跡事皆妄，無心物都了。", "何須更問辛，願君自食蓼。"]'),
('a924c6a1-e65a-4ac5-a900-92ded3d2a081','秋懷三十六首  其一四','邵雍','宋','宋诗','song-poetry','','[]','黄黍秋正熟，黄鷄秋正肥。',48,'全唐诗/poet.song.21000.json','["黄黍秋正熟，黄鷄秋正肥。", "此物劇易致，古人多重之。", "可以迓賓友，可以奉親闈。", "有褐能卒歲，此外何足爲。"]'),
('608d1ff0-d1e7-47b8-b7f7-1aebd2cb0b5d','秋懷三十六首  其一五','邵雍','宋','宋诗','song-poetry','','[]','稻稌天所生，麴蘗人所製。',48,'全唐诗/poet.song.21000.json','["稻稌天所生，麴蘗人所製。", "釀之命爲酒，飲之可成醉。", "剛者使之柔，懦者使之毅。", "善移造物權，其功亦不細。"]'),
('b136bf8b-632d-44c0-92aa-051cb52f68c3','秋懷三十六首  其一六','邵雍','宋','宋诗','song-poetry','','[]','秋色日漸深，老心日益懶。',48,'全唐诗/poet.song.21000.json','["秋色日漸深，老心日益懶。", "倦即下階行，閑來弄書卷。", "廣陌多風塵，見說難開眼。", "侯門已是深，帝閽又復遠。"]'),
('73576879-9d9d-4bdf-a0c0-f270a71e62b6','秋懷三十六首  其一七','邵雍','宋','宋诗','song-poetry','','[]','塞鴻猶未來，梁燕已辭去。',48,'全唐诗/poet.song.21000.json','["塞鴻猶未來，梁燕已辭去。", "雲山千萬重，相逢在何處。", "岌嶪都城門，繚遶長亭路。", "風土敗人衣，纔新又成故。"]'),
('f3b0d9c7-a89c-4e3e-981d-90782c9360ce','秋懷三十六首  其一八','邵雍','宋','宋诗','song-poetry','','[]','斷續蟬聲外，稀踈鴈下前。',48,'全唐诗/poet.song.21000.json','["斷續蟬聲外，稀踈鴈下前。", "年光空去也，人事益蕭然。", "洗竹留新笋，翻書得舊編。", "誰知養心者，肯與世爭權。"]'),
('939ec8e2-e726-4f4b-bf57-c596c5f4d6bf','秋懷三十六首  其一九','邵雍','宋','宋诗','song-poetry','','[]','中秋光景好，中州煙水奇。',48,'全唐诗/poet.song.21000.json','["中秋光景好，中州煙水奇。", "天重初寒候，人便半醉時。", "榻緣明月掃，襟待好風吹。", "一點胸中事，人間都不知。"]'),
('6a3295b5-5456-4c16-8d7c-7ed6e4dd0682','秋懷三十六首  其二○','邵雍','宋','宋诗','song-poetry','','[]','良月滿高樓，高樓仍中秋。',48,'全唐诗/poet.song.21000.json','["良月滿高樓，高樓仍中秋。", "午夜冷露下，千里寒光流。", "何人將此鑑，拂拭新磨休。", "照破萬古心，白盡萬古頭。"]'),
('d898f6bc-1174-40a2-ac91-76458f4bc00f','秋懷三十六首  其二一','邵雍','宋','宋诗','song-poetry','','[]','寒露綴衰草，凄風摇晚林。',48,'全唐诗/poet.song.21000.json','["寒露綴衰草，凄風摇晚林。", "鳥聲上復下，天氣晴還陰。", "節改一時事，人懷千古心。", "誰云子期死，舉世無知音。"]'),
('3bf11cb2-7630-4375-a3e2-281f95056096','秋懷三十六首  其二二','邵雍','宋','宋诗','song-poetry','','[]','風柳散如梳，霜雲淡如掃。',48,'全唐诗/poet.song.21000.json','["風柳散如梳，霜雲淡如掃。", "高樓破危空，低煙裊寒草。", "此際興不盡，何以戰秋老。", "止可將酒瓶，同向西風倒。"]'),
('8ae80c07-c875-4d6d-96ce-833dd8de4e78','秋懷三十六首  其二三','邵雍','宋','宋诗','song-poetry','','[]','池荷日取敗，籬菊日就榮。',48,'全唐诗/poet.song.21000.json','["池荷日取敗，籬菊日就榮。", "其于品彙間，自與節氣爭。", "盛衰不同時，賢愚難並行。", "安得松桂心，四時長青青。"]'),
('2aa4af64-2be4-4e3f-927f-54bee00114da','秋懷三十六首  其二四','邵雍','宋','宋诗','song-poetry','','[]','人老秋更老，山深水復深。',48,'全唐诗/poet.song.21000.json','["人老秋更老，山深水復深。", "高木已就脫，慧禽空好音。", "筋骸非曩日，道德負初心。", "頼有餘編在，時時尚可尋。"]'),
('f9bdf011-ea8b-44e2-bd3c-5e25c5a65afb','秋懷三十六首  其二五','邵雍','宋','宋诗','song-poetry','','[]','九月氣乍肅，衰柳猶有蟬。',48,'全唐诗/poet.song.21000.json','["九月氣乍肅，衰柳猶有蟬。", "霜外踈鐘斷，風餘清籟傳。", "千山亂遠月，一鶚摩高天。", "自非出世人，而敢危行言。"]'),
('d0c8b0db-da44-440b-8e7e-c50d546c0f0f','秋懷三十六首  其二六','邵雍','宋','宋诗','song-poetry','','[]','飽霜梨多紅，久雨榴自罅。',48,'全唐诗/poet.song.21000.json','["飽霜梨多紅，久雨榴自罅。", "此果世稱珍，厥味是可詫。", "地有百物備，天無一言掛。", "我患尚有言，不得同造化。"]'),
('6f401bc3-9930-432f-b0f8-d56fd90acdf7','秋懷三十六首  其二七','邵雍','宋','宋诗','song-poetry','','[]','惟南有美橘，惟北有美栗。',48,'全唐诗/poet.song.21000.json','["惟南有美橘，惟北有美栗。", "厥包或頗同，厥味信不一。", "天地豈無情，草木皆有實。", "物本不負人，人自負于物。"]'),
('4fd42d83-d86b-4f37-8d41-40e74560df94','秋懷三十六首  其二八','邵雍','宋','宋诗','song-poetry','','[]','蛺蝶遶寒菊，蟋蟀鳴空階。',48,'全唐诗/poet.song.21000.json','["蛺蝶遶寒菊，蟋蟀鳴空階。", "門前有犬卧，盡日無客來。", "清波靜中流，白雲閑處堆。", "何以發天和，時飲酒一盃。"]'),
('74dd748c-73f2-4848-bb69-c50a80a91b25','秋懷三十六首  其二九','邵雍','宋','宋诗','song-poetry','','[]','紅葉戰西風，黄花笑寒日。',48,'全唐诗/poet.song.21000.json','["紅葉戰西風，黄花笑寒日。", "天道有消長，人事無固必。", "靜勝得遺味，夢去知餘失。", "利害不相沿，是非然後出。"]'),
('27322279-2833-4266-a19a-1ffc4ae4e4e5','秋懷三十六首  其三○','邵雍','宋','宋诗','song-poetry','','[]','九日登高會，尋幽講雅歡。',48,'全唐诗/poet.song.21000.json','["九日登高會，尋幽講雅歡。", "俗風追故事，天氣薦輕寒。", "白酒連醅飲，黄花带露觀。", "消沉浮世事，何足重汍瀾。"]'),
('21b76d22-9b09-4e9f-9ecb-e6fd41713448','秋懷三十六首  其三一','邵雍','宋','宋诗','song-poetry','','[]','山橫暮靄中，鳥逝孤煙外。',48,'全唐诗/poet.song.21000.json','["山橫暮靄中，鳥逝孤煙外。", "殘菊憂霜摧，幽蘭懼風敗。", "患難人不喜，富貴人所愛。", "我心曰不有，愛憎豈能賣。"]'),
('f7d5d274-8598-44b7-b2ef-62a264120cbe','秋懷三十六首  其三二','邵雍','宋','宋诗','song-poetry','','[]','水寒潭見心，木落山露骨。',48,'全唐诗/poet.song.21000.json','["水寒潭見心，木落山露骨。", "始信天無涯，萬里不隔物。", "脫衣掛扶桑，引手探月窟。", "不負仁義心，區區五十一。"]'),
('96bc1716-a1d7-4108-b667-c0ff45c3cf4a','秋懷三十六首  其三三','邵雍','宋','宋诗','song-poetry','','[]','草綠露霑衣，草衰風切肌。',48,'全唐诗/poet.song.21000.json','["草綠露霑衣，草衰風切肌。", "物情非作異，人意强生疑。", "岐動楊朱泣，絲添墨子悲。", "知之何太晚，徒自淚淋灕。"]'),
('d6c31798-e152-4f48-a8f8-ab97fd67161b','秋懷三十六首  其三四','邵雍','宋','宋诗','song-poetry','','[]','萬里晴天外，一片霜上月。',48,'全唐诗/poet.song.21000.json','["萬里晴天外，一片霜上月。", "長松挺青葱，羣卉入消歇。", "有齒日益衰，有髮日益脫。", "獲罪固已多，此公難屑屑。"]'),
('aa073272-67a7-4a1c-9c1a-d76ec6f1fac3','秋懷三十六首  其三五','邵雍','宋','宋诗','song-poetry','','[]','草枯山川貧，木落天地瘦。',48,'全唐诗/poet.song.21000.json','["草枯山川貧，木落天地瘦。", "土口風大行，雲罅日微漏。", "既往不復追，未來尚可救。", "餘事不忍言，言之必成咎。"]'),
('eaa6d4a4-4b64-49cb-a6a5-74f74aa425a1','秋懷三十六首  其三六','邵雍','宋','宋诗','song-poetry','','[]','飲酒不甚多，數盃醺心顔。',48,'全唐诗/poet.song.21000.json','["飲酒不甚多，數盃醺心顔。", "未醺不可止，既醺勸亦難。", "誰云萬物廣，豈出天地關。", "誰云萬事廣，豈出人情閒。"]'),
('166a5b70-d838-4add-a22d-cd695825f711','和陝令張師柔石柱村詩','邵雍','宋','宋诗','song-poetry','','[]','君爲陝縣令，我實康公孫。',240,'全唐诗/poet.song.21000.json','["君爲陝縣令，我實康公孫。", "始祖有遺烈，託君訪其存。", "夫君有詩來，題云石柱村。", "石柱之始立，於古無所根。", "就勒分陝銘，惟唐人之言。", "既歷年所多，首尾無完文。", "難以從考正，將焉求其源。", "我患讀書寡，知識無過人。", "經書史傳外，不能破羣昏。", "從長卿公羊，宜自陝而分。", "從君陳畢命，宜成周而云。", "二者兼取之，於義似或尊。", "分政東西郊，可以陝洛論。", "此說如近之，庶幾緩紛紜。", "甘棠之蔽芾，石柱之青新。", "當時之盛事，予不得而親。", "二南之正化，二公之清芬。", "千載之美談，予可得而聞。", "棄經而任傳，儒者固不遵。", "作詩以明之，馳此庸報君。"]'),
('7eb96902-bf13-49ba-ace7-0e5bcc603896','天津新居成謝府尹王君貺尚書','邵雍','宋','宋诗','song-poetry','','[]','嘉祐壬寅歲，新巢始孱功。',120,'全唐诗/poet.song.21000.json','["嘉祐壬寅歲，新巢始孱功。", "仍分道德里，更近帝王宮。", "檻仰端門峻，軒迎兩觀雄。", "窗虛響瀍澗，臺逈璨伊嵩。", "好景尤難得，昌辰豈易逢。", "無才濟天下，有分樂年豐。", "水竹復心裏，鸎花淵藪中。", "老萊歡不已，靖節興何窮。", "嘯傲陪真侶，經營賀府公。", "丹誠徒自寫，匪報是恩隆。"]'),
('a4ebb92a-1bfb-4ec5-b3cb-16ab26c7f4e5','新春吟','邵雍','宋','宋诗','song-poetry','','[]','多病筋骸五十二，新春猶得共銜盃。',64,'全唐诗/poet.song.21000.json','["多病筋骸五十二，新春猶得共銜盃。", "踐形有說常希孟，樂內無功可比回。", "燕去燕來徒自苦，花開花謝漫相催。", "此心不爲人休慼，二十年來已若灰。"]'),
('d7b4e9f1-b338-487f-ab74-851a947e5864','有客吟','邵雍','宋','宋诗','song-poetry','','[]','伊嵩有客欲無言，進退由來盡俟天。',64,'全唐诗/poet.song.21000.json','["伊嵩有客欲無言，進退由來盡俟天。", "好靜未能忘水石，樂閑非爲學神仙。", "休嗟紫陌難爲客，且喜清風不用錢。", "枉尺直尋何必較，此心都大不求全。"]'),
('a8c9b48c-b2cc-488a-9b3a-d83ef173b58a','小圃逢春','邵雍','宋','宋诗','song-poetry','','[]','隨分亭欄亦弄妍，不妨閑傍酒壚邊。',64,'全唐诗/poet.song.21000.json','["隨分亭欄亦弄妍，不妨閑傍酒壚邊。", "夜簷靜透花間月，晝戶晴生竹外煙。", "事到悟來全偶爾，天教閑去豈徒然。", "壺中日月長多少，爛占風光十二年。"]'),
('8371ee1f-2269-4321-bcdc-caba0c1c5a21','暮春吟','邵雍','宋','宋诗','song-poetry','','[]','春來小圃弄羣芳，誰爲貧居富貴鄉。',64,'全唐诗/poet.song.21000.json','["春來小圃弄羣芳，誰爲貧居富貴鄉。", "門外柳陰浮翠澗，階前花影溜紅光。", "梁間新燕未調舌，天末歸鴻已著行。", "自問心源無所有，答云踈懶味偏長。"]'),
('0b2e5d2e-be28-431f-9b86-f72dddb2bf57','惜芳菲','邵雍','宋','宋诗','song-poetry','','[]','細算人間千萬事，皆輸花底共開顔。',64,'全唐诗/poet.song.21000.json','["細算人間千萬事，皆輸花底共開顔。", "芳菲大率一春內，爛漫都無十日間。", "亦恐憂愁爲齟齬，更防風雨作艱難。", "莫教此後成遺恨，把火罇前尚可攀。"]'),
('ccdf5cc7-6bdf-42a0-9e01-ac2bf4920e21','答人見寄','邵雍','宋','宋诗','song-poetry','','[]','鬢毛不患漸成霜，有託琴書子一雙。',64,'全唐诗/poet.song.21000.json','["鬢毛不患漸成霜，有託琴書子一雙。", "既乏長才康盛世，無如高枕卧南窗。", "明知筋力難爲强，猶說雲山未樹降。", "多謝故人相愛甚，轍魚幸免困西江。"]'),
('db8f2568-0592-4d5c-8d70-79d3ea4a8898','弄筆','邵雍','宋','宋诗','song-poetry','','[]','行年五十二，老去復何憂。',48,'全唐诗/poet.song.21000.json','["行年五十二，老去復何憂。", "事貴照至底，話難言到頭。", "上有明天子，下有賢諸侯。", "飽食高眠外，自餘無所求。"]'),
('44afca22-c2be-4254-a4b0-7468e08caff4','問人丐酒','邵雍','宋','宋诗','song-poetry','','[]','百病筋骸一老身，白頭今日愧因循。',64,'全唐诗/poet.song.21000.json','["百病筋骸一老身，白頭今日愧因循。", "雖無紫詔還朝速，却有青山入夢頻。", "風月滿天誰是主，林泉遍地豈無人。", "市沽酒味難醇美，長負襟懷一片春。"]'),
('987a6ce4-0b67-48e2-af54-86abebd907cb','答客','邵雍','宋','宋诗','song-poetry','','[]','人間相識幾無數，相識雖多未必知。',64,'全唐诗/poet.song.21000.json','["人間相識幾無數，相識雖多未必知。", "望我實多全爲道，知予淺處却因詩。", "升沉休問百年事，今古都歸一局棋。", "乘馬須求似騏驥，柰何騏驥未來時。"]'),
('3ee190eb-f978-4e3e-aa54-972d59b169ac','悟人一言','邵雍','宋','宋诗','song-poetry','','[]','百慮謀猶拙，一言迷自開。',48,'全唐诗/poet.song.21000.json','["百慮謀猶拙，一言迷自開。", "世間無大事，天下有雄才。", "唯恐人難和，寧憂道未恢。", "忌心都去盡，何復病塵埃。"]'),
('670e5ac3-d4a6-412a-ad0f-eb4bd7651f1f','謝人惠筆','邵雍','宋','宋诗','song-poetry','','[]','愛重寄文房，慇懃謝遠將。',48,'全唐诗/poet.song.21000.json','["愛重寄文房，慇懃謝遠將。", "兔毫剛且健，筠管直而長。", "靜錄新詩藁，閑抄舊藥方。", "自餘無所用，足以養鋒鋩。"]'),
('022518e2-031c-4581-b0e6-bd3c34390108','書事吟','邵雍','宋','宋诗','song-poetry','','[]','天地有常理，日月無循行。',48,'全唐诗/poet.song.21000.json','["天地有常理，日月無循行。", "飽食高眠外，率是皆虛名。", "雖乏伊呂才，不失堯舜氓。", "何須身作相，然後爲太平。"]'),
('a11017d6-99f5-4f64-aeb7-3ee89ac88b8b','雙頭蓮','邵雍','宋','宋诗','song-poetry','','[]','漢室嬋娟雙姊妹，天台縹緲兩神仙。',32,'全唐诗/poet.song.21000.json','["漢室嬋娟雙姊妹，天台縹緲兩神仙。", "當時盡有風流過，謫向人間作瑞蓮。"]'),
('9e1566a8-8e42-42c1-942e-f24919699d9e','答人書意','邵雍','宋','宋诗','song-poetry','','[]','仲尼言正性，子輿言踐形。',48,'全唐诗/poet.song.21000.json','["仲尼言正性，子輿言踐形。", "二者能自得，殆不爲虛生。", "所交若以道，所感若以誠。", "雖三軍在前，而莫得之凌。"]'),
('106ac505-6ef4-4c6f-8ee9-91fbc6162ec4','答人書言','邵雍','宋','宋诗','song-poetry','','[]','無位立事難，逢時建功易。',48,'全唐诗/poet.song.21000.json','["無位立事難，逢時建功易。", "求全自有毀，舉大須略細。", "去惡慮傷恩，存惡憂害義。", "徒有仁者心，殊無仁者意。"]'),
('28bd214a-ca07-4b68-8451-4c08c19d1f82','答人書','邵雍','宋','宋诗','song-poetry','','[]','卿相一歲俸，寒儒一生費。',48,'全唐诗/poet.song.21000.json','["卿相一歲俸，寒儒一生費。", "人爵固不同，天爵何嘗匱。", "不有霜與雪，安知松與桂。", "雖無官自高，豈無道自貴。"]'),
('cc484366-d2a4-4cf8-9d08-c27a083ae70d','與人話舊','邵雍','宋','宋诗','song-poetry','','[]','耳目所聞見，且言三十春。',48,'全唐诗/poet.song.21000.json','["耳目所聞見，且言三十春。", "纔更十次閏，已換一番人。", "圮族綺紈故，朱門車馬新。", "從來皆偶爾，何者謂功勳。"]'),
('a3df4f81-acb4-4438-924d-4ad4aabf2d0e','閑吟','邵雍','宋','宋诗','song-poetry','','[]','忽忽閑拈筆，時時樂性靈。',48,'全唐诗/poet.song.21000.json','["忽忽閑拈筆，時時樂性靈。", "何嘗無對景，未始便忘情。", "句會飄然得，詩因偶爾成。", "天機難狀處，一點自分明。"]'),
('b0cfffae-3392-44a9-97c5-8120bff35421','閑坐吟','邵雍','宋','宋诗','song-poetry','','[]','當年計過之，今日事難隨。',48,'全唐诗/poet.song.21000.json','["當年計過之，今日事難隨。", "天命不我祐，雲山聊自怡。", "無何緣淡薄，遂得造希夷。", "却欲嗤真宰，勞勞應不知。"]'),
('97e1b2b0-9bb0-4cc1-8c35-6051ef5f8db7','天津閑步','邵雍','宋','宋诗','song-poetry','','[]','天子舊神州，葱葱氣象浮。',48,'全唐诗/poet.song.21000.json','["天子舊神州，葱葱氣象浮。", "園林閑近水，殿閣遠橫秋。", "浪雪暑猶在，橋虹晴不收。", "人間無事日，此地好淹留。"]'),
('4b04b8cc-8354-4e33-946b-0ea8b5e668d1','天津幽居','邵雍','宋','宋诗','song-poetry','','[]','予家洛城裏，況復在天津。',48,'全唐诗/poet.song.21000.json','["予家洛城裏，況復在天津。", "日近先知曉，天低易得春。", "時光優化國，景物厚幽人。", "自可辭軒冕，閑中老此身。"]'),
('0a32eca3-99e2-4a1c-974f-e0dcb378010e','天津水聲','邵雍','宋','宋诗','song-poetry','','[]','洛水近吾廬，潺湲到枕虛。',48,'全唐诗/poet.song.21000.json','["洛水近吾廬，潺湲到枕虛。", "湍驚九秋後，波急五更初。", "細爲輕風背，豪因驟雨餘。", "幽人有茲樂，何必待笙竽。"]'),
('0f2117b0-163f-4f35-a29d-bc453697bc88','不寢','邵雍','宋','宋诗','song-poetry','','[]','閑坐更已深，就寢夜尚永。',48,'全唐诗/poet.song.21000.json','["閑坐更已深，就寢夜尚永。", "展轉不成寐，却把前事省。", "奠枕時昏昏，擁衾還耿耿。", "西窗明月中，數葉芭蕉影。"]'),
('46138af6-e059-401a-9a04-d7beaf8a4970','天宮小閣','邵雍','宋','宋诗','song-poetry','','[]','夏日到天宮，凭欄望莫窮。',48,'全唐诗/poet.song.21000.json','["夏日到天宮，凭欄望莫窮。", "古人用心遠，天子建都雄。", "樓觀深雲裏，山川暮靄中。", "行人漫來往，此意有誰同。"]'),
('70d1c19e-f2ce-4842-92a3-6fe097a7631a','聽琴','邵雍','宋','宋诗','song-poetry','','[]','琴宜入夜聽，別起一般清。',48,'全唐诗/poet.song.21000.json','["琴宜入夜聽，別起一般清。", "纔覺哀猿絕，還聞離鳳鳴。", "青山無限好，白髮不須驚。", "會取坐忘意，方知太古情。"]'),
('e31a6f3e-6c72-446b-aec4-5c25b7d018d6','天津感事二十六首  其一','邵雍','宋','宋诗','song-poetry','','[]','雲輕日淡天津暮，風急林踈洛水秋。',32,'全唐诗/poet.song.21000.json','["雲輕日淡天津暮，風急林踈洛水秋。", "獨步獨吟人莫會，時時鷗鷺下汀洲。"]'),
('aaecd26f-08be-4d1d-971c-f64b2210667b','天津感事二十六首  其二','邵雍','宋','宋诗','song-poetry','','[]','寵辱事多今不見，興亡時去止堪哀。',32,'全唐诗/poet.song.21000.json','["寵辱事多今不見，興亡時去止堪哀。", "諸觀今日長安道，抵暮行人猶往來。"]'),
('b42e628d-9d05-4834-a229-20f5b9a8d73a','天津感事二十六首  其三','邵雍','宋','宋诗','song-poetry','','[]','鳳樓深處鏁雲煙，一鏁雲煙又百年。',32,'全唐诗/poet.song.21000.json','["鳳樓深處鏁雲煙，一鏁雲煙又百年。", "痛惜汾陰西祀後，翠華辜負上陽天。"]'),
('6cb9c5cc-0072-4c92-849c-8a063edf3557','天津感事二十六首  其四','邵雍','宋','宋诗','song-poetry','','[]','誰引長河貫洛城，鑾輿東去此爲輕。',32,'全唐诗/poet.song.21000.json','["誰引長河貫洛城，鑾輿東去此爲輕。", "洪濤不服天津束，日夜奔騰作怒聲。"]'),
('ff68ffab-70bd-4959-b165-d95ff3be78b3','天津感事二十六首  其五','邵雍','宋','宋诗','song-poetry','','[]','陽烏西去水東流，今古推移幾度秋。',32,'全唐诗/poet.song.21000.json','["陽烏西去水東流，今古推移幾度秋。", "四面遠山長斂黛，不知終日爲誰愁。"]'),
('de2e4b97-db10-4844-bbcb-02da1ac81d3e','天津感事二十六首  其六','邵雍','宋','宋诗','song-poetry','','[]','忙忙負乘兩何殊，往復由來出此途。',32,'全唐诗/poet.song.21000.json','["忙忙負乘兩何殊，往復由來出此途。", "爭似不才閑處坐，平時雲水遶衣裾。"]'),
('9f5c4d75-ea8b-40e0-9a77-cc659af6c2e7','天津感事二十六首  其七','邵雍','宋','宋诗','song-poetry','','[]','人言垂釣辨浮沉，辨著浮沉用意深。',32,'全唐诗/poet.song.21000.json','["人言垂釣辨浮沉，辨著浮沉用意深。", "吾耻不爲知害性，等閑輕動望魚心。"]'),
('785362c6-1676-4e59-b1d7-01c9c73dd56e','天津感事二十六首  其八','邵雍','宋','宋诗','song-poetry','','[]','自古別都多隙地，參天喬木亂昏鴉。',32,'全唐诗/poet.song.21000.json','["自古別都多隙地，參天喬木亂昏鴉。", "荒垣壞堵人耕處，半是前朝卿相家。"]'),
('7b73fa08-7095-4404-abb0-256c12a0cb1f','天津感事二十六首  其九','邵雍','宋','宋诗','song-poetry','','[]','鳳凰樓觀冷橫秋，橋下長波入海流。',32,'全唐诗/poet.song.21000.json','["鳳凰樓觀冷橫秋，橋下長波入海流。", "千百年來舊朝市，幾番人向此經由。"]'),
('4f682765-df2f-4e81-acf2-fd0f0f3bb70f','天津感事二十六首  其一○','邵雍','宋','宋诗','song-poetry','','[]','輪蹄交錯未嘗停，去若相追來若爭。',32,'全唐诗/poet.song.21000.json','["輪蹄交錯未嘗停，去若相追來若爭。", "料得中心無別事，苟非干利即干名。"]'),
('08fe3e0e-452f-4534-aa39-f153f223ca04','天津感事二十六首  其一一','邵雍','宋','宋诗','song-poetry','','[]','煙樹盡歸秋色裏，人家常在水聲中。',32,'全唐诗/poet.song.21000.json','["煙樹盡歸秋色裏，人家常在水聲中。", "數行旅鴈斜飛去，一簇樓臺峭倚空。"]'),
('d739f357-97a0-44c4-8076-89d29c8a3efe','天津感事二十六首  其一二','邵雍','宋','宋诗','song-poetry','','[]','淥水悠悠際碧天，平蕪更與遠山連。',32,'全唐诗/poet.song.21000.json','["淥水悠悠際碧天，平蕪更與遠山連。", "白頭老叟心無事，閑凭欄干看洛川。"]'),
('58e217cb-0f00-4c2e-86c1-e11c225f4322','天津感事二十六首  其一三','邵雍','宋','宋诗','song-poetry','','[]','去年橋上凭欄人，今歲橋邊騎馬身。',32,'全唐诗/poet.song.21000.json','["去年橋上凭欄人，今歲橋邊騎馬身。", "橋上橋邊不知數，於今但記十三春。"]'),
('c152518c-d211-484f-9e2d-0f152fa07ddc','天津感事二十六首  其一四','邵雍','宋','宋诗','song-poetry','','[]','堤邊草色長芊芊，陌上行人自往還。',32,'全唐诗/poet.song.21000.json','["堤邊草色長芊芊，陌上行人自往還。", "淥水欲凈不得凈，春風未放柳條閑。"]'),
('d772da0c-6430-47ae-9232-2caac673e840','天津感事二十六首  其一五','邵雍','宋','宋诗','song-poetry','','[]','水流任急境常靜，花落雖頻意自閑。',32,'全唐诗/poet.song.21000.json','["水流任急境常靜，花落雖頻意自閑。", "不似世人忙裏老，生平未始得開顔。"]'),
('d55f97c0-5797-483e-9276-e0f810db4fe5','天津感事二十六首  其一六','邵雍','宋','宋诗','song-poetry','','[]','溪邊閑坐眼慵開，波射長堤勢欲摧。',32,'全唐诗/poet.song.21000.json','["溪邊閑坐眼慵開，波射長堤勢欲摧。", "多少水禽文彩好，幾番飛去又飛來。"]'),
('0e43ceb2-d142-455a-8ee9-2723e6a2cfb0','天津感事二十六首  其一七','邵雍','宋','宋诗','song-poetry','','[]','名利從來本任才，行人不用苦相猜。',32,'全唐诗/poet.song.21000.json','["名利從來本任才，行人不用苦相猜。", "壺中日月長多少，閑步天津看往來。"]'),
('14c9e39f-1b68-470f-9517-c558d1fc2255','天津感事二十六首  其一八','邵雍','宋','宋诗','song-poetry','','[]','地勢東南一槩傾，水流何日得安平。',32,'全唐诗/poet.song.21000.json','["地勢東南一槩傾，水流何日得安平。", "天津更在急流處，無限高深併此聲。"]'),
('09fae983-42ea-4762-b100-d97e3838c558','天津感事二十六首  其一九','邵雍','宋','宋诗','song-poetry','','[]','三千里外名荒服，一百年來號太平。',32,'全唐诗/poet.song.21000.json','["三千里外名荒服，一百年來號太平。", "爭似洛川無事客，何須列土始爲榮。"]'),
('2f58baf0-b7c4-4b3a-98fa-276c650e4805','天津感事二十六首  其二○','邵雍','宋','宋诗','song-poetry','','[]','遶堤楊柳輕風裏，隔水樓臺細雨中。',32,'全唐诗/poet.song.21000.json','["遶堤楊柳輕風裏，隔水樓臺細雨中。", "酒放半醺重九後，此時情味更無窮。"]'),
('48bf50c2-6e14-4aa2-acf0-2d5b0ad0209d','天津感事二十六首  其二一','邵雍','宋','宋诗','song-poetry','','[]','著身靜處觀人事，放意閑中鍊物情。',32,'全唐诗/poet.song.21000.json','["著身靜處觀人事，放意閑中鍊物情。", "去盡風波存止水，世間何事不能平。"]'),
('af86e5fb-9afa-4e0a-aa0e-2b746b49e2d5','天津感事二十六首  其二二','邵雍','宋','宋诗','song-poetry','','[]','隨唐而下貴公卿，近世風波走利名。',32,'全唐诗/poet.song.21000.json','["隨唐而下貴公卿，近世風波走利名。", "借問天津橋下水，當時湍急作何聲。"]'),
('f9a6279d-4ed2-4fbd-88f9-d84b1f6c144b','天津感事二十六首  其二三','邵雍','宋','宋诗','song-poetry','','[]','前朝無限貴公卿，後世徒能記姓名。',32,'全唐诗/poet.song.21000.json','["前朝無限貴公卿，後世徒能記姓名。", "唯此天津橋下水，古今都作一般聲。"]'),
('64be2d24-42ab-4abb-b334-6ecaa7e31990','天津感事二十六首  其二四','邵雍','宋','宋诗','song-poetry','','[]','雲無一縷干明月，橋有千尋卧淥波。',32,'全唐诗/poet.song.21000.json','["雲無一縷干明月，橋有千尋卧淥波。", "料得人間無此景，中秋對月興如何。"]'),
('edb7fa22-9a5c-4666-b55b-d4a99c9a11a7','天津感事二十六首  其二五','邵雍','宋','宋诗','song-poetry','','[]','郟鄏城中同德友，鳳凰樓下會中秋。',32,'全唐诗/poet.song.21000.json','["郟鄏城中同德友，鳳凰樓下會中秋。", "芳罇倒盡人歸去，月色波光戰未休。"]'),
('d3e6f42d-c282-4189-b59e-fda3ecd82893','天津感事二十六首  其二六','邵雍','宋','宋诗','song-poetry','','[]','了生始可言常事，知性方能議大猷。',32,'全唐诗/poet.song.21000.json','["了生始可言常事，知性方能議大猷。", "只此長川無晝夜，爲誰驅逼向東流。"]'),
('63cb31ae-adfb-4ff6-9d37-180384940e31','誠明吟','邵雍','宋','宋诗','song-poetry','','[]','孔子生知非假習，孟軻先覺亦須脩。',32,'全唐诗/poet.song.21000.json','["孔子生知非假習，孟軻先覺亦須脩。", "誠明本屬吾家事，自是今人好外求。"]'),
('e8db874f-85be-4125-a091-64d96b144799','繩水吟','邵雍','宋','宋诗','song-poetry','','[]','有水善平難善直，唯繩能直不能平。',32,'全唐诗/poet.song.21000.json','["有水善平難善直，唯繩能直不能平。", "如將繩水合爲一，世上何憂事不明。"]'),
('6270e3a8-5da9-4b52-8ded-cb21360c470c','辛酸吟','邵雍','宋','宋诗','song-poetry','','[]','辛酸既不爲中味，商徵如何是正音。',32,'全唐诗/poet.song.21000.json','["辛酸既不爲中味，商徵如何是正音。", "舉世未能分曲直，使誰爲主主心平。"]'),
('0deedb72-c8aa-48ad-8087-77fe0d597f16','言默吟','邵雍','宋','宋诗','song-poetry','','[]','當默用言言是垢，當言任默默爲塵。',32,'全唐诗/poet.song.21000.json','["當默用言言是垢，當言任默默爲塵。", "當言當默都無任，塵垢何由得到身。"]'),
('eb086006-9a89-496c-9936-cc0e2b06f879','閑居述事  其一','邵雍','宋','宋诗','song-poetry','','[]','一點天真都不耗，千鐘人祿是難來。',32,'全唐诗/poet.song.21000.json','["一點天真都不耗，千鐘人祿是難來。", "太平自慶無他事，有酒時時三五盃。"]'),
('690008b9-d371-42a1-9856-cc33ce3af3d9','閑居述事  其二','邵雍','宋','宋诗','song-poetry','','[]','竹雨侵人氣自涼，南窗睡起望瀟湘。',32,'全唐诗/poet.song.21000.json','["竹雨侵人氣自涼，南窗睡起望瀟湘。", "茅簷滴瀝無休歇，却憶當初宿夜航。"]'),
('94f422b1-340d-4275-92e7-09f6c6893c30','閑居述事  其三','邵雍','宋','宋诗','song-poetry','','[]','初晴月向松間出，盛暑風從水面來。',32,'全唐诗/poet.song.21000.json','["初晴月向松間出，盛暑風從水面來。", "已比他人多數倍，況能時復舉樽罍。"]'),
('1612aa79-acc0-44f1-9284-6e8dd2f7f70d','閑居述事  其四','邵雍','宋','宋诗','song-poetry','','[]','堂上慈親八十餘，階前兒女戲相呼。',32,'全唐诗/poet.song.21000.json','["堂上慈親八十餘，階前兒女戲相呼。", "旨甘取足隨豐儉，此樂人間更有無。"]'),
('e9baab8b-2c7f-4687-9a79-04e5319e6f14','閑居述事  其五','邵雍','宋','宋诗','song-poetry','','[]','清歡少有虛三日，劇飲未嘗過五分。',32,'全唐诗/poet.song.21000.json','["清歡少有虛三日，劇飲未嘗過五分。", "相見心中無別事，不評興廢即論文。"]'),
('98c57399-11c4-4b29-98a8-7e1557e2b11f','閑居述事  其六','邵雍','宋','宋诗','song-poetry','','[]','花木四時分景致，經書千卷好生涯。',32,'全唐诗/poet.song.21000.json','["花木四時分景致，經書千卷好生涯。", "有人若問閑居處，道德坊中第一家。"]'),
('bdbee5f7-7aca-4b22-9701-b221f4bc93ea','天宮小閣納凉  其一','邵雍','宋','宋诗','song-poetry','','[]','小閣凭虛看洛城，滿川雲物拱神京。',32,'全唐诗/poet.song.21000.json','["小閣凭虛看洛城，滿川雲物拱神京。", "風從萬歲山頭至，多少煙嵐併此清。"]'),
('6a74dfea-d4f5-4704-a9b2-7b0563d4936f','天宮小閣納凉  其二','邵雍','宋','宋诗','song-poetry','','[]','小閣於吾有大功，清凉冠絕洛城中。',32,'全唐诗/poet.song.21000.json','["小閣於吾有大功，清凉冠絕洛城中。", "自慙虛薄誠多幸，襟袖長涵萬里風。"]'),
('1f94fbba-6fb5-4697-880a-1c21b5c37ae3','天宮小閣納凉  其三','邵雍','宋','宋诗','song-poetry','','[]','小閣清風豈易當，一般情味若羲皇。',32,'全唐诗/poet.song.21000.json','["小閣清風豈易當，一般情味若羲皇。", "洛陽有客不知姓，二十年來享此凉。"]'),
('f2052f3a-8425-4268-972a-4cfbd407d781','天宮幽居即事','邵雍','宋','宋诗','song-poetry','','[]','人苦天津遠，來須特特來。',48,'全唐诗/poet.song.21000.json','["人苦天津遠，來須特特來。", "閑餘知道泰，靜久覺神開。", "悟易觀棊局，談詩捻酒盃。", "世情千萬狀，都不與裝懷。"]'),
('26452a1b-2db4-4d59-946c-a54c30af5eaa','遊龍門','邵雍','宋','宋诗','song-poetry','','[]','江天無少異，幽鳥下晴沙。',48,'全唐诗/poet.song.21000.json','["江天無少異，幽鳥下晴沙。", "路去山形斷，川迴渡口斜。", "龕巖千萬穴，店舍兩三家。", "清景四時好，都城況不賒。"]'),
('653de179-93e7-43b6-bca3-06b53bed7a60','重遊洛川','邵雍','宋','宋诗','song-poetry','','[]','買石尚饒雲，買山當從水。',48,'全唐诗/poet.song.21000.json','["買石尚饒雲，買山當從水。", "雲可致無心，水能爲鑑止。", "性以無心明，情由鑑止已。", "二者不可失，出彼而入此。"]'),
('019042ca-f570-44eb-92be-76ff1c524752','川上觀魚','邵雍','宋','宋诗','song-poetry','','[]','天氣冷涵秋，川長魚正遊。',48,'全唐诗/poet.song.21000.json','["天氣冷涵秋，川長魚正遊。", "雖知能避網，猶恐誤吞鈎。", "已絕登門望，曾無點額憂。", "因思濠上樂，曠達是莊周。"]'),
('3bc810e5-60e5-441e-a918-76b470e91448','後園即事三首  其一','邵雍','宋','宋诗','song-poetry','','[]','太平身老復何憂，景愛家園自在遊。',64,'全唐诗/poet.song.21000.json','["太平身老復何憂，景愛家園自在遊。", "幾樹綠楊陰乍合，數聲幽鳥語方休。", "竹侵舊徑高低迸，水滿春渠左右流。", "借問主人何似樂，答云殊不異封侯。"]'),
('b6f38ab5-b452-4162-abef-de91718369da','後園即事三首  其二','邵雍','宋','宋诗','song-poetry','','[]','天養踈慵自有方，洛城分得水雲鄉。',64,'全唐诗/poet.song.21000.json','["天養踈慵自有方，洛城分得水雲鄉。", "不聞世上風波險，但見壺中日月長。", "一局閑棊留野客，數盃醇酒面脩篁。", "物情悟了都無事，未學顔淵已坐忘。"]'),
('ca76fdb7-3fac-410c-9e8c-cc47af016058','後園即事三首  其三','邵雍','宋','宋诗','song-poetry','','[]','年來得疾號詩狂，每度詩狂必命觴。',64,'全唐诗/poet.song.21000.json','["年來得疾號詩狂，每度詩狂必命觴。", "樂道襟懷忘檢束，任真言語省思量。", "賓朋欵密過從久，雲水優閑興味長。", "始信淵明深意在，北窗當日比羲皇。"]'),
('b2375e32-c636-44d8-bb19-1a54b3dbbe6d','觀棋長吟','邵雍','宋','宋诗','song-poetry','','[]','院靜春深晝掩扉，竹間閑看客爭棋。',160,'全唐诗/poet.song.21000.json','["院靜春深晝掩扉，竹間閑看客爭棋。", "搜羅神鬼聚胸臆，措致山河入範圍。", "局合龍蛇成陣闘，刧殘鴻鴈破行飛。", "殺多項羽坑秦卒，敗劇苻堅畏晉師。", "座上戈鋋嘗擊搏，面前冰炭旋更移。", "死生共抵兩家事，勝負都由一著時。", "當路斷無相假借，對人須且强推辭。", "腹心受害誠堪懼，唇齒生憂尚可醫。", "善用中傷爲得策，陰行狡獪謂知機。", "請觀今日長安道，易地何嘗不有之。"]'),
('9416b90e-41ec-4407-899c-8cc9256a7331','秋日登崇德閣二首  其一','邵雍','宋','宋诗','song-poetry','','[]','無限高賢抑壯圖，登臨不用起長吁。',64,'全唐诗/poet.song.21000.json','["無限高賢抑壯圖，登臨不用起長吁。", "山川千古戰爭後，冠劒百年零落餘。", "浪把功名爲己任，那知富貴豈人謨。", "丹青曲盡世間妙，寫得凭欄意思無。"]'),
('5cece881-4c05-434c-ae4f-197940f41081','秋日登崇德閣二首  其二','邵雍','宋','宋诗','song-poetry','','[]','一百年來號太平，當初仍患不丁寧。',64,'全唐诗/poet.song.21000.json','["一百年來號太平，當初仍患不丁寧。", "京都尚有漢唐氣，宮闕猶虛霸王形。", "煙外亂峰纔隠約，霜餘紅樹半凋零。", "樽中有酒難成醉，旋被西風吹又醒。"]'),
('c9527384-c757-4652-9850-8cb37fe8d51b','秋日飲後晚歸','邵雍','宋','宋诗','song-poetry','','[]','水竹園林秋更好，忍把芳樽容易倒。',64,'全唐诗/poet.song.21000.json','["水竹園林秋更好，忍把芳樽容易倒。", "重陽已過菊方開，情多不學年光老。", "陰雲不動楊柳低，風遞輕寒生暮草。", "無涯逸興不可收，馬蹄慢踏天街道。"]'),
('236518ed-eab3-403c-a418-cb70b324263c','寄陝守祖擇之舍人','邵雍','宋','宋诗','song-poetry','','[]','記得相逢否，當時在海東。',48,'全唐诗/poet.song.21000.json','["記得相逢否，當時在海東。", "別離千里外，倏忽十年中。", "跡異名尤異，心同齒更同。", "終期再清會，文酒樂無窮。"]'),
('0fc1b4fa-8c23-45d7-a5b0-2b6a401be117','哭張元伯職方','邵雍','宋','宋诗','song-poetry','','[]','近年老輩頻凋落，使我中心又惻然。',64,'全唐诗/poet.song.21000.json','["近年老輩頻凋落，使我中心又惻然。", "洛社掛冠高卧者，唯君清澈如神仙。", "昔日與君論少長，今日與君爭後先。", "把酒酹君君必知，爲君洒淚西風前。"]'),
('61330f4a-36b2-446f-baa8-c7dcc5393f89','哭張師柔長官','邵雍','宋','宋诗','song-poetry','','[]','生平志在立功名，誰謂才難與命爭。',64,'全唐诗/poet.song.21000.json','["生平志在立功名，誰謂才難與命爭。", "絕筆有詩形雅意，蓋棺無地盡交情。", "胸中時事何由展，天下人才不復評。", "魂若有知宜自慰，子孫大可振家聲。"]'),
('e3fa2185-5588-433a-8ed9-c1a4867b3b8e','和登封裴寺丞翰見寄','邵雍','宋','宋诗','song-poetry','','[]','陋巷簞飄世所傳，予何人則恥蕭然。',64,'全唐诗/poet.song.21000.json','["陋巷簞飄世所傳，予何人則恥蕭然。", "既知富貴須由命，難把升沉更問天。", "靜默有功成野性，騫驤無路學時賢。", "紛華出入金門者，應笑溪翁治石田。"]'),
('82606b87-50e5-4530-bcca-1e0b91d5a72d','代書寄友人','邵雍','宋','宋诗','song-poetry','','[]','當年有志高天下，嘗讀前書笑謝安。',64,'全唐诗/poet.song.21000.json','["當年有志高天下，嘗讀前書笑謝安。", "豈謂此身甘老朽，尚無閑地可盤桓。", "棋逢敵手纔堪著，琴少知音不願彈。", "非止不才能退默，古賢長恨得時難。"]'),
('83f95d4e-9b1e-471c-80ab-572420ea8381','訪姚輔周郎中月陂西園','邵雍','宋','宋诗','song-poetry','','[]','相憶不可遏，西街來訪時。',48,'全唐诗/poet.song.21000.json','["相憶不可遏，西街來訪時。", "交橫過溝水，隙曲遶蔬畦。", "樹偃低頭避，筇高換手持。", "朋遊相得甚，何樂更如之。"]'),
('604fc523-986a-49ea-aafd-92de8b379106','依韻謝登封劉李裴三君見約遊山','邵雍','宋','宋诗','song-poetry','','[]','諸公見約往嵩前，重走新詩各一篇。',64,'全唐诗/poet.song.21000.json','["諸公見約往嵩前，重走新詩各一篇。", "擺落塵埃非敢後，訪尋雲水柰輸先。", "三陽宮近叢幽石，萬歲峯高羃紫煙。", "多少勝遊俱未到，願陪仙躅共攀緣。"]'),
('f4bb2667-4480-4550-8901-4d0938bc944d','登嵩頂','邵雍','宋','宋诗','song-poetry','','[]','九州環遶持棋枰，萬歲嵩高看太平。',64,'全唐诗/poet.song.21000.json','["九州環遶持棋枰，萬歲嵩高看太平。", "四海有人能統御，中原何復有交爭。", "長憂眼見姦雄輩，且願身爲堯舜氓。", "五十三年蕪沒事，如今方喜看春耕。"]'),
('a4850dd3-3118-42f7-87f4-b3b1529f0079','登封縣宇觀少室','邵雍','宋','宋诗','song-poetry','','[]','天地始融結，此山已高極。',48,'全唐诗/poet.song.21000.json','["天地始融結，此山已高極。", "羣峯擁旌幢，巨石羅劒戟。", "日出崖先紅，雨餘嵐更碧。", "安知無神仙，其間久遁迹。"]'),
('a8b3d1c6-613e-4768-a683-ebe2c53036e8','山中寄登封令','邵雍','宋','宋诗','song-poetry','','[]','初離縣日謀經宿，既到山中未忍迴。',32,'全唐诗/poet.song.21000.json','["初離縣日謀經宿，既到山中未忍迴。", "公宇若無民事决，願携茶器上山來。"]'),
('c40567d8-30a1-47b6-b59a-4bd89b0b4df1','歸洛寄鄭州祖擇之龍圖','邵雍','宋','宋诗','song-poetry','','[]','恩深骨髓謂慈親，義重丘山是故人。',32,'全唐诗/poet.song.21000.json','["恩深骨髓謂慈親，義重丘山是故人。", "歸過嵩陽舊遊地，白雲收得薜蘿身。"]'),
('decf07b1-97be-40a3-97e1-29880f88a836','和祖龍圖見寄','邵雍','宋','宋诗','song-poetry','','[]','吾家職分是雲山，不見雲山不解顔。',64,'全唐诗/poet.song.21000.json','["吾家職分是雲山，不見雲山不解顔。", "遊興亦難拘日阻，夢魂都不到人間。", "煙嵐欲極無涯樂，軒冕何嘗有暫閑。", "洛社交朋屢相約，幾時曾得略躋攀。"]'),
('10439a9a-4153-4ada-8559-e3ca12eeb166','緣飾吟','邵雍','宋','宋诗','song-poetry','','[]','緣飾了時稱好手，作爲成處是真家。',32,'全唐诗/poet.song.21000.json','["緣飾了時稱好手，作爲成處是真家。", "須防冷眼人觀覷，傀儡都無帳幕遮。"]'),
('26912167-dd3b-4fad-965d-0600777ec934','自況三首  其一','邵雍','宋','宋诗','song-poetry','','[]','名利場中難著脚，林泉路上早迴頭。',32,'全唐诗/poet.song.21000.json','["名利場中難著脚，林泉路上早迴頭。", "不然半百殘軀體，正被風波汩未休。"]'),
('892f7d98-bd96-4413-8324-d5f832dd0eee','自況三首  其二','邵雍','宋','宋诗','song-poetry','','[]','滿天風月爲官守，遍地雲山是事權。',32,'全唐诗/poet.song.21000.json','["滿天風月爲官守，遍地雲山是事權。", "唯我敢開無意口，對人高道不妨言。"]'),
('c57431a5-9e9e-468d-b311-281e40784059','自況三首  其三','邵雍','宋','宋诗','song-poetry','','[]','每恨性昏聞道晚，長慙智短適時難。',32,'全唐诗/poet.song.21000.json','["每恨性昏聞道晚，長慙智短適時難。", "人生三萬六千日，二萬日來身却閑。"]'),
('80750d6d-4389-42e9-ae31-ed0ac2af049b','偶書','邵雍','宋','宋诗','song-poetry','','[]','紛紛議論出多門，安得真儒號縉紳。',64,'全唐诗/poet.song.21000.json','["紛紛議論出多門，安得真儒號縉紳。", "名教一宗長有主，中原萬里豈無人。", "皇王帝伯時雖異，禮樂詩書道自新。", "觀古事多今可見，不知何者謂經綸。"]'),
('1ec536da-b6b3-4187-afda-90d7b1341732','代書寄商洛令陳成伯','邵雍','宋','宋诗','song-poetry','','[]','此去替期猶半歲，商山窮僻少醫名。',64,'全唐诗/poet.song.21000.json','["此去替期猶半歲，商山窮僻少醫名。", "感傷多後風防滯，暑濕偏時疾易生。", "聖智不能無蹇剝，賢才方善處哀榮。", "斯言至淺理非淺，少補英豪一二明。"]'),
('da4a8626-41c4-4fcf-a411-8b5100e6759f','治平丁未仲秋遊伊洛二川六日晚出洛城西門宿奉親僧舍聽張道人彈琴','邵雍','宋','宋诗','song-poetry','','[]','向晚驅車出上陽，初程便宿水雲鄉。',32,'全唐诗/poet.song.21000.json','["向晚驅車出上陽，初程便宿水雲鄉。", "更聞數弄神仙曲，始信壺中日月長。"]'),
('96c99e86-fde5-4a7b-9bbb-9e8ed2ba1172','七日遡洛夜宿延秋莊上','邵雍','宋','宋诗','song-poetry','','[]','八月延秋禾熟天，農家富貴在豐年。',32,'全唐诗/poet.song.21000.json','["八月延秋禾熟天，農家富貴在豐年。", "一簞雞黍一瓢酒，誰羨王公食萬錢。"]'),
('e95aace5-a1ba-46e2-bb1e-134e5991372c','八日渡洛登南山觀噴玉泉會壽安縣張趙尹三君同遊','邵雍','宋','宋诗','song-poetry','','[]','渡洛南觀噴玉泉，千峯萬峰遥相連。',32,'全唐诗/poet.song.21000.json','["渡洛南觀噴玉泉，千峯萬峰遥相連。", "中間一道長如雪，飛入寒潭不記年。"]'),
('9e347ebf-f9e2-46be-abbe-9fe5c8078a0e','九日登壽安縣錦幈山下宿邑中  其一','邵雍','宋','宋诗','song-poetry','','[]','煙嵐一簇特崔嵬，到此令人心自灰。',32,'全唐诗/poet.song.21000.json','["煙嵐一簇特崔嵬，到此令人心自灰。", "上有神仙不知姓，洞門閑倚白雲開。"]'),
('c943ffd0-4a81-4baa-95ee-e03858a9eaae','九日登壽安縣錦幈山下宿邑中  其二','邵雍','宋','宋诗','song-poetry','','[]','並轡西遊疊石溪，斷崖環合與雲齊。',32,'全唐诗/poet.song.21000.json','["並轡西遊疊石溪，斷崖環合與雲齊。", "飛泉亦有留人意，肯負他年尚此樓。"]'),
('1e692eed-99d0-4ff9-8230-1b7f127de332','十日西過永濟橋','邵雍','宋','宋诗','song-poetry','','[]','十日西行過永濟，時時細雨濕衫衣。',32,'全唐诗/poet.song.21000.json','["十日西行過永濟，時時細雨濕衫衣。", "多情會得山神意，猶恐行人欠翠微。"]'),
('8ff6db50-4f83-492a-bd70-bfb2c1b5d8e3','過宜陽城二首  其一','邵雍','宋','宋诗','song-poetry','','[]','六國區區共事秦，疲於奔命尚難親。',32,'全唐诗/poet.song.21000.json','["六國區區共事秦，疲於奔命尚難親。", "如何殺盡半天下，豈是關東沒一人。"]'),
('a8d1276e-4c0b-4902-9d6a-5b081bc18da4','過宜陽城二首  其二','邵雍','宋','宋诗','song-poetry','','[]','當日宜陽號別都，柰何韓國特區區。',32,'全唐诗/poet.song.21000.json','["當日宜陽號別都，柰何韓國特區區。", "子房不得宣遺恨，博浪沙中中副車。"]'),
('9b71f834-8284-4609-9681-355f93ebbefc','十一日福昌縣會雨','邵雍','宋','宋诗','song-poetry','','[]','雲勢移峯緩，泉聲出竹遲。',24,'全唐诗/poet.song.21000.json','["雲勢移峯緩，泉聲出竹遲。", "此時無限意，唯有翠禽知。"]'),
('0a381740-7ebe-49c9-9525-6a3746195a9d','依韻和壽安尹尉有寄','邵雍','宋','宋诗','song-poetry','','[]','不向紅塵浪著鞭，殊無才業合時賢。',64,'全唐诗/poet.song.21000.json','["不向紅塵浪著鞭，殊無才業合時賢。", "本酬壯志都無效，欲住青山却有緣。", "翠竹陰中開縹帙，白雲堆裏揖飛泉。", "錦幈正與溪南對，他日從遊子子傳。"]'),
('d6911617-8e8d-4c9a-8a79-d72ea10cd8b1','十二日同福昌令王贊善遊龍潭十五里  其一','邵雍','宋','宋诗','song-poetry','','[]','一潭冷浸崖根黑，數峯高入雲衢碧。',32,'全唐诗/poet.song.21000.json','["一潭冷浸崖根黑，數峯高入雲衢碧。", "遊人屏氣不敢言，長恐雷霆奮於側。"]'),
('03258910-8cce-42dc-84fa-42a003ce9491','十二日同福昌令王贊善遊龍潭十五里  其二','邵雍','宋','宋诗','song-poetry','','[]','水邊靜坐天將暮，猶自盤桓未成去。',32,'全唐诗/poet.song.21000.json','["水邊靜坐天將暮，猶自盤桓未成去。", "馬上迴頭更一觀，雲煙已隔無重數。"]'),
('a85bf859-14a2-46b2-b379-68f1569c972b','十三日遊上寺及黄澗  其一','邵雍','宋','宋诗','song-poetry','','[]','能休塵境爲真境，未了僧家是俗家。',32,'全唐诗/poet.song.21000.json','["能休塵境爲真境，未了僧家是俗家。", "不向此中尋洞府，更於何處覓城花。"]'),
('9234bcdb-0e57-4f3e-9a91-4d8b9253ca99','十三日遊上寺及黄澗  其二','邵雍','宋','宋诗','song-poetry','','[]','堪嗟五伯爭周燼，可笑三分拾漢餘。',32,'全唐诗/poet.song.21000.json','["堪嗟五伯爭周燼，可笑三分拾漢餘。", "何似不才閑處坐，平時雲水遶衣裾。"]'),
('d51854f7-d6d2-40d8-b8c2-10a139a1d91d','十四日留題福昌縣宇之東軒','邵雍','宋','宋诗','song-poetry','','[]','洛川秋入景尤佳，微雨初過徑路斜。',128,'全唐诗/poet.song.21000.json','["洛川秋入景尤佳，微雨初過徑路斜。", "水竹洞中藏縣宇，煙嵐塢裏住人家。", "霜餘紅間千重葉，天外晴排數縷霞。", "溪淺溪深清瀲灧，峯高峯下碧查牙。", "鳥因擇木飛還遠，雲爲無心去更賒。", "蓋世功名多齟齬，出羣才業足咨嗟。", "浮生日月仍須惜，半老筋骸莫强誇。", "就此巖邊宜築室，樂吾真樂樂無涯。"]'),
('66f65b8a-3e0b-4719-b313-af235de2b146','十五日別福昌因有所感','邵雍','宋','宋诗','song-poetry','','[]','連昌宮廢昌河在，事去時移語浪傳。',32,'全唐诗/poet.song.21000.json','["連昌宮廢昌河在，事去時移語浪傳。", "下有荒祠難問處，古槐枝禿竹參天。"]'),
('20b77b67-aa77-4c48-ad18-e036c94ef31f','是夕宿至錦幈山下','邵雍','宋','宋诗','song-poetry','','[]','尋常看月亦嬋娟，不似今宵特地圓。',32,'全唐诗/poet.song.21000.json','["尋常看月亦嬋娟，不似今宵特地圓。", "疑是素娥紓宿憾，相逢爲在錦幈前。"]'),
('d6f90632-0df0-4934-a74f-3f6ee7f51041','十六日依韻酬福昌令有寄','邵雍','宋','宋诗','song-poetry','','[]','道義相歡豈易親，古稱難處是知人。',64,'全唐诗/poet.song.21000.json','["道義相歡豈易親，古稱難處是知人。", "文章不結市朝士，榮辱非關雲水身。", "話入精詳皆物理，言無形跡盡天真。", "他時洛社過從輩，圖牒中添又一隣。"]'),
('d92b5eb5-1f2f-4a3d-adef-163cd812e5e1','十七日錦幈山下謝城中張孫二君惠茶','邵雍','宋','宋诗','song-poetry','','[]','山似挼藍波似染，遊心一向難拘撿。',32,'全唐诗/poet.song.21000.json','["山似挼藍波似染，遊心一向難拘撿。", "仍携二友所分茶，每到煙嵐深處點。"]'),
('4f63d436-72db-4606-82f1-0ad62aaea491','壽安縣晚望','邵雍','宋','宋诗','song-poetry','','[]','休歎浮生榮與辱，且聽終日水潺潺。',64,'全唐诗/poet.song.21000.json','["休歎浮生榮與辱，且聽終日水潺潺。", "遥穿暝靄孤鴻去，橫截野煙雙鷺還。", "佳樹排青巖下圃，好峯環翠縣前山。", "報言名利差輕者，少輟光陰到此間。"]'),
('3876be5c-f170-4be0-87b6-7700cde2e9c0','十八日逾牽羊坂南達伊川墳上','邵雍','宋','宋诗','song-poetry','','[]','三尺荒墳百尺山，生身慈愛在其間。',32,'全唐诗/poet.song.21000.json','["三尺荒墳百尺山，生身慈愛在其間。", "此情至死不能盡，日暮徘徊又且還。"]'),
('7d8c7420-66d1-44fd-8d18-3035c332fdf3','思程氏父子兄弟因以寄之  其一','邵雍','宋','宋诗','song-poetry','','[]','年年時節近中秋，佳水佳山熳爛遊。',32,'全唐诗/poet.song.21000.json','["年年時節近中秋，佳水佳山熳爛遊。", "此際歸期爲君促，伊川不得久遲留。"]'),
('113b33e9-4513-467d-9519-70faa89ecca6','思程氏父子兄弟因以寄之  其二','邵雍','宋','宋诗','song-poetry','','[]','氣候如當日，山川似舊時。',24,'全唐诗/poet.song.21000.json','["氣候如當日，山川似舊時。", "獨來還獨往，此意有誰知。"]'),
('41eabb03-18e6-496e-968d-54260abe08bd','十九日歸洛城路遊龍門  其一','邵雍','宋','宋诗','song-poetry','','[]','伊川往復過龍山，每過龍山意且閑。',32,'全唐诗/poet.song.21000.json','["伊川往復過龍山，每過龍山意且閑。", "莫道移人不由境，可堪深著利名閒。"]'),
('448ea3f5-7050-406b-b190-97e6821918d2','十九日歸洛城路遊龍門  其二','邵雍','宋','宋诗','song-poetry','','[]','無煩物象弄精神，世態何常不喜新。',32,'全唐诗/poet.song.21000.json','["無煩物象弄精神，世態何常不喜新。", "唯有前墀好風月，清光依舊屬閑人。"]'),
('757b8894-4761-47c9-97c2-96745aaebc98','留題龍門  其一','邵雍','宋','宋诗','song-poetry','','[]','融結成來不記秋，斷崖蒼壁鏁煙愁。',64,'全唐诗/poet.song.21000.json','["融結成來不記秋，斷崖蒼壁鏁煙愁。", "中分洪造夏王力，橫截大山伊水流。", "八節灘聲長在耳，一川風景盡歸樓。", "行人莫動凭欄興，無限英雄浪白頭。"]'),
('056ee4a0-f810-4c9a-b70c-7416ae5733c8','留題龍門  其二','邵雍','宋','宋诗','song-poetry','','["\u534e\u5c71"]','誰將長劍斬長蛟，斬斷長蛟劍復韜。',64,'全唐诗/poet.song.21000.json','["誰將長劍斬長蛟，斬斷長蛟劍復韜。", "爪尾蜿蜒凝華嶽，角牙獰惡結嵩高。", "骨傷兩處嶄蒼壁，血出東流洶巨濤。", "此物猶難保身首，謂言讒口莫嗷嗷。"]'),
('fce9aa35-5bf5-4306-8a19-6e40dccf5259','龍門石樓看伊川','邵雍','宋','宋诗','song-poetry','','[]','數朝從欵走煙霞，縱意凭欄看物華。',64,'全唐诗/poet.song.21000.json','["數朝從欵走煙霞，縱意凭欄看物華。", "百尺樓臺通鳥道，一川煙水屬僧家。", "直須心逸方爲樂，始信官榮未足誇。", "此景得遊無事日，也宜知幸福無涯。"]'),
('d38b65ae-4b7a-432e-82bf-648cfca7ab13','二十日到城中見交舊','邵雍','宋','宋诗','song-poetry','','[]','年年此際走煙嵐，人亦何嘗謂我貪。',32,'全唐诗/poet.song.21000.json','["年年此際走煙嵐，人亦何嘗謂我貪。", "歸見交親話清勝，且無防患在三緘。"]'),
('a93e810b-ac42-463e-aa36-3490abfa12ca','二十二日晚步天津次日有詩','邵雍','宋','宋诗','song-poetry','','[]','溪翁昨晚步天津，步到天津佇立頻。',64,'全唐诗/poet.song.21000.json','["溪翁昨晚步天津，步到天津佇立頻。", "洛水只聞煎去棹，西風唯解促行人。", "山川慘淡籠寒雨，樓觀參差鏁暮雲。", "此景分明誰會得，欲霜時候鴈來賓。"]'),
('674c8da5-67be-46b7-9fc6-e06449a9b295','二十五日依韻和左藏吳傳正寺丞見贈','邵雍','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','上陽光景好看書，非象之中有坦途。',64,'全唐诗/poet.song.21000.json','["上陽光景好看書，非象之中有坦途。", "良月引歸芳草渡，快風飛過洞庭湖。", "不因赤水時時往，焉有黄芽日日娛。", "莫道天津便無事，也須閑處著功夫。"]'),
('f0399113-9bd3-474e-ab27-014a195548a3','二十九日依韻和洛陽陸剛叔主簿見贈','邵雍','宋','宋诗','song-poetry','','[]','一霎蕭蕭晚雨餘，鳳凰樓下偶驅車。',64,'全唐诗/poet.song.21000.json','["一霎蕭蕭晚雨餘，鳳凰樓下偶驅車。", "郄詵片玉知能挹，樂廣青天幸未踈。", "相闊夏秋聞甚事，可親燈火讀何書。", "恨無束帛嘉程子，徒自悁悁返弊廬。"]'),
('b0a0b2b5-6cb1-47a3-bed7-53fac880e59f','代書寄劍州普安令周士彥屯田  其一','邵雍','宋','宋诗','song-poetry','','[]','作官休用歎奚爲，未有升高不自卑。',64,'全唐诗/poet.song.21000.json','["作官休用歎奚爲，未有升高不自卑。", "君子屈伸方爲道，吾儒進退貴從宜。", "即今彭澤歸何地，他日東門去未遲。", "痛恨伊嵩景無限，一名佳處重求資。"]'),
('19d2a2e1-badb-4562-8d43-666b9a4218ab','代書寄劍州普安令周士彥屯田  其二','邵雍','宋','宋诗','song-poetry','','[]','二蜀至三吳，中間萬里餘。',48,'全唐诗/poet.song.21000.json','["二蜀至三吳，中間萬里餘。", "去年方北望，今歲復西驅。", "劍閣離天日，秦川限帝都。", "臨風相憶處，能飲一盃無。"]'),
('491321c4-7ad7-483e-8bcb-1236d6b07b1c','又一絕','邵雍','宋','宋诗','song-poetry','','[]','正當老輩過從日，況值高秋摇落天。',32,'全唐诗/poet.song.21000.json','["正當老輩過從日，況值高秋摇落天。", "一把黄花一樽酒，故人西去又經年。"]'),
('0cc31b0e-b4ee-4ddf-ad46-94dc7af0e118','和趙充道秘丞見贈','邵雍','宋','宋诗','song-poetry','','[]','人言人事危冠冕，吾愛吾廬遠市朝。',64,'全唐诗/poet.song.21000.json','["人言人事危冠冕，吾愛吾廬遠市朝。", "野面不堪趨魏闕，閑身唯稱訪楊寥。", "殊無紀律詩千首，富有雲山酒一瓢。", "預借軒車又東去，自茲風月恐難招。"]'),
('eb75ecec-2cfb-442b-a575-c3dbee7d01be','和王不疑郎中見贈','邵雍','宋','宋诗','song-poetry','','[]','二十年來住洛都，眼前人事任紛如。',64,'全唐诗/poet.song.21000.json','["二十年來住洛都，眼前人事任紛如。", "形同草木何勝野，心類鐘彝不啻虛。", "已沐仁風深骨髓，更驚詩思劇瓊璩。", "莊周休道虧名實，自是無才悅衆狙。"]'),
('11a7dbc8-ca18-46a7-b0b6-62835ca00419','和魏教授見贈','邵雍','宋','宋诗','song-poetry','','[]','清世文章日月懸，無才唯幸樂豐年。',64,'全唐诗/poet.song.21000.json','["清世文章日月懸，無才唯幸樂豐年。", "遊山太室更少室，看水伊川又洛川。", "古有孟軻難語覺，時無顔子易爲賢。", "讀書每到天根處，長懼諸公問極玄。"]'),
('7a2d26f5-df16-47e3-84ab-7ac78bcbd1ff','和吳沖卿省副見贈','邵雍','宋','宋诗','song-poetry','','[]','非有非無是祖卿，都來相去一毫芒。',64,'全唐诗/poet.song.21000.json','["非有非無是祖卿，都來相去一毫芒。", "人人可到我未到，物物不妨誰與妨。", "失即肝脾爲楚越，得之藜藿是膏粱。", "一言千古難知處，妙用仍須看呂粱。"]'),
('544618bc-abef-4193-ae50-104214d385a9','和孫傳師秘校見贈','邵雍','宋','宋诗','song-poetry','','[]','天津南畔是吾廬，時荷夫君枉乘車。',64,'全唐诗/poet.song.21000.json','["天津南畔是吾廬，時荷夫君枉乘車。", "始爲退來忘檢束，却因閑久長空踈。", "與其功業逋青史，孰若雲山負素書。", "一片丹誠最難狀，庶幾長得類舟虛。"]'),
('1b9a2f8d-abc8-4ef6-b639-8f3114f8f3e0','依韻和陳成伯著作長壽雪會','邵雍','宋','宋诗','song-poetry','','[]','瓊苑羣花一夜新，瑶臺十二玉爲塵。',64,'全唐诗/poet.song.21000.json','["瓊苑羣花一夜新，瑶臺十二玉爲塵。", "城中竹葉湧增價，坐上楊花盛學春。", "時會梁園皆墨客，誰思姑射有神人。", "餘糧豈止千倉望，盈尺仍宜莫厭頻。"]'),
('043b5c9d-f10c-41a1-b1b7-f6a61cb51225','依韻和陳成伯著作史館園會上作','邵雍','宋','宋诗','song-poetry','','[]','竹遶長松松遶亭，令人到此骨毛清。',64,'全唐诗/poet.song.21000.json','["竹遶長松松遶亭，令人到此骨毛清。", "梅稍带雪微微拆，水脈連冰湱湱鳴。", "殘臘歲華無柰感，半醺襟韻不勝情。", "誰憐相國名空在，吾道如何必可行。"]'),
('f2de4073-5871-49ad-bf5f-d740b2181772','和夔峽張憲白帝城懷古','邵雍','宋','宋诗','song-poetry','','[]','不憤曹公跨許昌，苟非梁益莫爭王。',64,'全唐诗/poet.song.21000.json','["不憤曹公跨許昌，苟非梁益莫爭王。", "三分區宇風雷惡，橫截西南氣勢强。", "行客往來閑批點，史官褒貶浪文章。", "後人未識興亡意，請看江心舊戰場。"]'),
('207f1c9f-ef62-4c47-9085-501bb679af31','閑適吟  其一','邵雍','宋','宋诗','song-poetry','','[]','爲士幸而居盛世，住家況復在中都。',64,'全唐诗/poet.song.21000.json','["爲士幸而居盛世，住家況復在中都。", "虛名浮利非我有，綠水青山何處無。", "選勝直宜尋美景，命儔須是擇吾徒。", "樂閑本屬閑人事，又與偷閑事更殊。"]'),
('c6d86065-1852-4b97-86e7-f4446af75f3f','閑適吟  其二','邵雍','宋','宋诗','song-poetry','','[]','六尺眼前安樂身，四時爭忍負佳辰。',64,'全唐诗/poet.song.21000.json','["六尺眼前安樂身，四時爭忍負佳辰。", "漫凉氣候二八月，道義賓朋三五人。", "量力盃盤隨草具，開懷語笑任天真。", "勸君似此清閑事，雖老何須更厭頻。"]'),
('f09a947f-3800-4a96-bd16-ac4029ad9bda','閑適吟  其三','邵雍','宋','宋诗','song-poetry','','[]','莫將真氣助憂傷，憤死英豪世更長。',64,'全唐诗/poet.song.21000.json','["莫將真氣助憂傷，憤死英豪世更長。", "陌上雖多馬跳躍，天邊亦有鳳翺翔。", "三千賓客磨圭角，百二山河擁劍鋩。", "等是一場春夢過，自餘惡足自悲凉。"]'),
('44fea96a-e4b7-42bb-bcb5-0bbe0c67bc5f','閑適吟  其四','邵雍','宋','宋诗','song-poetry','','[]','南窗睡起望春山，山在霏微煙靄間。',64,'全唐诗/poet.song.21000.json','["南窗睡起望春山，山在霏微煙靄間。", "千里難逃兩眼淨，百年未見一人閑。", "情如落絮無高下，心似遊絲自往還。", "又恐幽禽知此意，故來枝上語綿蠻。"]'),
('5bf1ab75-0185-4bf2-bf65-a85e6f083c27','閑適吟  其五','邵雍','宋','宋诗','song-poetry','','[]','誰將造化屬東風，一屬東風事莫窮。',64,'全唐诗/poet.song.21000.json','["誰將造化屬東風，一屬東風事莫窮。", "殘臘也宜先作策，新正其那便要功。", "柳梢借暖渾摇軟，梅萼偷春半露紅。", "安得曏時情意在，輕衫撩亂少年中。"]'),
('c3729dbe-7c28-41ac-a1b6-1002c7c7727e','桃李吟','邵雍','宋','宋诗','song-poetry','','[]','桃李因風花滿枝，因風桃李却離披。',64,'全唐诗/poet.song.21000.json','["桃李因風花滿枝，因風桃李却離披。", "慘舒相繼不離手，憂喜兩盤都在眉。", "泰到盛時須入蠱，否當極處却成隨。", "今人休愛古人好，只爲今人生較遲。"]'),
('263768b3-6ce1-4703-b838-e46cf0e2af18','傷心行','邵雍','宋','宋诗','song-poetry','','[]','不知何鐵打成針，一打成針只刺心。',32,'全唐诗/poet.song.21000.json','["不知何鐵打成針，一打成針只刺心。", "料得人心不過寸，刺時須刺十分深。"]'),
('4174045b-c43d-4b3c-9728-0b7f7da8583c','傷二舍弟無疾而化  其一','邵雍','宋','宋诗','song-poetry','','[]','手足情深不可忘，割心猶未比其傷。',64,'全唐诗/poet.song.21000.json','["手足情深不可忘，割心猶未比其傷。", "急難疇者爾相濟，終鮮如今我遂當。", "韡鞾棣開無并萼，邕邕鴈去破初行。", "自茲明月清風夜，蕭索東籬看斷腸。"]'),
('cd8e54f9-dae8-4a0c-bab6-a597be56de67','傷二舍弟無疾而化  其二','邵雍','宋','宋诗','song-poetry','','[]','腸斷東籬何所尋，東籬從此事沉沉。',64,'全唐诗/poet.song.21000.json','["腸斷東籬何所尋，東籬從此事沉沉。", "差肩行處皆成往，弔影傷時無似今。", "清淚已乾情莫極，黄泉未到恨非深。", "不知何日能銷盡，三十二年雍睦心。"]'),
('67a470f4-b3c6-4699-9895-ad297461f5d9','又一首','邵雍','宋','宋诗','song-poetry','','[]','兄既名雍弟名睦，弟兄雍睦情何足。',128,'全唐诗/poet.song.21000.json','["兄既名雍弟名睦，弟兄雍睦情何足。", "居常出入留一人，奉親教子如其欲。", "慈父享年七十九，四人稚子常相逐。", "其間同戲綵衣時，堂上愉愉歡可掬。", "慈父前年忽傾逝，爾弟今年命還促。", "獨予奉母引四子，日對幾筵相向哭。", "不知腸有幾千尺，不知淚有幾千斛。", "斷盡滴盡無柰何，曏日恩光焉可贖。"]'),
('83fc3f41-18ee-4ee5-8054-ded8b06a8217','又一絕','邵雍','宋','宋诗','song-poetry','','[]','手足恩情重，塤篪歡樂長。',24,'全唐诗/poet.song.21000.json','["手足恩情重，塤篪歡樂長。", "要知能忘處，墳草兩荒凉。"]'),
('ffd5356e-1135-4462-a158-37c2305ee110','聽杜鵑思亡弟','邵雍','宋','宋诗','song-poetry','','[]','嘗憶去年初夏時，與爾同聽杜鵑啼。',64,'全唐诗/poet.song.21000.json','["嘗憶去年初夏時，與爾同聽杜鵑啼。", "杜鵑今年又復至，還是去年初夏時。", "禽鳥亦知人意切，一聲未絕一聲悲。", "腸隨此聲既已斷，魂逐此禽何處飛。"]'),
('59457631-161b-4830-b6df-7e45c7051192','書亡弟殯所','邵雍','宋','宋诗','song-poetry','','[]','後乎吾來，先乎吾往。',20,'全唐诗/poet.song.21000.json','["後乎吾來，先乎吾往。", "當往之初，殊不相讓。"]'),
('c829b259-925e-44a0-850a-932604789903','南園南晚步思亡弟','邵雍','宋','宋诗','song-poetry','','[]','南園之南草如茵，迎風晚步清無塵。',48,'全唐诗/poet.song.21000.json','["南園之南草如茵，迎風晚步清無塵。", "不得與爾同歡欣，又疑天上有飛雲。", "一片世間來作人，飄來飄去殊無因。"]'),
('0db2ad75-1a64-4c03-ba93-4a1dc6585ee3','自憫','邵雍','宋','宋诗','song-poetry','','[]','天無私覆古今同，手足情多驟一空。',64,'全唐诗/poet.song.21000.json','["天無私覆古今同，手足情多驟一空。", "五七年來併家難，六十歲許更頭風。", "常情不免順世俗，私計固難專僕童。", "安得仙人舊查在，伊川雲水樂無窮。"]'),
('79b4a734-c735-4397-8c11-a4f6d36aa20c','戊申自貽','邵雍','宋','宋诗','song-poetry','','[]','雖老仍思鼓缶歌，庶幾都未喪天和。',64,'全唐诗/poet.song.21000.json','["雖老仍思鼓缶歌，庶幾都未喪天和。", "明夷用晦止于是，無妄生災終柰何。", "似箭光陰頭上去，如麻人事眼前過。", "中間若不自爲計，所損其來又更多。"]'),
('70d60dd5-f3da-4ebb-9ba8-9a829ccdefbf','代書寄北海幕趙充道太博','邵雍','宋','宋诗','song-poetry','','[]','自從終鮮罷吟哦，聊爲臨風一浩歌。',64,'全唐诗/poet.song.21000.json','["自從終鮮罷吟哦，聊爲臨風一浩歌。", "別易會難情不已，登高望遠興如何。", "百年可惜時無再，千里相思事更多。", "今日樽疊真北海，況君雅重幾人過。"]'),
('d3729751-f921-4561-9f36-07ca1ff5722f','依韻和王不疑少卿見贈','邵雍','宋','宋诗','song-poetry','','[]','不把憂愁累物華，光陰過眼疾如車。',64,'全唐诗/poet.song.21000.json','["不把憂愁累物華，光陰過眼疾如車。", "以平爲樂忝知分，待足求安恐未涯。", "食罷有時尋蕙圃，睡餘無事訪僧家。", "天津風月勝他處，長是思君共煮茶。"]'),
('130a741a-26a7-420e-a8cd-ad20d883235e','仁者吟','邵雍','宋','宋诗','song-poetry','','[]','仁者難逢思有常，平居慎勿恃無傷。',64,'全唐诗/poet.song.21000.json','["仁者難逢思有常，平居慎勿恃無傷。", "爭先徑路機關惡，近後語言滋味長。", "爽口物多須作疾，快心事過必爲殃。", "與其病後能求藥，不若病前能自防。"]'),
('986689b0-7c08-4dd3-8498-e7d39f1cfd06','東軒消梅初開勸客酒二首  其一','邵雍','宋','宋诗','song-poetry','','[]','爲愛消梅勝早梅，數枝先發日徘徊。',64,'全唐诗/poet.song.21000.json','["爲愛消梅勝早梅，數枝先發日徘徊。", "若教嶺表臘前盡，安有洛陽正後開。", "香逐暖風初出谷，艷隨芳酒正浮醅。", "佳賓會取東君意，莫負乘春此際來。"]'),
('27fc263f-659e-44e3-9964-4546493701a5','東軒消梅初開勸客酒二首  其二','邵雍','宋','宋诗','song-poetry','','[]','春色融融滿洛城，莫辭行樂慰平生。',64,'全唐诗/poet.song.21000.json','["春色融融滿洛城，莫辭行樂慰平生。", "深思閑友開眉笑，重惜梅花照眼明。", "況是山翁差好事，可憐芳酒最多情。", "此時不向樽前醉，更向何時醉太平。"]'),
('0e3bf1ef-9936-4ac1-a682-2b833cb2267d','清風長吟','邵雍','宋','宋诗','song-poetry','','[]','宇宙中和氣，清泠無比方。',216,'全唐诗/poet.song.21000.json','["宇宙中和氣，清泠無比方。", "與時蠲疾病，爲歲造豐穰。", "起自青蘋末，來從翠樹傍。", "得逢明月夜，便入故人鄉。", "密葉摇重幄，殷花舞靚粧。", "兩三聲逈笛，千萬縷垂楊。", "細度絲桐韻，深傳蘭蕙香。", "樓臺臨遠水，軒檻近脩篁。", "盛夏驅煩暑，初晴送晚凉。", "輕披綠荷芰，緩透薄衣裳。", "浪走翻翩袂，波生瀲灧觴。", "閑愁難著莫，幽思易飛揚。", "快若乘天馬，醒如沃蔗漿。", "面前遊閬苑，坐上泛瀟湘。", "不可將錢買，焉能用斗量。", "依憑全藉德，收貯豈須倉。", "無患兼并取，寧憂寇盜攘。", "以茲爲樂事，未始有憂傷。"]'),
('dc9a50a2-58f0-4bc5-93bb-af126dfffaf7','垂柳長吟','邵雍','宋','宋诗','song-poetry','','[]','垂柳有兩種，有長有短垂。',288,'全唐诗/poet.song.21000.json','["垂柳有兩種，有長有短垂。", "唯茲長一種，偏與靜相宜。", "院宇深春後，亭臺晚景時。", "不勝煙羃羃，無柰日遲遲。", "霢霂雨初過，清泠風乍吹。", "章臺街左右，華表柱東西。", "起眼出牆樹，拂頭當路枝。", "翩翻綠羅带，縹緲縷金衣。", "蕩颺飄晴絮，繽紛舞暖絲。", "絲牽寸腸斷，絮入萬家飛。", "婀娜王巷韻，婆娑趙后姿。", "脩妍張緒少，柔軟沈侯羸。", "濯濯青拖地，毿毿翠遶池。", "般添花灼灼，引惹草凄凄。", "欝欝籠山館，踈踈映酒旗。", "贈人人自泣，駐馬馬還嘶。", "影裏咿啞去，陰中轣轆歸。", "凄凉裝暝靄，淡薄掛斜暉。", "懊惱輕攀折，憂愁重別離。", "早衰緣傍道，先茂爲臨溪。", "樓外蟬纔噪，橋邊鸎又啼。", "生憎遮望眼，死恨學粧眉。", "遠客莫知數，長條曾繫誰。", "經霜儘憔悴，來歲却依依。"]'),
('9220eeb3-563d-4f62-9518-871cd0502e0d','落花長吟','邵雍','宋','宋诗','song-poetry','','[]','以酒戰花穠，花穠酒更濃。',288,'全唐诗/poet.song.21000.json','["以酒戰花穠，花穠酒更濃。", "花能十日盡，酒未百壺空。", "尚喜裝衣袂，猶憐墜酒鐘。", "多情唯粉蝶，薄倖是遊蜂。", "減却牆頭艷，添爲徑畔紅。", "飄零深院宇，點綴靜簾櫳。", "又恐隨流水，仍憂嫁遠風。", "水流猶委曲，風遠便西東。", "狼籍殘春後，離披晚照中。", "亭臺雖有主，軒騎斷無蹤。", "劍去擁妃子，兵來圍石崇。", "馬嵬方戀戀，金谷正匆匆。", "曹植辭休切，襄王夢已終。", "謬稱尋洛浦，浪說數巫峰。", "燕訴冤還在，鸎傳信莫通。", "苔錢如可買，柳線自能縫。", "悵望尤真宰，凄凉殢化工。", "放教成爛漫，不使略從容。", "命掃心爭忍，言收計遂窮。", "異香銷骨髓，絕色死英雄。", "任詫回天力，饒矜蓋世功。", "柰何時既往，到了事難重。", "開謝形相戾，興衰理一同。", "天機之淺者，未始免忡忡。"]'),
('77af0092-9b95-4b68-82d1-84d1011e70ca','芳草長吟','邵雍','宋','宋诗','song-poetry','','[]','芳草更休生，芳樽更不傾。',288,'全唐诗/poet.song.21000.json','["芳草更休生，芳樽更不傾。", "草如生不已，樽豈便能停。", "雨後閑池閣，春深小院庭。", "是時簾半捲，此際酒初醒。", "密密嫩方布，葺葺綠已成。", "送回殘照淡，引起曉寒輕。", "靜襯花村薄，閑裝竹塢清。", "溪邊微水浸，原上未春耕。", "莫遣香車輾，休教細馬行。", "籍餘無限意，望久不勝情。", "臺逈眉初斂，樓危眼乍明。", "低低暮雲碧，隠隠遠山青。", "翠接鴛鴦浦，萋連楊柳汀。", "江潭夜帆落，海渚晚舟橫。", "戍壘角一弄，牧童笛數聲。", "沙頭雙鷺下，渡口亂鴻驚。", "蓊鬰出征地，芊綿奉使程。", "遠披來往路，遍遶短長亭。", "苒苒秦皇墓，離離漢帝城。", "荒凉故銅雀，破碎舊金陵。", "霧鏁前朝事，煙昏後世名。", "枯猶藏狡兔，腐亦化流螢。", "縱剗奚由盡，纔燒又却榮。", "徒能蔽京觀，仍願且升平。"]'),
('c78c81ef-1f89-4b12-9af1-ac63697348fe','春水長吟','邵雍','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','春在水自淥，春歸淥遂休。',240,'全唐诗/poet.song.21000.json','["春在水自淥，春歸淥遂休。", "清非不逮淥，春柰勝于秋。", "淥向陽中得，清於冷上求。", "加於清一等，用是淥爲優。", "薄薄冰初泮，微微雨乍收。", "渺瀰新島嶼，瀲灧舊汀洲。", "荷芰低猶卷，菰蒲嫩已抽。", "蘋繁雖漸出，藻荇禾全稠。", "日煖鴛鴦浴，煙晴翡翠游。", "波平雙躍鯉，風靜戲羣鷗。", "西蜀遨爭舉，東甌禊競修。", "武陵花再識，漢曲珮還投。", "臺下溶溶過，堤邊漫漫流。", "檻前纔泚泚，天外更悠悠。", "泛濫情懷惡，潺湲意思幽。", "遠山遮不斷，別浦去難留。", "二月溪橋畔，三吳野渡頭。", "依前橫兩槳，特地送孤舟。", "畫手方停筆，騷人正倚樓。", "長江飛絮外，只是動離愁。"]'),
('7d409e8c-7f82-45ec-a50b-f9028effefe4','花月長吟','邵雍','宋','宋诗','song-poetry','','[]','少年貪讀兩行書，人世樂事都如愚。',224,'全唐诗/poet.song.21000.json','["少年貪讀兩行書，人世樂事都如愚。", "而今却欲釋前憾，柰何意氣難如初。", "每逢花開與月圓，一般情態還何如。", "當此之際無詩酒，情亦願死不願甦。", "花逢皓月精神好，月見奇花光彩舒。", "人與花月合爲一，但覺此身遊蕊珠。", "又恐月爲雲阻隔，又恐花爲風破除。", "若無詩酒重收管，過此又却成輕辜。", "可收幸有長詩篇，可管幸有清酒壺。", "詩扁酒壺時一講，長如花月相招呼。", "有花無月愁花老，有月無花恨月孤。", "月恨只憑詩告訴，花愁全仰酒枝梧。", "月恨花愁無一點，始知詩酒有功夫。", "些兒林下閑踈散，做得風流罪過無。"]'),
('5e5c634a-7b3a-43f2-9b03-8e54e78b85e1','同府尹李給事遊上清宮','邵雍','宋','宋诗','song-poetry','','[]','洛城二月春摇蕩，桃李盛開如步障。',64,'全唐诗/poet.song.21000.json','["洛城二月春摇蕩，桃李盛開如步障。", "高花下花紅相連，垂陽更出高花上。", "閑陪大尹出都門，邙阜真宮共尋訪。", "不見翠華西幸時，臨風盡日獨惆悵。"]'),
('065d7583-3c61-426f-b3dd-e653d3b1579c','乞笛竹栽於李少保宅','邵雍','宋','宋诗','song-poetry','','[]','浪種閑花占地生，未嘗容易暫留情。',64,'全唐诗/poet.song.21000.json','["浪種閑花占地生，未嘗容易暫留情。", "柰何苦愛凌霜節，況是猶存縷管名。", "待鳳至時當有實，學龍吟處豈無聲。", "幽人願乞數枝種，得自君家又更榮。"]'),
('e9889eb1-f38a-4132-a0e9-3459b011e356','思山吟  其一','邵雍','宋','宋诗','song-poetry','','[]','看即青山與白雲，尋思沒量大功勳。',64,'全唐诗/poet.song.21000.json','["看即青山與白雲，尋思沒量大功勳。", "未知樂處緣何事，豈止饑時會茹葷。", "千首拙詩難著怨，一樽芳醑別涵春。", "壺中日月長多少，能老紅塵幾輩人。"]'),
('8c44e4e3-fb8e-49f0-abd2-cc79bbdd8399','思山吟  其二','邵雍','宋','宋诗','song-poetry','','[]','祇恐身閑心未閑，心閑何必住雲山。',64,'全唐诗/poet.song.21000.json','["祇恐身閑心未閑，心閑何必住雲山。", "果然得手情性上，更肯埋頭利害間。", "動止未嘗防忌諱，語言何復著機關。", "不圖爲樂至于此，天馬無蹤自往還。"]'),
('6cc007ff-a0ec-4713-ae8d-32b462405e8b','恨月吟','邵雍','宋','宋诗','song-poetry','','[]','我儂非是惜黄金，自是常娥愛負心。',64,'全唐诗/poet.song.21000.json','["我儂非是惜黄金，自是常娥愛負心。", "初未上時猶露滴，恰纔圓處便天陰。", "欄桿倚了還重倚，芳酒斟迴又再斟。", "安得深閨與收管，柰何前後誤人深。"]'),
('393080fc-b785-4574-a9e2-1381e2dd6779','愁花吟','邵雍','宋','宋诗','song-poetry','','[]','三千宮女衣宮袍，望幸心同各自嬌。',64,'全唐诗/poet.song.21000.json','["三千宮女衣宮袍，望幸心同各自嬌。", "初似綻時猶淡薄，半來開處特妖嬈。", "檀心未吐香先發，露粉既垂魂已銷。", "對此芳樽多少意，看看風雨騁麄豪。"]'),
('32d4180b-e65f-4dc5-982f-2e314bad8485','和張子望洛城觀花','邵雍','宋','宋诗','song-poetry','','[]','造化從來不負人，萬般紅紫見天真。',32,'全唐诗/poet.song.21000.json','["造化從來不負人，萬般紅紫見天真。", "滿城車馬空撩亂，未必逢春便得春。"]'),
('32517c26-0b16-489d-be23-2a2c6e3161ad','落花短吟','邵雍','宋','宋诗','song-poetry','','[]','滿園桃李正離披，更被狂風作意吹。',64,'全唐诗/poet.song.21000.json','["滿園桃李正離披，更被狂風作意吹。", "長是憂愁初謝處，却須思念未開時。", "柰何紅艷易消歇，不似青陰少改移。", "九十日春都去盡，樽前安忍更顰眉。"]'),
('574888e4-eabf-4e88-a9af-6fac0d27b62f','芳草短吟','邵雍','宋','宋诗','song-poetry','','[]','花間水畔綠如茵，興廢曾經漢與秦。',64,'全唐诗/poet.song.21000.json','["花間水畔綠如茵，興廢曾經漢與秦。", "占了山川無限地，愁傷今古幾何人。", "嚴霜殺盡還逢雨，野火燒殘又遇春。", "不那路傍多此物，農家長是費耕耘。"]'),
('82d981a7-b6e1-4295-b270-1d111dad54c1','垂柳短吟','邵雍','宋','宋诗','song-poetry','','[]','臨溪拂水正依依，更被狂風來往吹。',64,'全唐诗/poet.song.21000.json','["臨溪拂水正依依，更被狂風來往吹。", "薄暮不勝煙羃羃，深春無柰日遲遲。", "誰家縹緲青羅帔，何處蹁躚金縷衣。", "猶恐離人腸未斷，滿天仍著亂花飛。"]'),
('3e8e065a-c72d-48bb-9a11-1b3fdb4ef97e','春水短吟','邵雍','宋','宋诗','song-poetry','','[]','雪消冰泮淥盈溝，翡翠鴛鴦得志秋。',64,'全唐诗/poet.song.21000.json','["雪消冰泮淥盈溝，翡翠鴛鴦得志秋。", "長恨遠山遮不斷，又疑別浦去難留。", "遶堤楊柳輕輕拂，近岸新蒲細細抽。", "滿眼煙波杳無際，三吳特地送孤舟。"]'),
('0cb0b6f0-216f-4144-b8ff-863cafaf2531','清風短吟','邵雍','宋','宋诗','song-poetry','','[]','清風興況未全衰，豈謂天心便棄遺。',64,'全唐诗/poet.song.21000.json','["清風興況未全衰，豈謂天心便棄遺。", "長具齋莊緣讀易，每慙踈散爲吟詩。", "人間好景皆輸眼，世上閑愁不到眉。", "生長太平無事日，又還身老太平時。"]'),
('e4a0302c-c285-4320-8a1a-17dea5b3a283','暮春寄李審言龍圖','邵雍','宋','宋诗','song-poetry','','[]','年年長是怕春深，每到春深病不任。',64,'全唐诗/poet.song.21000.json','["年年長是怕春深，每到春深病不任。", "傷酒情懷因小會，養花天氣爲輕陰。", "歲華易革向來事，節物難迴老去心。", "唯有前軒堪靜坐，臨風想望舊知音。"]'),
('b712edfa-17e0-4390-b816-a114820714cf','初夏閑吟','邵雍','宋','宋诗','song-poetry','','[]','綠楊深處囀流鶑，鶑語猶能喜太平。',64,'全唐诗/poet.song.21000.json','["綠楊深處囀流鶑，鶑語猶能喜太平。", "人享永年非不幸，天生珍物豈無情。", "牡丹謝後紫櫻熟，芍藥開時斑笋生。", "林下一般閑富貴，何嘗更肯讓公卿。"]'),
('278436dd-a4f7-4a0e-afe5-e1cd15a542a2','代書答開封府推官姚輔周郎中','邵雍','宋','宋诗','song-poetry','','[]','世態其如與願違，必須言進是無知。',64,'全唐诗/poet.song.21000.json','["世態其如與願違，必須言進是無知。", "遍將底事閑思處，不若西街極論時。", "設有奇才能動世，柰何雙鬢已如絲。", "天邊新月從來細，不爲人間愛畫眉。"]'),
('a972733a-a3ca-43c2-800c-98afb881a9ee','代書寄濠倅張都官','邵雍','宋','宋诗','song-poetry','','[]','多慙吾亦未知音，天樂雖聞不許尋。',64,'全唐诗/poet.song.21000.json','["多慙吾亦未知音，天樂雖聞不許尋。", "惠子相時情自好，莊生遊處意能深。", "閑來略記一春事，老去難忘千里心。", "洛社交朋每相見，爲吾因掉白頭吟。"]'),
('53e82880-944c-4d13-a92b-b62861f748c1','詔三下答鄉人不起之意','邵雍','宋','宋诗','song-poetry','','[]','生平不作皺眉事，天下應無切齒人。',64,'全唐诗/poet.song.21000.json','["生平不作皺眉事，天下應無切齒人。", "斷送落花安用雨，裝添舊物豈須春。", "幸逢堯舜爲真主，且放巢由作外臣。", "六十病夫宜揣分，監司無用苦開陳。"]'),
('b6e185bf-02b8-4feb-b826-2a1c9238af48','和王安之少卿韻','邵雍','宋','宋诗','song-poetry','','[]','却恐鄉人未甚知，相知深後又何疑。',64,'全唐诗/poet.song.21000.json','["却恐鄉人未甚知，相知深後又何疑。", "貧時與祿是可受，老後得官難更爲。", "自有林泉安素志，況無才業動丹墀。", "荀楊若守吾儒分，免被韓文議小疵。"]'),
('12463479-e707-496b-850f-6394a8efcfcf','依韻和劉職方見贈','邵雍','宋','宋诗','song-poetry','','[]','造物工夫意自深，從吾所樂是山林。',64,'全唐诗/poet.song.21000.json','["造物工夫意自深，從吾所樂是山林。", "少因多病不干祿，老爲無才難動心。", "花月靜時行水際，蕙風香處卧松陰。", "閑窗一覺從容睡，願當封侯與賜金。"]'),
('7cffca7b-a95a-4bc1-a7f9-a155c60647cb','代書謝王勝之學士寄萊石茶酒器','邵雍','宋','宋诗','song-poetry','','[]','東山有石若瓊玖，匠者追琢可盛酒。',304,'全唐诗/poet.song.21000.json','["東山有石若瓊玖，匠者追琢可盛酒。", "君子得之惜不用，慇懃遠寄林下叟。", "林叟從來用瓦盞，驚惶不敢擎上手。", "重誡兒童無損傷，緘藏復以待賢友。", "未知賢友何時歸，男子功名未成就。", "朝廷先從憂者言，方今莫如二虜醜。", "漢之六郡限遼西，唐之八州隔山後。", "自餘瓜沙甘與凉，中原久而不能有。", "柰何更餌以金帛，重困吾民猶掣肘。", "若非堂上出奇兵，安得閫外拉餘朽。", "直可逐去此腥羶，西出玉門北逾口。", "城下狐狸既不存，路上豺狼自無走。", "太陽烜赫耀天衢，氛妖接變匿塵垢。", "功成不肯受上賞，印解黄金大于斗。", "乞洛辭君出國門，歸鞍暖拂天街柳。", "千官如壁遮道留，仰面弄鞭不回首。", "鄉人夾路迎大尹，醉擁旌幢錦光溜。", "下車拜墓還政餘，不訪公門訪親舊。", "始知此器用有時，吾當爲君獻眉壽。"]'),
('2ea34dbb-6f47-4182-9dfb-d9f6734d3063','崇德閣下答諸公不語禪','邵雍','宋','宋诗','song-poetry','','[]','浩浩長空走日輪，何煩苦苦辨根塵。',64,'全唐诗/poet.song.21000.json','["浩浩長空走日輪，何煩苦苦辨根塵。", "鵬程萬里非由駕，鶴筭三千別有春。", "鉛錫點金終屬假，丹青畫馬妄求真。", "請觀風急天寒夜，誰是當門定脚人。"]'),
('283831d3-39e2-48fe-bb96-2db8244b69e4','天宮小閣倚欄','邵雍','宋','宋诗','song-poetry','','[]','六尺殘軀病復羸，況堪日日更添衰。',64,'全唐诗/poet.song.21000.json','["六尺殘軀病復羸，況堪日日更添衰。", "滿懷可惜精明處，一語未能分付時。", "沙裏有金然索揀，石中韞玉柰何疑。", "此情牢落西風暮，倚遍欄干人不知。"]'),
('54699560-138c-4b55-938f-17595a214272','代書寄華山雲臺觀武道士','邵雍','宋','宋诗','song-poetry','','[]','太華中峯五千仞，下有大道人往還。',64,'全唐诗/poet.song.21000.json','["太華中峯五千仞，下有大道人往還。", "當時馬上一回首，十載夢魂猶過關。", "生平愛山山未足，由此看盡天下山。", "求如華山是難得，使人消得一生閑。"]'),
('05b330ef-7e1c-4a17-90c4-8f3e0ded0c1d','代書寄長安幕張文通','邵雍','宋','宋诗','song-poetry','','[]','無學又無謀，胸中一向虛。',48,'全唐诗/poet.song.21000.json','["無學又無謀，胸中一向虛。", "枯腸忺飲酒，病眼怕看書。", "洛浦輕風裏，天津小雨餘。", "故人千里隔，相望意何如。"]'),
('262db09b-d677-411c-b169-eca2e8a08604','和人聞韓魏公出鎮永興過洛','邵雍','宋','宋诗','song-poetry','','[]','佐命三朝爲太宰，名垂千古號元功。',64,'全唐诗/poet.song.21000.json','["佐命三朝爲太宰，名垂千古號元功。", "栽培桃李滿天下，出入風濤半海中。", "虎帳夜寒心益壯，鳳池波暖位猶空。", "君王鼎盛子儀在，萬里河湟不足攻。"]'),
('2e18882d-5612-484a-b76f-144a9392f80f','代書寄白波張景真輦運','邵雍','宋','宋诗','song-poetry','','[]','秋入山河氣象雄，不堪閑望老年中。',64,'全唐诗/poet.song.21000.json','["秋入山河氣象雄，不堪閑望老年中。", "金蘭契重思無限，手足情多感未終。", "半局殘棋銷白晝，一簪華髮亂西風。", "唯君父子相知久，松桂心同色更同。"]'),
('36f36140-ebf5-435a-90b3-3cf1788906b3','代書寄鄞江知縣張太博','邵雍','宋','宋诗','song-poetry','','[]','長憶當年歸弊廬，弟兄同受策名初。',64,'全唐诗/poet.song.21000.json','["長憶當年歸弊廬，弟兄同受策名初。", "一生不記尋常事，千里猶通咫尺書。", "風月遥知四明好，江山況是九秋餘。", "片帆未得閑飛去，徒見嚴君問起居。"]'),
('2904d0ef-3ee2-4077-b18f-a02bfa4037d1','先幾吟','邵雍','宋','宋诗','song-poetry','','[]','先幾能識是吾儕，慎勿輕爲世俗咍。',64,'全唐诗/poet.song.21000.json','["先幾能識是吾儕，慎勿輕爲世俗咍。", "把似衆中呈醜拙，爭如靜裏且談諧。", "奇花萬狀皆輸眼，明月一輪長入懷。", "似此光陰豈虛過，也知快活作人來。"]'),
('2f998e3e-e26b-4f77-8cb0-5f73000ec257','秋暮西軒','邵雍','宋','宋诗','song-poetry','','[]','遶欄種菊一齊芳，戶牖軒窗總是香。',64,'全唐诗/poet.song.21000.json','["遶欄種菊一齊芳，戶牖軒窗總是香。", "得意不能無興詠，樂時況復遇豐穰。", "深秋景物隨宜好，向老筋骸粗且康。", "飲罷何防更登眺，爛霞堆裏有斜陽。"]'),
('a1bef336-f414-4052-96ac-99c644adabd7','天津閑步','邵雍','宋','宋诗','song-poetry','','[]','洛陽城裏任西東，二十年來放盡慵。',64,'全唐诗/poet.song.21000.json','["洛陽城裏任西東，二十年來放盡慵。", "故舊人多時欵曲，京都國大體雍容。", "池平有類江湖上，林靜或如山谷中。", "不必奇功蓋天下，閑居之樂自無窮。"]'),
('914bc84f-161f-4569-bdbf-18ed4c5c9d48','寄和長安張强二機冝','邵雍','宋','宋诗','song-poetry','','[]','二公詩美過連城，欲報才非禰正平。',64,'全唐诗/poet.song.21000.json','["二公詩美過連城，欲報才非禰正平。", "本謂柏舟終不遇，却驚華衮重爲榮。", "岷峨雨後方知峭，風月霜餘始見清。", "前有古人稱寡和，陽春白雪豈虛名。"]'),
('3ee6c479-5160-446e-881e-f9444b0fc88e','代書答淮南憲張司封','邵雍','宋','宋诗','song-poetry','','[]','緣木求魚固不能，緣魚求炙恐能行。',64,'全唐诗/poet.song.21000.json','["緣木求魚固不能，緣魚求炙恐能行。", "與其病後求良藥，不若醉時辭大觥。", "芝草無根休用種，蟠桃有實豈難生。", "荷君見愛情非淺，一芥還同一芥榮。"]'),
('32e60ef2-ea78-42e2-80e6-59c3be57b01f','偶得吟','邵雍','宋','宋诗','song-poetry','','[]','集大成人不肯模，却行何異棄金車。',64,'全唐诗/poet.song.21000.json','["集大成人不肯模，却行何異棄金車。", "便言天下無難事，豈信人間有丈夫。", "天意順時爲善計，人情安處是良圖。", "天人之際只些子，過此還同隔五湖。"]'),
('5c94b661-cf38-46f3-9f43-ee6b8e0acf10','代書寄友人','邵雍','宋','宋诗','song-poetry','','[]','一別光陰二紀餘，歲華如箭止堪吁。',64,'全唐诗/poet.song.21000.json','["一別光陰二紀餘，歲華如箭止堪吁。", "東西契闊久經難，前後慇懃兩得書。", "故國山川皆夢寐，舊家人物半丘墟。", "何時重講當時事，笑對西風坼酒壺。"]'),
('a7bf0066-c9c9-48c8-bfb4-702a1eda32be','風吹木葉吟','邵雍','宋','宋诗','song-poetry','','[]','風吹木葉不吹根，慎勿將根苦自陳。',64,'全唐诗/poet.song.21000.json','["風吹木葉不吹根，慎勿將根苦自陳。", "天子舊都閑好住，聖人餘事冗休論。", "長年國裏神仙侶，安樂窩中富貴人。", "萬水千山行已遍，歸來認得自家身。"]'),
('7056d0c3-f62f-43e1-98d6-f633e6cf88ff','閑行吟  其一','邵雍','宋','宋诗','song-poetry','','[]','長憶當年歸弊廬，未嘗三徑草荒蕪。',64,'全唐诗/poet.song.21000.json','["長憶當年歸弊廬，未嘗三徑草荒蕪。", "欲爲天下屠龍手，肯讀人間非聖書。", "否泰悟來知進退，乾坤見了識親踈。", "自從會得環中意，閑氣胸中一點無。"]'),
('137a4684-d5c4-4201-9017-334f0aea01cf','閑行吟  其二','邵雍','宋','宋诗','song-poetry','','[]','投吳走越覓青天，殊不知天在眼前。',64,'全唐诗/poet.song.21000.json','["投吳走越覓青天，殊不知天在眼前。", "開眼見是猶有病，舉頭尋處更無緣。", "顔淵正在如愚日，孟子方當不動年。", "安得功夫遊寶肆，愛人珠貝重憂錢。"]'),
('7a5a1da4-cc0c-432d-94d5-6973590bdd52','閑行吟  其三','邵雍','宋','宋诗','song-poetry','','[]','買卜稽疑是買疑，病深何藥可能醫。',64,'全唐诗/poet.song.21000.json','["買卜稽疑是買疑，病深何藥可能醫。", "夢中說夢重重妄，牀上安牀疊疊非。", "列子御風徒有待，夸夫逐日豈無疲。", "勞多未有收功處，踏盡人間閑路岐。"]'),
('48f788c2-b7ad-427a-9d0c-ffdf4ce19716','對花飲','邵雍','宋','宋诗','song-poetry','','[]','人言物外有煙霞，物外煙霞豈足誇。',64,'全唐诗/poet.song.21000.json','["人言物外有煙霞，物外煙霞豈足誇。", "若用校量爲樂事，但無憂撓是仙家。", "百年光景留難住，十日芳菲去莫遮。", "對酒無花非負酒，對花無酒是虧花。"]'),
('94dd3c56-de8d-4d95-9169-72bef884da86','春盡後園閑步','邵雍','宋','宋诗','song-poetry','','[]','綠樹成陰日，黄鸎對語時。',48,'全唐诗/poet.song.21000.json','["綠樹成陰日，黄鸎對語時。", "小渠初瀲灧，新竹正參差。", "倚杖閑吟久，携童引步遲。", "好風知我意，故故向人吹。"]'),
('fa00857b-d695-410b-bea1-0f2559796d91','代書寄吳傳正寺丞','邵雍','宋','宋诗','song-poetry','','[]','敦篤情懷世所稀，昔年今日事難追。',64,'全唐诗/poet.song.21000.json','["敦篤情懷世所稀，昔年今日事難追。", "雪霜未始寒無甚，松桂何嘗色暫移。", "洛邑士人雖我信，天津風月只君知。", "夢魂不悟東都遠，依舊過從似舊時。"]'),
('38d749c1-fba7-440c-847d-1c2ecfe4b3ac','洛下園池','邵雍','宋','宋诗','song-poetry','','[]','洛下園池不閉門，洞天休用別尋春。',64,'全唐诗/poet.song.21000.json','["洛下園池不閉門，洞天休用別尋春。", "縱遊只却輸閑客，遍入何嘗問主人。", "更小亭欄花自好，儘荒臺榭景纔真。", "虛名誤了無涯事，未必虛名總到身。"]'),
('dabbda6a-2a1d-4c8a-a403-d36c7ee185f8','夢過城東謁洛陽尉楊應之','邵雍','宋','宋诗','song-poetry','','[]','夜來清夢過城東，溪水分流徑路通。',32,'全唐诗/poet.song.21000.json','["夜來清夢過城東，溪水分流徑路通。", "全似乘查上天漢，但無嚴子驗行蹤。"]'),
('82ae1d05-8c6e-4d95-8f0c-22535db7cbbb','代書寄前洛陽簿陸剛叔秘校','邵雍','宋','宋诗','song-poetry','','[]','洛城官滿振衣裾，塵土何由浼遠途。',64,'全唐诗/poet.song.21000.json','["洛城官滿振衣裾，塵土何由浼遠途。", "道在幸逢清日月，眼明應見舊江湖。", "知行知止唯賢者，能屈能伸是丈夫。", "歸去何妨趁殘水，三吳還似嚮時無。"]'),
('7975d32c-1b4c-4158-8711-d8d7085d7b2c','答人乞碧蘆','邵雍','宋','宋诗','song-poetry','','[]','草有可嘉者，莫將蕭艾儔。',48,'全唐诗/poet.song.21000.json','["草有可嘉者，莫將蕭艾儔。", "扶踈全類竹，蒼翠特宜秋。", "風雨聲初入，江湖思莫收。", "無功濟天下，藉此一淹留。"]'),
('cffd43c5-3914-408d-b24b-a01714431e70','逍遥吟  其一','邵雍','宋','宋诗','song-poetry','','[]','吾道本來平，人多不肯行。',48,'全唐诗/poet.song.21000.json','["吾道本來平，人多不肯行。", "得心無後味，失脚有深坑。", "若未通天地，焉能了死生。", "向其間一事，須是自誠明。"]'),
('946b6093-13fc-4d23-808d-a538e063a083','逍遥吟  其二','邵雍','宋','宋诗','song-poetry','','[]','人生憂不足，足外更何求。',48,'全唐诗/poet.song.21000.json','["人生憂不足，足外更何求。", "吾生雖未足，亦也却無憂。", "天和將酒養，真樂用詩勾。", "不信年光會，催人早白頭。"]'),
('0afb2a45-b1a7-4fa6-bcce-0bcd5134bca6','逍遥吟  其三','邵雍','宋','宋诗','song-poetry','','[]','夜入安樂窩，晨興飲太和。',48,'全唐诗/poet.song.21000.json','["夜入安樂窩，晨興飲太和。", "窮神知道泰，養素得天多。", "日月任推盪，山川徒琢磨。", "欲求爲此者，到了是誰何。"]'),
('31c09ac3-19aa-429a-8d40-0a022394e451','逍遥吟  其四','邵雍','宋','宋诗','song-poetry','','[]','何事感人深，求之無處尋。',48,'全唐诗/poet.song.21000.json','["何事感人深，求之無處尋。", "兩儀長在手，萬化不關心。", "石裏時藏玉，砂中屢得金。", "分明難理會，須索入沉吟。"]'),
('9bebc6a1-d0a9-4b0f-8e1b-3ce22199fa83','偶得吟','邵雍','宋','宋诗','song-poetry','','[]','相去一毛間，千山復萬山。',48,'全唐诗/poet.song.21000.json','["相去一毛間，千山復萬山。", "雖能忘寢食，未肯去機關。", "不是責人備，柰何開口難。", "天心況非遠，既遠遂無還。"]'),
('446a99d9-9411-4266-be26-ef07c24c4ed0','每度過東鄰','邵雍','宋','宋诗','song-poetry','','[]','每度過東鄰，東鄰愈覺懃。',48,'全唐诗/poet.song.21000.json','["每度過東鄰，東鄰愈覺懃。", "既來長是愧，相見只如親。", "飲食皆隨好，兒童亦自忻。", "吾鄉有是樂，何必更求仁。"]'),
('711d8513-4439-40e0-8a02-a7c9ace4df83','每度過東街','邵雍','宋','宋诗','song-poetry','','[]','每度過東街，東街怨暮來。',48,'全唐诗/poet.song.21000.json','["每度過東街，東街怨暮來。", "只知閑說話，那覺太開懷。", "我有千般樂，人無一點猜。", "半醺歡喜酒，未晚未成迴。"]'),
('fa296c4c-bff0-4015-b263-9a78133403ff','君子與人交','邵雍','宋','宋诗','song-poetry','','[]','君子與人交，未始無驚惕。',48,'全唐诗/poet.song.21000.json','["君子與人交，未始無驚惕。", "小人與人交，示始無差忒。", "祗此真喜歡，也宜重愛惜。", "他年雲水踈，亦恐難尋覓。"]'),
('057151b6-46fd-4037-b89e-2fb1acc6e73c','唯天有二氣','邵雍','宋','宋诗','song-poetry','','[]','唯天有二氣，一陰而一陽。',48,'全唐诗/poet.song.21000.json','["唯天有二氣，一陰而一陽。", "陰毒産蛇蝎，陽和生鸞凰。", "安得蛇蝎死，不爲人之殃。", "安得鳳凰生，長爲國之祥。"]'),
('a5a5c514-8f93-463f-af96-2368b773eb2f','無客迴天意  其一','邵雍','宋','宋诗','song-poetry','','[]','無客迴天意，有人資盜糧。',48,'全唐诗/poet.song.21000.json','["無客迴天意，有人資盜糧。", "日中屢見斗，六月時降霜。", "有書不暇讀，有食不暇嘗。", "食況不盈缶，書空堆滿牀。"]'),
('76212425-eddb-429d-a942-9cf9bcbe60d8','無客迴天意  其二','邵雍','宋','宋诗','song-poetry','','[]','惡死而好生，古今之常情。',48,'全唐诗/poet.song.21000.json','["惡死而好生，古今之常情。", "人心可生事，天下自無兵。", "草木尚咸若，山川豈不寧。", "胡爲無擊壤，飲酒樂升平。"]'),
('873e3636-005b-4bb7-a90b-85e00c3c626d','放小魚','邵雍','宋','宋诗','song-poetry','','[]','纖鱗不足留，此失一生休。',48,'全唐诗/poet.song.21000.json','["纖鱗不足留，此失一生休。", "放爾江湖去，寬渠鼎鑊憂。", "更宜深避網，慎勿誤吞鈎。", "天下多庖者，無令落庶羞。"]'),
('155cda49-d61f-408c-93bc-b4cbd71170dc','依韻和田大卿見贈','邵雍','宋','宋诗','song-poetry','','[]','日日步家園，清風不著錢。',48,'全唐诗/poet.song.21000.json','["日日步家園，清風不著錢。", "城中得野景，竹下弄飛泉。", "自願無嗟若，何妨養浩然。", "却慙天下士，語道未忘筌。"]'),
('d1ddb5b2-107a-44d1-82dc-d62c76fb693d','乞笛竹','邵雍','宋','宋诗','song-poetry','','[]','洛人好種花，唯我好種竹。',48,'全唐诗/poet.song.21000.json','["洛人好種花，唯我好種竹。", "所好雖不同，其心亦自足。", "花止十日紅，竹能經歲綠。", "俱霑雨露恩，獨無霜雪辱。"]'),
('5055337f-9582-4a65-9539-6837d35419a6','依韻和王不疑少卿招飲','邵雍','宋','宋诗','song-poetry','','[]','經難憶浮丘，吾鄉足勝遊。',48,'全唐诗/poet.song.21000.json','["經難憶浮丘，吾鄉足勝遊。", "風前驚白髮，雨後喜新秋。", "仕官情雖薄，登臨興未休。", "人間浪憂事，都不到心頭。"]'),
('fa775cd5-1cfe-4f40-bb51-8ab087dcda05','再和王不疑少卿見贈','邵雍','宋','宋诗','song-poetry','','[]','乍凉天氣好，何處不堪遊。',48,'全唐诗/poet.song.21000.json','["乍凉天氣好，何處不堪遊。", "鴻鴈來賓日，鷹鸇得志秋。", "忘形終夕樂，失脚一生休。", "多少江湖上，舟舡未到頭。"]'),
('e1aa50b6-9f5a-47ce-ae02-9b8b4c39d851','依韻和三王少卿同過弊廬','邵雍','宋','宋诗','song-poetry','','[]','洛中詩有社，馬上句如神。',48,'全唐诗/poet.song.21000.json','["洛中詩有社，馬上句如神。", "白首交情重，黄花節物新。", "見過心可荷，知愧道非淳。", "寂寞西風裏，身閑半古人。"]'),
('1ab3817c-1aca-4e96-93f0-508395e35a05','代書寄南陽太守呂獻可諫議','邵雍','宋','宋诗','song-poetry','','[]','一別星霜二紀中，升沉音問不相通。',64,'全唐诗/poet.song.21000.json','["一別星霜二紀中，升沉音問不相通。", "林間談笑須歸我，天下安危宜繫公。", "萬乘几前嘗蹇諤，百花洲上略從容。", "不知月白風清夜，能憶伊川舊釣翁。"]'),
('1b9bd2d7-aae3-410b-af42-8c07f7c9657e','寄吳傳正寺丞','邵雍','宋','宋诗','song-poetry','','[]','天津風月一何孤，似我經秋相憶無。',32,'全唐诗/poet.song.21000.json','["天津風月一何孤，似我經秋相憶無。", "每仗晴波寄聲去，不知曾得到東都。"]'),
('8c8be6e9-0bf5-4f39-b52c-71fd75c8b401','寄前洛陽簿陸剛叔秘校','邵雍','宋','宋诗','song-poetry','','[]','洛陽官滿歸吳會，男子雄圖志未伸。',32,'全唐诗/poet.song.21000.json','["洛陽官滿歸吳會，男子雄圖志未伸。", "若到江山最佳處，舉盃無惜望天津。"]'),
('1d86bb42-7b49-436e-8689-6e60acbdf727','依韻和淮南憲張司封','邵雍','宋','宋诗','song-poetry','','[]','庭梧葉半黄，籬菊初受霜。',48,'全唐诗/poet.song.21000.json','["庭梧葉半黄，籬菊初受霜。", "向晚意不快，把酒西南望。", "望君不見君，但見鴻南翔。", "正欲思寄書，自成書數行。"]'),
('99120e22-3064-41d0-a03b-02a0055cce07','重陽前一日作','邵雍','宋','宋诗','song-poetry','','[]','近來多病不堪言，長欲醺醺带醉眠。',64,'全唐诗/poet.song.21000.json','["近來多病不堪言，長欲醺醺带醉眠。", "新酒乍逢重九日，好花初接小春天。", "自知命薄臨頭上，不願事多來眼前。", "唯有天津橫落照，水聲仍是舊潺湲。"]'),
('de471410-dff5-4ee4-99a1-21d7fedaa490','重九日登石閣三首  其一','邵雍','宋','宋诗','song-poetry','','[]','人情見了多，世態諳來久。',48,'全唐诗/poet.song.21000.json','["人情見了多，世態諳來久。", "事過憂噬臍，物傷防掣肘。", "水濁更澄濾，衣塵須抖擻。", "必欲論主衡，何人爲好手。"]'),
('0c15ce0a-d231-417d-a3fb-7fa6a94e173b','重九日登石閣三首  其二','邵雍','宋','宋诗','song-poetry','','[]','事出一時間，時過事莫還。',48,'全唐诗/poet.song.21000.json','["事出一時間，時過事莫還。", "當時深可愛，過後不堪看。", "夏去休言暑，冬來始講寒。", "人能知此理，憂患自難干。"]'),
('203d0bdc-db3c-4d56-b489-0ccde0a263b4','重九日登石閣三首  其三','邵雍','宋','宋诗','song-poetry','','[]','今歲重陽日，凭欄氣候遲。',48,'全唐诗/poet.song.21000.json','["今歲重陽日，凭欄氣候遲。", "雲煙雖已淡，林木未全衰。", "天地開懷處，山川快眼時。", "欄干空倚遍，此意有誰知。"]'),
('9a4c6078-d434-496f-b74c-eac552cddaaf','依韻答友人','邵雍','宋','宋诗','song-poetry','','[]','百萬貔貅動塞塵，朝廷委寄不輕人。',64,'全唐诗/poet.song.21000.json','["百萬貔貅動塞塵，朝廷委寄不輕人。", "胡兒生事雖然淺，國士盡忠須是純。", "隴上悲歌應憤惋，林間酣飲但酸辛。", "欲陳一句好言語，只恐相知未甚真。"]'),
('86605a1c-fe70-44e9-98f0-03a4d80b9774','偶見吟  其一','邵雍','宋','宋诗','song-poetry','','[]','富貴多傲人，人情有時移。',48,'全唐诗/poet.song.21000.json','["富貴多傲人，人情有時移。", "道德不傲人，人情久益歸。", "道德有常理，富貴無定期。", "蒿萊霜至萎，松柏雪更滋。"]'),
('363fc6b6-528c-4016-9c01-a14e072f2a8e','偶見吟  其二','邵雍','宋','宋诗','song-poetry','','[]','世上多附炎，炎歇人自去。',48,'全唐诗/poet.song.21000.json','["世上多附炎，炎歇人自去。", "君子善處約，約久情自固。", "炎歇勢不迴，情固人不去。", "路人或如親，親人却如路。"]'),
('fb6c46ca-a4f8-47a7-aa01-52b7d665ec3d','偶見吟  其三','邵雍','宋','宋诗','song-poetry','','[]','心跡貴相親，相親善惡分。',48,'全唐诗/poet.song.21000.json','["心跡貴相親，相親善惡分。", "世間須有物，天下豈無人。", "既見薰蕕臭，當思玉石焚。", "如何得時態，長似洛陽春。"]'),
('3541fdb3-66fd-4f5e-8f63-1c357b3cfa4f','無題吟','邵雍','宋','宋诗','song-poetry','','[]','昔日不鍊物，嘗爲物所誤。',48,'全唐诗/poet.song.21000.json','["昔日不鍊物，嘗爲物所誤。", "今日不鍊人，又爲人所怒。", "物誤亦可辨，人怒難往訴。", "我對人稱過，人亦爲我恕。"]'),
('b45385fc-f6cc-46c7-8a8a-2c859684cda7','無酒吟','邵雍','宋','宋诗','song-poetry','','[]','自從新法行，嘗苦樽無酒。',48,'全唐诗/poet.song.21000.json','["自從新法行，嘗苦樽無酒。", "每有賓朋至，盡日閑相守。", "必欲丐于人，交親自無有。", "必欲典衣買，焉能得長久。"]'),
('f316b86f-797a-400e-8abe-9bde2f6d217e','讀陶淵明歸去來','邵雍','宋','宋诗','song-poetry','','[]','歸去來兮任我真，事雖成往意能新。',64,'全唐诗/poet.song.21000.json','["歸去來兮任我真，事雖成往意能新。", "何嘗不遇如斯世，其那難逢似此人。", "近暮特嗟時翳翳，向榮還喜木欣欣。", "可憐六百餘年外，復有閑人繼後塵。"]'),
('60d31af4-14df-45b8-a1bb-b3272fa3c69b','訪南園張氏昆仲因而留宿','邵雍','宋','宋诗','song-poetry','','[]','中秋天氣隨宜好，來訪南園會隠家。',32,'全唐诗/poet.song.21000.json','["中秋天氣隨宜好，來訪南園會隠家。", "貪飲不知歸去晚，水精宮裏宿煙霞。"]'),
('a35e2a3e-e25d-41e4-afcf-7d09cbe579af','和王安之少卿同遊龍門  其一','邵雍','宋','宋诗','song-poetry','','[]','生平有癖好尋幽，一歲龍山四五遊。',32,'全唐诗/poet.song.21000.json','["生平有癖好尋幽，一歲龍山四五遊。", "或往或還都不計，蓋無榮利可稽留。"]'),
('c5094b4e-643d-433f-a8c4-22d63817e554','和王安之少卿同遊龍門  其二','邵雍','宋','宋诗','song-poetry','','[]','數朝從款看伊流，夜卜香山宿石樓。',32,'全唐诗/poet.song.21000.json','["數朝從款看伊流，夜卜香山宿石樓。", "會有凉風開遠意，更和煙雨弄高秋。"]'),
('bf2b8ab5-26a8-4a66-974e-c4c876808b6e','歸城中再用前韻  其一','邵雍','宋','宋诗','song-poetry','','[]','乘興龍山訪盡幽，恰如人在畫圖遊。',32,'全唐诗/poet.song.21000.json','["乘興龍山訪盡幽，恰如人在畫圖遊。", "恨無美酒酬佳景，正欲留時不得留。"]'),
('6ad627d3-d107-4593-a4a9-90018df02ed8','歸城中再用前韻  其二','邵雍','宋','宋诗','song-poetry','','[]','初秋微雨造輕寒，倚遍東岑閣上欄。',32,'全唐诗/poet.song.21000.json','["初秋微雨造輕寒，倚遍東岑閣上欄。", "不謂是時煙靄裏，松齋人作畫圖看。"]'),
('8d2a5889-272f-4c20-aa5b-149de24a07d0','和人留題張相公庵','邵雍','宋','宋诗','song-poetry','','[]','做了三公更引年，人間福德合居先。',32,'全唐诗/poet.song.21000.json','["做了三公更引年，人間福德合居先。", "結茅未盡忘君處，正在嵩高萬歲前。"]'),
('2a2f6572-6af2-4957-8997-f406bd6c75d5','代書寄程正叔','邵雍','宋','宋诗','song-poetry','','[]','嚴親出守劍門西，色養歡深世表儀。',64,'全唐诗/poet.song.21000.json','["嚴親出守劍門西，色養歡深世表儀。", "唐相規模今歷歷，蜀民遨樂舊熙熙。", "海棠洲畔停橈處，金鴈橋邊立馬時。", "料得預憂天下計，不忘君者更爲誰。"]'),
('c248ce60-0793-4358-9bb7-0f1cf586f025','歲暮自貽','邵雍','宋','宋诗','song-poetry','','[]','當年志意欲橫秋，今日思之重可羞。',160,'全唐诗/poet.song.21000.json','["當年志意欲橫秋，今日思之重可羞。", "事到强圖皆屑屑，道非真得盡悠悠。", "靜中照物情難隠，老後看書味轉優。", "談麈從容對賓客，薦章重疊誤公侯。", "已蒙賢傑開青眼，不顧妻孥怨白頭。", "谷口鄭真焉敢望，壽陵餘子若爲謀。", "鼎間龍虎忘看守，棋上山河廢講求。", "一枕晴窗睡初覺，數聲幽鳥語方休。", "林泉好處將詩買，風月佳時用酒酬。", "三百六旬如去箭，肯教襟抱落閑愁。"]'),
('2456579e-8852-40b5-a659-0c7a44144958','歡喜吟','邵雍','宋','宋诗','song-poetry','','[]','行年六十一，筋骸未甚老。',48,'全唐诗/poet.song.21000.json','["行年六十一，筋骸未甚老。", "已爲兩世人，便化豈爲夭。", "況且粗康强，又復無憂撓。", "如何不喜歡，佳辰自不少。"]'),
('6315799e-affa-45fd-8eae-04b6b27fcbda','寄李景真太博','邵雍','宋','宋诗','song-poetry','','[]','花前靜榻閑眠處，竹下明窗獨坐時。',32,'全唐诗/poet.song.21000.json','["花前靜榻閑眠處，竹下明窗獨坐時。", "著甚語言名宇泰，林間自有翠禽知。"]'),
('bdefb6c8-740f-4366-b86a-abed7ee5ea94','感事吟','邵雍','宋','宋诗','song-poetry','','[]','蛇頭蝎尾不相同，毒殺人多始是功。',32,'全唐诗/poet.song.21000.json','["蛇頭蝎尾不相同，毒殺人多始是功。", "風月四時無限好，莫將閑事撓胸中。"]'),
('4ba817a1-ccee-46b8-b41f-49527fd6cdf8','寄亳州秦伯鎮兵部  其一','邵雍','宋','宋诗','song-poetry','','[]','三川地正得中陽，氣入奇葩亦自王。',32,'全唐诗/poet.song.21000.json','["三川地正得中陽，氣入奇葩亦自王。", "善識好花人不遠，好花無恡十分芳。"]'),
('fcd5e64c-7f11-4688-8c2f-4f05e41a2ba0','寄亳州秦伯鎮兵部  其二','邵雍','宋','宋诗','song-poetry','','[]','人事紛紛積有年，何煩顰蹙向花前。',32,'全唐诗/poet.song.21000.json','["人事紛紛積有年，何煩顰蹙向花前。", "萬般計較頭須白，饒了胸中不坦然。"]'),
('7da8c710-e224-47d4-aca0-23b15fd474fe','寄亳州秦伯鎮兵部  其三','邵雍','宋','宋诗','song-poetry','','[]','無限有情風月間，好將醇酒發酡顔。',32,'全唐诗/poet.song.21000.json','["無限有情風月間，好將醇酒發酡顔。", "柰何人自生疑阻，利害嫌輕更設關。"]'),
('4908bcd3-8d31-42f0-afe1-84f3f27bd78d','寄亳州秦伯鎮兵部  其四','邵雍','宋','宋诗','song-poetry','','[]','雖貧無害日高眠，人不堪憂我自便。',32,'全唐诗/poet.song.21000.json','["雖貧無害日高眠，人不堪憂我自便。", "鍛鍊物情時得意，新詩還有百來篇。"]'),
('a40bec25-fe58-42f9-a6ec-940d003e7cf6','寄亳州秦伯鎮兵部  其五','邵雍','宋','宋诗','song-poetry','','[]','天心復處是無心，心到無時無處尋。',32,'全唐诗/poet.song.21000.json','["天心復處是無心，心到無時無處尋。", "若謂無心便無事，水中何故不生金。"]'),
('0c059cc2-9d54-4de2-9ad8-c0e113987cbe','寄亳州秦伯鎮兵部  其六','邵雍','宋','宋诗','song-poetry','','[]','酒涵花影滿巵紅，瀉入天和胸臆中。',32,'全唐诗/poet.song.21000.json','["酒涵花影滿巵紅，瀉入天和胸臆中。", "最愛一般情味好，半醺時與太初同。"]'),
('f143ea4d-7ed1-4f90-9214-0f1ed6300592','別寄一首','邵雍','宋','宋诗','song-poetry','','[]','許大秦皇定九州，九州纔定却歸劉。',32,'全唐诗/poet.song.21000.json','["許大秦皇定九州，九州纔定却歸劉。", "佗人莫謾誇精彩，徒自區區撰白頭。"]'),
('499382f1-9dfb-446c-aa8d-53a5437a5608','思故人','邵雍','宋','宋诗','song-poetry','','[]','芳酒一樽雖甚滿，故人千里柰思何。',32,'全唐诗/poet.song.21000.json','["芳酒一樽雖甚滿，故人千里柰思何。", "柳挼池閣條偏細，花近簷楹香更多。"]'),
('bc43d2d4-2ddb-4e6f-8f86-4b69e846d616','和王平甫教授賞花處惠茶韻','邵雍','宋','宋诗','song-poetry','','[]','太學先生善識花，得花精處却因茶。',32,'全唐诗/poet.song.21000.json','["太學先生善識花，得花精處却因茶。", "萬紅香裏烹餘後，分送天津第一家。"]'),
('4dd5be20-6216-43b4-9947-844ac4938528','南園賞花  其一','邵雍','宋','宋诗','song-poetry','','[]','三月初三花正開，閑同親舊上春臺。',32,'全唐诗/poet.song.21000.json','["三月初三花正開，閑同親舊上春臺。", "尋常不醉此時醉，更醉猶能舉大盃。"]'),
('4d9a82c9-c95b-4fae-afcf-7134082aec1d','南園賞花  其二','邵雍','宋','宋诗','song-poetry','','[]','花前把酒花前醉，醉把花枝仍自歌。',32,'全唐诗/poet.song.21000.json','["花前把酒花前醉，醉把花枝仍自歌。", "花見白頭入莫笑，白頭人見好花多。"]'),
('29f63066-1f41-408e-a42a-06813d0f7f8c','獨賞牡丹','邵雍','宋','宋诗','song-poetry','','[]','賞花全易識花難，善識花人獨倚欄。',64,'全唐诗/poet.song.21000.json','["賞花全易識花難，善識花人獨倚欄。", "雨露功中觀造化，神仙品裏定容顔。", "尋常止可言時尚，奇絕方名出世間。", "賦分也須知不淺，筭來消得一生閑。"]'),
('7fb1eb82-7802-4f70-8efe-203694d096e3','問春  其一','邵雍','宋','宋诗','song-poetry','','[]','三月春歸留不住，春歸春意難分付。',32,'全唐诗/poet.song.21000.json','["三月春歸留不住，春歸春意難分付。", "凡言歸者必歸家，爲問春家在何處。"]'),
('35b845d8-978b-4b46-a1d6-7aee74e231a9','問春  其二','邵雍','宋','宋诗','song-poetry','','[]','春歸必竟歸何處，無限春冤都未訴。',32,'全唐诗/poet.song.21000.json','["春歸必竟歸何處，無限春冤都未訴。", "欲托流鸎問所因，子規又叫不如去。"]'),
('70566f77-acb2-4a21-bcc4-ad3b51e9f087','問春  其三','邵雍','宋','宋诗','song-poetry','','[]','春來愁去只因花，春去愁來翻殢酒。',32,'全唐诗/poet.song.21000.json','["春來愁去只因花，春去愁來翻殢酒。", "長恨愁多酒力微，爲春成病花知否。"]'),
('1c80f038-2d0e-4766-a8d3-41c80c7774d4','安樂窩中自貽','邵雍','宋','宋诗','song-poetry','','[]','物如善得終爲美，事到巧圖安有公。',64,'全唐诗/poet.song.21000.json','["物如善得終爲美，事到巧圖安有公。", "不作風波於世上，自無冰炭到胸中。", "災殃秋葉霜前墜，富貴春華雨後紅。", "造化分明人莫會，花榮消得幾何功。"]'),
('2f44134d-8359-4f95-b98e-46eb8f5bac5b','花前勸酒','邵雍','宋','宋诗','song-poetry','','[]','春在對花飲，春歸花亦殘。',48,'全唐诗/poet.song.21000.json','["春在對花飲，春歸花亦殘。", "對花不飲酒，歡意遂闌珊。", "酒向花前飲，花宜醉後看。", "花前不飲酒，終負一年歡。"]'),
('9ea7ff3e-7028-45d8-b64c-172353545d14','書皇極經世後','邵雍','宋','宋诗','song-poetry','','[]','樸散人道立，法始乎羲皇。',288,'全唐诗/poet.song.21000.json','["樸散人道立，法始乎羲皇。", "歲月易遷革，書傳難考詳。", "二帝啟禪讓，三王正紀綱。", "五伯仗形勝，七國爭强梁。", "兩漢驤龍鳳，三分走虎狼。", "西晉擅風流，羣凶來北荒。", "東晉事清芬，傳聲宋齊梁。", "逮陳不足算，江表成悲傷。", "後魏乘晉弊，掃除幾小康。", "遷洛未甚久，旋聞東西將。", "北齊舉爝火，後周馳星光。", "隨能一統之，駕福于巨唐。", "五代如傳舍，天下徒擾攘。", "不有真主出，何由奠中央。", "一萬里區字，四千年興亡。", "五百主肇位，七十國開疆。", "或混同六合，或控制一方。", "或創業先後，或垂祚短長。", "或奮于將墜，或奪于已昌。", "或火興无妄，或福會不祥。", "或患生藩屏，或難起蕭牆。", "或病由唇齒，或疾亟膏肓。", "談笑萌事端，酒食開戰場。", "情慾之一發，利害之相戕。"]'),
('deedbf1c-007f-42b1-b1dc-76274508e755','履道會飲','邵雍','宋','宋诗','song-poetry','','[]','衆人之所樂，所樂唯囂塵。',240,'全唐诗/poet.song.21000.json','["衆人之所樂，所樂唯囂塵。", "吾友之所樂，所樂唯清芬。", "清芬無鼓吹，直與太古鄰。", "太古者靡佗，和氣常絪紜。", "里閈舊情好，有才復有文。", "過從一日樂，十月生陽春。", "洛陽古神州，周公嘗縷陳。", "四時寒暑正，四方道里均。", "代不乏英俊，號爲多縉紳。", "至于花與木，天下莫敢倫。", "而逢此之景，而當此之辰。", "而能開口笑，而世有幾人。", "清衷貫金石，劇變驚鬼神。", "天地爲一指，富貴如浮雲。", "明時緩康濟，白晝閑經綸。", "莫如陪歡伯，又復對此君。", "商於六百里，黄金四萬斤。", "不能買茲樂，自餘惡足論。", "接䍦倒戴時，蟾蜍生海垠。", "小車倒載時，山翁歸天津。"]'),
('54ce2ea5-3a52-4054-b393-c0aa7a30a69d','思鄭州陳知默因感其化去不得一識面','邵雍','宋','宋诗','song-poetry','','[]','美物須絕代，異人須不世。',48,'全唐诗/poet.song.21000.json','["美物須絕代，異人須不世。", "造化生得成，諒亦非容易。", "曠世耳可聞，同時目能視。", "陳子同時人，柰何聞諸耳。"]'),
('e4e43e0d-26bc-4eb5-bd21-3f2b534b6353','謝城南張氏四弟兄冒雪載餚酒見過','邵雍','宋','宋诗','song-poetry','','[]','久旱幾逾冬，川守祈未得。',48,'全唐诗/poet.song.21000.json','["久旱幾逾冬，川守祈未得。", "鴈行聊鑣來，佳雪遽盈尺。", "酒面生紅光，客心喜何極。", "上夜離天津，天津陡岑寂。"]'),
('f40cdb7f-56bc-44e1-93e9-6563199f27da','大寒吟','邵雍','宋','宋诗','song-poetry','','[]','舊雪未及消，新雪又擁戶。',48,'全唐诗/poet.song.21000.json','["舊雪未及消，新雪又擁戶。", "階前凍銀牀，簷頭冰鐘乳。", "清日無光輝，烈風正號怒。", "人口各有舌，言語不能吐。"]'),
('57bcc51b-be9c-459d-9ccb-1b1f41f18472','和李審言龍圖大雪','邵雍','宋','宋诗','song-poetry','','[]','萬樹瓊花一夜開，都和天地色皚皚。',64,'全唐诗/poet.song.21000.json','["萬樹瓊花一夜開，都和天地色皚皚。", "素娥腰細舞將徹，白玉堂深曲又催。", "甕牖書生方挾策，沙場甲士正啣枚。", "幽人骨瘦欲清損，頼有時時酒一盃。"]'),
('d1cdf05d-dd9b-4b40-917f-ddd93f14a0d5','小車行','邵雍','宋','宋诗','song-poetry','','[]','喜醉豈無千日酒，惜春還有四時花。',32,'全唐诗/poet.song.21000.json','["喜醉豈無千日酒，惜春還有四時花。", "小車行處人歡喜，滿洛城中都似家。"]'),
('cf1d3418-5c2e-4adb-a06c-e688fa57c3b4','依韻和浙憲任度支','邵雍','宋','宋诗','song-poetry','','[]','官路尋真已得真，可堪輕負洛城春。',32,'全唐诗/poet.song.21000.json','["官路尋真已得真，可堪輕負洛城春。", "江湖想望三千里，休使鄉朋想望頻。"]'),
('8f8f6a0d-2acc-496f-b041-8ea18bed1b9e','和宋都官乞梅','邵雍','宋','宋诗','song-poetry','','[]','小園雖有四般梅，不似江南迎臘開。',32,'全唐诗/poet.song.21000.json','["小園雖有四般梅，不似江南迎臘開。", "長恨東君少風韻，先時未肯放春來。"]'),
('3664dfc4-d3e5-4c79-8d30-c63e18c70a5c','東軒黄紅二梅正開坐上書呈友人','邵雍','宋','宋诗','song-poetry','','[]','一年一度見雙梅，能見雙梅幾度開。',32,'全唐诗/poet.song.21000.json','["一年一度見雙梅，能見雙梅幾度開。", "入壽百年今六十，休論閑事且啣盃。"]'),
('b6533202-3c9b-4f20-bb56-d2df9fbad307','和任比部憶梅','邵雍','宋','宋诗','song-poetry','','[]','痛憶梅開易得殘，既殘憔悴不堪看。',32,'全唐诗/poet.song.21000.json','["痛憶梅開易得殘，既殘憔悴不堪看。", "年年長被清香誤，爭似閑栽竹數竿。"]'),
('bae21f20-5e48-48c9-8689-e712d8306204','垂柳','邵雍','宋','宋诗','song-poetry','','[]','門前垂柳正依依，更被東風來往吹。',32,'全唐诗/poet.song.21000.json','["門前垂柳正依依，更被東風來往吹。", "忘了自家今已老，却疑身是少年時。"]'),
('b3cebe8b-f0ec-4e8b-aa36-ea8e284eab8d','至靈吟','邵雍','宋','宋诗','song-poetry','','[]','至靈之謂人，至貴之謂君。',24,'全唐诗/poet.song.21000.json','["至靈之謂人，至貴之謂君。", "明則有日月，幽則有鬼神。"]'),
('c3ee056d-aae1-4c31-9fa9-6c1725cf3647','人鬼吟','邵雍','宋','宋诗','song-poetry','','[]','既不能事人，又焉能事鬼。',24,'全唐诗/poet.song.21000.json','["既不能事人，又焉能事鬼。", "人鬼雖不同，其理何嘗異。"]'),
('6eba4ca7-f5e7-480c-876e-71744daafba5','生平與人交','邵雍','宋','宋诗','song-poetry','','[]','生平與人交，未始有甘壞。',24,'全唐诗/poet.song.21000.json','["生平與人交，未始有甘壞。", "己亦無負人，人亦無我害。"]'),
('a1e2dd99-d114-42c9-a620-849ab5b120a0','知識吟','邵雍','宋','宋诗','song-poetry','','[]','目見之謂識，耳聞之謂知。',24,'全唐诗/poet.song.21000.json','["目見之謂識，耳聞之謂知。", "柰何知與識，天下亦常稀。"]'),
('b92f420e-ebb6-44ef-8151-18c5dc96658d','偶書吟','邵雍','宋','宋诗','song-poetry','','[]','風林無靜柯，風池無靜波。',24,'全唐诗/poet.song.21000.json','["風林無靜柯，風池無靜波。", "林池既不靜，禽魚當如何。"]'),
('ae2092a0-9aba-44d8-a9f3-d4d224955c33','思患吟','邵雍','宋','宋诗','song-poetry','','[]','僕奴凌主人，夷狄犯中國。',24,'全唐诗/poet.song.21000.json','["僕奴凌主人，夷狄犯中國。", "自古知不平，無由能絕得。"]'),
('9210fa90-ae44-400a-b577-95e9b6724c33','寄三城王宣徽二首  其一','邵雍','宋','宋诗','song-poetry','','[]','林下居雖陋，花前飲却頻。',24,'全唐诗/poet.song.21000.json','["林下居雖陋，花前飲却頻。", "世間無事樂，都恐屬閑人。"]'),
('879fd106-56f7-4436-8390-74fbff1731f8','寄三城王宣徽二首  其二','邵雍','宋','宋诗','song-poetry','','[]','路上塵方坌，壺中花正開。',24,'全唐诗/poet.song.21000.json','["路上塵方坌，壺中花正開。", "何須頭盡白，然後賦歸來。"]'),
('e3ef8c11-5237-45fc-9b8b-07cffc9972a9','仁聖吟','邵雍','宋','宋诗','song-poetry','','[]','盡道之謂聖，如天之謂仁。',24,'全唐诗/poet.song.21000.json','["盡道之謂聖，如天之謂仁。", "如何仁與聖，天下莫敢倫。"]'),
('fb2f9bc6-97fe-49e2-af85-aa3b63c24e60','和邢和叔學士見別','邵雍','宋','宋诗','song-poetry','','[]','世路如何若大東，相逢不待語言通。',64,'全唐诗/poet.song.21000.json','["世路如何若大東，相逢不待語言通。", "觀君自比諸葛亮，顧我殊非黄石公。", "講道污隆無巨細，語時興替有初終。", "出人才業尤須惜，慎勿輕爲西晉風。"]'),
('b47f4747-99d8-4557-b25d-37066dd2a41a','擊壤吟','邵雍','宋','宋诗','song-poetry','','[]','人言別有洞中仙，洞裏神仙恐妄傳。',64,'全唐诗/poet.song.21000.json','["人言別有洞中仙，洞裏神仙恐妄傳。", "若俟靈丹須九轉，必求朱頂更千年。", "長年國裏花千樹，安樂窩中樂滿懸。", "有樂有花仍有酒，却疑身是洞中仙。"]'),
('d0cb3630-b230-4ad4-9c43-0068bc217de5','春去吟','邵雍','宋','宋诗','song-poetry','','[]','好物足艱難，都來數日間。',48,'全唐诗/poet.song.21000.json','["好物足艱難，都來數日間。", "既爲風攪撓，又被雨摧殘。", "富貴醉初醒，神仙夢乍還。", "遊人不知止，依舊倚朱欄。"]'),
('7c0c7eeb-ff21-448a-912b-111ab08f9466','南園花竹','邵雍','宋','宋诗','song-poetry','','[]','花行竹逕緊相挨，每日須行四五迴。',64,'全唐诗/poet.song.21000.json','["花行竹逕緊相挨，每日須行四五迴。", "因把花行侵竹種，且圖竹逕對花開。", "花香遠遠隨衣袂，竹影重重上酒盃。", "誰道山翁少溫潤，這般紅翠却長偎。"]'),
('a19fc2d5-206f-42d5-a646-a3acb7d3311f','再答王宣徽  其一','邵雍','宋','宋诗','song-poetry','','[]','自有吾儒樂，人多不肯循。',24,'全唐诗/poet.song.21000.json','["自有吾儒樂，人多不肯循。", "以禪爲樂事，又起一重塵。"]'),
('f379f2a9-0119-4118-ba99-c173876536d5','再答王宣徽  其二','邵雍','宋','宋诗','song-poetry','','[]','大達誠無礙，人人自有家。',24,'全唐诗/poet.song.21000.json','["大達誠無礙，人人自有家。", "假花猶入念，何者謂真花。"]'),
('1790f385-00f0-4a3a-aaf0-8c5b1e4163f3','蒼蒼吟寄答曹州李審言龍圖','邵雍','宋','宋诗','song-poetry','','[]','一般顔色正蒼蒼，今古人曾望斷腸。',96,'全唐诗/poet.song.21000.json','["一般顔色正蒼蒼，今古人曾望斷腸。", "日往月來無少異，陽舒陰慘不相妨。", "迅雷震後山川裂，甘露零時草木香。", "幽暗巖崖生鬼魅，清平郊野見鸞凰。", "千花爛爲三春雨，萬木凋因一夜霜。", "此意分明難理會，直須賢者入消詳。"]'),
('abdf0fdb-b21e-4c41-b200-878295e7afc5','林下五吟  其一','邵雍','宋','宋诗','song-poetry','','[]','真工造化豈容私，拙者爲謀亦甚微。',64,'全唐诗/poet.song.21000.json','["真工造化豈容私，拙者爲謀亦甚微。", "安樂窩深初起後，太和湯釅半醺時。", "長年國裏籃舁往，永熟鄉中杖策歸。", "身似升平無一事，數莖髭白任風吹。"]'),
('6570e020-1e96-41d3-9de3-104ae38c19d5','林下五吟  其二','邵雍','宋','宋诗','song-poetry','','[]','老年軀體素溫存，安樂窩中別有春。',64,'全唐诗/poet.song.21000.json','["老年軀體素溫存，安樂窩中別有春。", "萬事去心閑偃仰，四支由我任舒伸。", "庭花盛處凉鋪簟，簷雪飛時軟布裀。", "誰道山翁拙於用，也能康濟自家身。"]'),
('2b3731f7-a5bb-4da5-8c81-7c793fa0f8e0','林下五吟  其三','邵雍','宋','宋诗','song-poetry','','[]','有物輕醇號太和，半醺中最得春多。',64,'全唐诗/poet.song.21000.json','["有物輕醇號太和，半醺中最得春多。", "靈丹換骨還如否，白日升天似得麽。", "儘快意時仍起舞，到忘言處只謳歌。", "賓朋莫怪無拘檢，真樂攻心不柰何。"]'),
('e74b6916-ba32-4401-8f44-f03d3dfd77fc','林下五吟  其四','邵雍','宋','宋诗','song-poetry','','[]','相招相勸飲流霞，鬢亂秋霜髮亂華。',64,'全唐诗/poet.song.21000.json','["相招相勸飲流霞，鬢亂秋霜髮亂華。", "所記莫非前甲子，凡經多是老官家。", "共誇今日重孫過，更說當時舊事呀。", "言語丁寧有情味，後生無笑太周遮。"]'),
('4ffea6c0-2d1c-41e5-98b9-51246c1f77fd','林下五吟  其五','邵雍','宋','宋诗','song-poetry','','[]','生來未始事田疇，無歲無時長有秋。',64,'全唐诗/poet.song.21000.json','["生來未始事田疇，無歲無時長有秋。", "隨分盃盤俱是樂，等閑池館便成遊。", "風花雪月千金子，水竹雲山萬戶侯。", "欲俟河清人壽幾，兩眉能著幾多愁。"]'),
('44c5fdfb-c9e8-4e37-86d7-4cf16c159052','安樂窩中自訟吟','邵雍','宋','宋诗','song-poetry','','[]','不向紅塵浪著鞭，唯求寡過尚無緣。',64,'全唐诗/poet.song.21000.json','["不向紅塵浪著鞭，唯求寡過尚無緣。", "虛更蘧瑗知非日，謬歷宣尼讀易年。", "髮到白時難受彩，心歸通後更何言。", "至陽之氣方爲玉，猶恐鑽磨未甚堅。"]'),
('71cb6e04-a04e-43c5-99de-a9c8e662583e','和君實端明花庵二首  其一','邵雍','宋','宋诗','song-poetry','','[]','不用丹楹刻桷爲，重重自有翠陰垂。',32,'全唐诗/poet.song.21000.json','["不用丹楹刻桷爲，重重自有翠陰垂。", "後人繼取天真意，種蒔增華非所宜。"]'),
('94b54c3b-9bc2-4a51-b351-652d8d47382e','和君實端明花庵二首  其二','邵雍','宋','宋诗','song-poetry','','[]','庵後庵前盡植花，花開番次四時好。',32,'全唐诗/poet.song.21000.json','["庵後庵前盡植花，花開番次四時好。", "主人事簡常燕休，不信歲華能撰老。"]'),
('a5d624a9-5744-4703-8e14-fbccc01043b4','六十二吟','邵雍','宋','宋诗','song-poetry','','[]','行年六十二康强，況復身居永熟鄉。',64,'全唐诗/poet.song.21000.json','["行年六十二康强，況復身居永熟鄉。", "美景良辰非易得，淺斟低唱又何妨。", "無涯歲月難拘管，有限形骸莫毀傷。", "多少英豪弄才智，大曾經過惡思量。"]'),
('e3f64115-520a-4325-9154-728666a7a708','林下局事吟','邵雍','宋','宋诗','song-poetry','','[]','閑人亦也有官守，官守一身四事有。',64,'全唐诗/poet.song.21000.json','["閑人亦也有官守，官守一身四事有。", "一事承曉露看花，一事迎晚風觀柳。", "一事對皓月吟詩，一事留佳賓飲酒。", "從事于茲二十年，欲求同列誰能否。"]'),
('a5b132c1-cc5c-4432-a314-d394c343654a','依韻和吳傳正寺丞見寄','邵雍','宋','宋诗','song-poetry','','[]','五十年來讀舊書，世間應笑我迂疏。',64,'全唐诗/poet.song.21000.json','["五十年來讀舊書，世間應笑我迂疏。", "因思偊女忘今古，遂悟輪人致疾徐。", "道業未醇誠可病，生涯雖薄敢言虛。", "時和受賜已多矣，安有胸中不晏如。"]'),
('a2857ab8-c4fb-4f2e-8165-6ea168fdf7c5','延福坊李太博乞園池詩','邵雍','宋','宋诗','song-poetry','','[]','宣威十九次高牙，奕葉功臣舊將家。',64,'全唐诗/poet.song.21000.json','["宣威十九次高牙，奕葉功臣舊將家。", "清世辭榮歸里第，白頭行樂過年華。", "盃盈香醑浮春水，曲度新聲出靚花。", "如此園池如此壽，兒孫滿眼慶無涯。"]'),
('c707204a-da28-42fe-8818-14fc58044386','金玉吟','邵雍','宋','宋诗','song-poetry','','[]','良金美玉信難偕，好物其來最受埋。',64,'全唐诗/poet.song.21000.json','["良金美玉信難偕，好物其來最受埋。", "盜跖免兵非積善，仲尼無土反成猜。", "中孚既若須爲信，無妄因何却有災。", "莫若致之爲外事，心源可樂是昭回。"]'),
('3cc622ad-a57d-4fb8-a6a3-96d194f99ab3','夏日南園','邵雍','宋','宋诗','song-poetry','','[]','夏木無重數，森陰翠樾低。',24,'全唐诗/poet.song.21000.json','["夏木無重數，森陰翠樾低。", "相呼百禽語，太半是黄鸝。"]'),
('168bdc26-ed37-4169-87d0-16b835437863','謝寧寺丞惠希夷罇','邵雍','宋','宋诗','song-poetry','','[]','仙掌峯巒峭不收，希夷去後遂無儔。',64,'全唐诗/poet.song.21000.json','["仙掌峯巒峭不收，希夷去後遂無儔。", "能斟時事高擡手，善酌人情略撥頭。", "畫虎不成心尚在，悲麟無應淚橫流。", "悟來不必多言語，贏得清閑第一籌。"]'),
('80b54a5f-883e-4fd6-88ca-788c229d6f89','和君實端明花庵獨坐','邵雍','宋','宋诗','song-poetry','','[]','靜坐養天和，其來所得多。',48,'全唐诗/poet.song.21000.json','["靜坐養天和，其來所得多。", "耽耽同厦宇，密密引藤蘿。", "忘去貴臣度，能容野客過。", "繫時休戚重，終不道如何。"]'),
('7928d92a-0829-4c22-8a74-eece2df9d7cd','依韻和宋都官惠椶拂子','邵雍','宋','宋诗','song-poetry','','[]','洛邑從來號別都，能容無狀久安居。',32,'全唐诗/poet.song.21000.json','["洛邑從來號別都，能容無狀久安居。", "衆蚊多少成雷處，一拂何由議掃除。"]'),
('de2cc707-7603-4ecd-b5f0-1cfcc64ea387','同王勝之學士轉運賞西園芍藥','邵雍','宋','宋诗','song-poetry','','[]','此物揚州素所聞，今于洛汭特稱珍。',64,'全唐诗/poet.song.21000.json','["此物揚州素所聞，今于洛汭特稱珍。", "雅知國色善移物，更著天香暗結人。", "欲殿羣芳仍占夏，得專奇品不須春。", "日斜立馬將歸去，再倚朱欄看一巡。"]'),
('2c2a3b3e-b6ad-49c0-93cb-89ecfa445cca','戲謝富相公惠班筍三首  其一','邵雍','宋','宋诗','song-poetry','','[]','名園不放過鵶飛，相國如今遂請時。',32,'全唐诗/poet.song.21000.json','["名園不放過鵶飛，相國如今遂請時。", "鼎食從來稱富貴，更和花笋一兼之。"]'),
('8eb7a101-2824-4f11-87e4-3a08570a9014','戲謝富相公惠班筍三首  其二','邵雍','宋','宋诗','song-poetry','','[]','承將大笋來相詫，小圃其如都不生。',32,'全唐诗/poet.song.21000.json','["承將大笋來相詫，小圃其如都不生。", "雖向性情曾著力，柰何今日未能平。"]'),
('fe279b5c-e695-47a5-9c18-c28bc577bf07','戲謝富相公惠班筍三首  其三','邵雍','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','應物功夫出世間，豈容人可强躋攀。',32,'全唐诗/poet.song.21000.json','["應物功夫出世間，豈容人可强躋攀。", "我儂自是不知量，培塿須求比泰山。"]'),
('110b4078-0492-4d70-9267-826478e76492','答李希淳屯田','邵雍','宋','宋诗','song-poetry','','[]','逢時雖出欲胡爲，其那天資智識微。',64,'全唐诗/poet.song.21000.json','["逢時雖出欲胡爲，其那天資智識微。", "弊性止堪同蠖屈，薄才安敢望鵬飛。", "長因方舊歡無極，每爲尋幽暮不歸。", "花愛半開承露看，柰何花上露沾衣。"]'),
('b78fe2e8-3c3f-489f-b13b-81f84d6b5742','苔錢','邵雍','宋','宋诗','song-poetry','','[]','一雨一番新，非關鼓鑄頻。',72,'全唐诗/poet.song.21000.json','["一雨一番新，非關鼓鑄頻。", "縱多難贈客，便失不猜人。", "遍地未爲富，滿階那濟貧。", "買愁須有爲，酤酒斷無因。", "散處如籌計，重時似索陳。", "不能賙己急，何暇更賙親。"]'),
('a14f068b-fa22-468c-bbc3-a9accb88afd0','種穀吟','邵雍','宋','宋诗','song-poetry','','[]','農家種穀時，種禾不種莠。',48,'全唐诗/poet.song.21000.json','["農家種穀時，種禾不種莠。", "柰何禾未榮，而見莠先茂。", "莠若不誅鋤，禾亦未成就。", "又況雨霈時，霑及恩一溜。"]'),
('41e933e7-77f1-4e63-bda6-2b8d8c60d016','和君實端明見贈','邵雍','宋','宋诗','song-poetry','','[]','曾不見譊譊，城中類遠郊。',48,'全唐诗/poet.song.21000.json','["曾不見譊譊，城中類遠郊。", "雖無千里馬，却有一枝巢。", "月出雲山背，風來松竹梢。", "頑然何所得，豈復避人嘲。"]'),
('d79b17e6-a322-4b2d-81aa-83ff3fbdbe6a','和秋夜','邵雍','宋','宋诗','song-poetry','','[]','久畏夏暑日，喜逢秋夜天。',48,'全唐诗/poet.song.21000.json','["久畏夏暑日，喜逢秋夜天。", "急雨過脩竹，凉風摇晚蓮。", "豈謂敗莎蛩，能繼衰柳蟬。", "安得九臯禽，清唳一灑然。"]'),
('2df8ec25-ea8e-4a9c-a62e-9f98852de7bf','和貂褥筇杖二物皆范景仁所惠','邵雍','宋','宋诗','song-poetry','','[]','君子亦保物，保故不保新。',48,'全唐诗/poet.song.21000.json','["君子亦保物，保故不保新。", "筇生蜀部石，貂走陰山塵。", "善扶巇嶮路，能暖瘦羸身。", "行坐不可捨，常如靚斯人。"]'),
('4af8130d-b912-4aa4-a777-a96b2eed22a2','和雲','邵雍','宋','宋诗','song-poetry','','[]','萬里幙四垂，一片雲自飛。',48,'全唐诗/poet.song.21000.json','["萬里幙四垂，一片雲自飛。", "祗知根抱石，不爲天爲衣。", "既來曾無心，却去寧有機。", "未能作霖雨，安用帝鄉歸。"]'),
('d2167e95-613a-4fb0-9389-fb9f5aa37546','和閑來','邵雍','宋','宋诗','song-poetry','','[]','以身觀萬物，萬物理非遥。',48,'全唐诗/poet.song.21000.json','["以身觀萬物，萬物理非遥。", "馬爲乘多瘦，龜因灼苦焦。", "能言謝鸚鵡，易飽過鷦鷯。", "伊洛好煙水，願同漁與樵。"]'),
('1285252d-99ec-4bb7-8912-79f50fcaab19','和花庵上牽牛花','邵雍','宋','宋诗','song-poetry','','[]','葉鬧深如幄，花繁翠似鈿。',48,'全唐诗/poet.song.21000.json','["葉鬧深如幄，花繁翠似鈿。", "瀼瀼零曉露，羃羃蔽晴煙。", "謝既成番次，開仍有後先。", "主人凝佇苦，長是廢朝眠。"]'),
('44353604-d38c-4ba6-b95b-2a49c6a96c9c','寄三城舊友衛比部二絕  其一','邵雍','宋','宋诗','song-poetry','','[]','雖老未龍鐘，籬邊菊滿叢。',24,'全唐诗/poet.song.21000.json','["雖老未龍鐘，籬邊菊滿叢。", "乍凉天氣好，里閈正過從。"]'),
('86c2dcb3-b6da-459d-b3e5-34c8aebf92e6','寄三城舊友衛比部二絕  其二','邵雍','宋','宋诗','song-poetry','','[]','景好身還健，天晴路又乾。',24,'全唐诗/poet.song.21000.json','["景好身還健，天晴路又乾。", "小車芳草軟，處處是清歡。"]'),
('7ca46bbc-1b57-4746-ac2e-c85b5435af14','秋日登石閣','邵雍','宋','宋诗','song-poetry','','[]','初晴僧閣一凭欄，風物凄凉八月間。',64,'全唐诗/poet.song.21000.json','["初晴僧閣一凭欄，風物凄凉八月間。", "欲盡上層嘗脚力，更於高處看人寰。", "秋深天氣隨宜好，老後心懷只愛閑。", "爲報遠山休斂黛，這般情意久蘭珊。"]'),
('71f8153b-01f6-446f-8735-45027b0d768d','和李審言龍圖行次龍門見寄','邵雍','宋','宋诗','song-poetry','','[]','萬里秋光入坐明，交情預喜笑相迎。',32,'全唐诗/poet.song.21000.json','["萬里秋光入坐明，交情預喜笑相迎。", "菊花未服重陽過，如待君來泛巨觥。"]'),
('d8483bc6-3477-419f-99b2-e0ea1208e930','風月吟','邵雍','宋','宋诗','song-poetry','','[]','凉風無限清，良月無限明。',48,'全唐诗/poet.song.21000.json','["凉風無限清，良月無限明。", "清明不我捨，長能成歡情。", "終朝三褫辱，晝日三接榮。", "榮辱我不預，何復能有驚。"]'),
('08165cfb-7300-44ec-b4d6-03ede32ce6d9','贈富公','邵雍','宋','宋诗','song-poetry','','[]','天下繫休戚，世間誰擬倫。',48,'全唐诗/poet.song.21000.json','["天下繫休戚，世間誰擬倫。", "三朝爲宰相，四海作閑人。", "照破萬古事，收歸一點真。", "不知緣底事，見我却慇懃。"]'),
('14e1442f-255b-44bc-832f-0e287f5208e4','弄筆吟','邵雍','宋','宋诗','song-poetry','','[]','人生所貴有精神，既有精神却不純。',64,'全唐诗/poet.song.21000.json','["人生所貴有精神，既有精神却不純。", "弄假像真終是假，將勤補拙總輸勤。", "因饑得飽飽猶病，爲病求安安未真。", "人誤聖人人不少，聖人無誤世間人。"]'),
('2985408d-710d-4362-8afe-1b01078f1f61','招司馬君實遊夏圃','邵雍','宋','宋诗','song-poetry','','[]','雨霽景自好，秋深天未寒。',24,'全唐诗/poet.song.21000.json','["雨霽景自好，秋深天未寒。", "可能乘興否，夏圃上盤桓。"]'),
('e0b4aa09-fc7c-48ed-aa02-07f12af9c72f','秋日雨霽閑望','邵雍','宋','宋诗','song-poetry','','[]','水冷雲疎霜意早，歲華雖晚黄花好。',64,'全唐诗/poet.song.21000.json','["水冷雲疎霜意早，歲華雖晚黄花好。", "饒教四面遠山圍，柰何一片秋光老。", "上天生物固無私，聖人餘事人難曉。", "陳言生活不須矜，自是中才皆可了。"]'),
('94024b04-3c5d-4175-9079-85c676545e4a','四小吟簡陳季常','邵雍','宋','宋诗','song-poetry','','[]','八月小春天，小花開且殷。',24,'全唐诗/poet.song.21000.json','["八月小春天，小花開且殷。", "晚來經小雨，遂使小車閑。"]'),
('4718c42d-d5c8-48b3-bd24-6c757d0d8b97','樂樂吟','邵雍','宋','宋诗','song-poetry','','[]','吾常好樂樂，所樂無害義。',48,'全唐诗/poet.song.21000.json','["吾常好樂樂，所樂無害義。", "樂天四時好，樂地百物備。", "樂人有美行，樂己能樂事。", "此數樂之外，更樂微微醉。"]'),
('6b2c67c8-c994-4847-a9c6-b8c0aecd5569','誡子吟','邵雍','宋','宋诗','song-poetry','','[]','善惡無佗在所存，小人君子此中分。',64,'全唐诗/poet.song.21000.json','["善惡無佗在所存，小人君子此中分。", "改圖不害爲君子，迷復終歸作小人。", "良藥有功方利病，白圭無玷始稱珍。", "欲成令器須追琢，過失如何不就新。"]'),
('60ce203c-aff0-466f-943d-b21464301e54','聞少華崩','邵雍','宋','宋诗','song-poetry','','[]','變化無蹤倏忽間，力迴天地不爲難。',64,'全唐诗/poet.song.21000.json','["變化無蹤倏忽間，力迴天地不爲難。", "若教施展巨靈手，豈止軒騰少華山。", "六社居民皆覆沒，九泉磐石盡飛翻。", "芻蕘一句能收采，堯舜之時自可攀。"]'),
('39b8acfd-ca8c-4245-8763-2cef708877b9','自古吟','邵雍','宋','宋诗','song-poetry','','[]','自古大聖人，猶以爲難事。',48,'全唐诗/poet.song.21000.json','["自古大聖人，猶以爲難事。", "而況後世人，豈復便能至。", "求之不勝難，得之至容易。", "千人萬人心，一人之心是。"]'),
('28f3ab97-5ac3-47b5-b99d-96e3567f6495','代書寄祖龍圖','邵雍','宋','宋诗','song-poetry','','[]','三十年交舊，相逢各白頭。',48,'全唐诗/poet.song.21000.json','["三十年交舊，相逢各白頭。", "海壖曾共飲，洛社又同遊。", "脫屣風波地，開懷松桂秋。", "兩眉從此後，應不著閑愁。"]'),
('69182a88-5d26-48cc-a54c-d571b9f28bd0','寒夜吟','邵雍','宋','宋诗','song-poetry','','[]','天加一上寒，我添一重被。',48,'全唐诗/poet.song.21000.json','["天加一上寒，我添一重被。", "不出既往言，不爲已甚事。", "責己重以周，與人不求備。", "唯是大聖人，能立無過地。"]'),
('d9f038b9-c5f1-425c-87b1-e124ffdd8996','知幸吟','邵雍','宋','宋诗','song-poetry','','[]','雞職在司晨，犬職在守禦。',48,'全唐诗/poet.song.21000.json','["雞職在司晨，犬職在守禦。", "二者皆有功，一歸于報主。", "我饑亦享食，我寒亦受衣。", "如何無纖毫，功德補于時。"]'),
('0d5b23db-0ffe-48c9-a8e1-7204d5da5454','趨嚮','邵雍','宋','宋诗','song-poetry','','[]','捨我靈龜，觀我朵頤。',40,'全唐诗/poet.song.21000.json','["捨我靈龜，觀我朵頤。", "背義從利，人無遠思。", "賁于丘園，束帛戔戔。", "既能圖大，小在其間。"]'),
('b8f8161c-801b-4fd0-95f6-321e6908c2da','不可知吟','邵雍','宋','宋诗','song-poetry','','[]','犁牛生騂角，老蚌産明珠。',48,'全唐诗/poet.song.21000.json','["犁牛生騂角，老蚌産明珠。", "人雖欲勿用，山川其舍諸。", "事固不可知，物亦難其拘。", "一歸于臆度，義失乎精粗。"]'),
('86e45959-6bcf-44c2-bf49-1559fafd45ea','事急吟','邵雍','宋','宋诗','song-poetry','','[]','旱極望雨意，病危思藥心。',24,'全唐诗/poet.song.21000.json','["旱極望雨意，病危思藥心。", "人人當此際，不待勸而深。"]'),
('9fac0fb3-31d8-4dc5-b569-cd9566c5207b','知人吟','邵雍','宋','宋诗','song-poetry','','[]','事到急時觀態度，人于危處露肝脾。',32,'全唐诗/poet.song.21000.json','["事到急時觀態度，人于危處露肝脾。", "深心厚貌平時可，慎勿便言容易知。"]'),
('b89e960b-634f-4d09-aa9e-cd6cfc0a552b','言語吟','邵雍','宋','宋诗','song-poetry','','[]','一語便喜處，千言益怒時。',24,'全唐诗/poet.song.21000.json','["一語便喜處，千言益怒時。", "既因言語合，却爲語言離。"]'),
('61ff76bb-6d9d-4fa5-9edc-ffaad7ee9ed0','思患吟','邵雍','宋','宋诗','song-poetry','','[]','緣飾近虛襟，虛襟後患深。',24,'全唐诗/poet.song.21000.json','["緣飾近虛襟，虛襟後患深。", "療饑當用食，救旱必須霖。"]'),
('62af8618-a319-4315-932f-4139147e5e5b','人生一世吟','邵雍','宋','宋诗','song-poetry','','[]','前有億萬年，後有億萬世。',48,'全唐诗/poet.song.21000.json','["前有億萬年，後有億萬世。", "中間一百年，做得幾何事。", "又況人之壽，幾人能百歲。", "如何不喜歡，强自生憔悴。"]'),
('a33628a4-cb7b-4023-abc1-a1bbdeef9103','謝人惠石笋','邵雍','宋','宋诗','song-poetry','','[]','誰將天柱峯，快刀割一半。',48,'全唐诗/poet.song.21000.json','["誰將天柱峯，快刀割一半。", "泉漱痕微清，雲抱色猶見。", "權門不能移，富室不能轉。", "則予何人哉，當閻君之獻。"]'),
('4fb8cf83-e9d0-4302-8973-907b9ab85814','奉和十月二十四日初見雪呈相國元老','邵雍','宋','宋诗','song-poetry','','[]','壬子初逢雪，未多仍却晴。',48,'全唐诗/poet.song.21000.json','["壬子初逢雪，未多仍却晴。", "人間都變白，林下不勝清。", "寒士痛遭恐，窮民惡著驚。", "盃觴限新法，何故便能傾。"]'),
('5e9f8495-ccba-42d8-9a88-bad181c5e290','和相國元老','邵雍','宋','宋诗','song-poetry','','[]','崇臺未經慶，瑞雪下雲端。',48,'全唐诗/poet.song.21000.json','["崇臺未經慶，瑞雪下雲端。", "雖地盡成白，而天不甚寒。", "有年豐可待，盈尺潤難乾。", "畎畝無忘處，追蹤擊壤歡。"]'),
('2171ec8c-6506-49f7-8564-dcd88c98a417','天津看雪代簡謝蔣秀才還詩卷','邵雍','宋','宋诗','song-poetry','','[]','清洛接天去，寒雲貼地飛。',24,'全唐诗/poet.song.21000.json','["清洛接天去，寒雲貼地飛。", "人於橋上立，詩向雪中歸。"]'),
('21461d1c-87ec-4dba-83da-b67e7e52e9db','安樂窩中看雪  其一','邵雍','宋','宋诗','song-poetry','','[]','同雲漠漠雪霏霏，安樂窩中卧看時。',64,'全唐诗/poet.song.21000.json','["同雲漠漠雪霏霏，安樂窩中卧看時。", "初訝後園羅玉樹，却驚平地璨瑶池。", "未逢寒食梨花謝，不待春風柳絮飛。", "酒放半醺簾半卷，此情無使外人知。"]'),
('2f1d4163-c3e6-4d9f-abaa-d787a19f96b3','安樂窩中看雪  其二','邵雍','宋','宋诗','song-poetry','','[]','滿目是瑶琚，貧家遂富如。',48,'全唐诗/poet.song.21000.json','["滿目是瑶琚，貧家遂富如。", "許觀非許賣，宜慘不宜舒。", "醇釀裝醺後，重衾造暖餘。", "肯於人世上，造險較錙銖。"]'),
('e72d0cad-bbd7-4408-b221-058d7f085e5b','答富鄭公見示正旦四絕','邵雍','宋','宋诗','song-poetry','','[]','正旦四篇詩，緣忻七十期。',24,'全唐诗/poet.song.21000.json','["正旦四篇詩，緣忻七十期。", "請觀唐故事，未放晉公歸。"]'),
('515dc8d2-607d-48e6-8bfc-1a567079f69a','和君實端明','邵雍','宋','宋诗','song-poetry','','[]','養道自安恬，霜毛一任添。',48,'全唐诗/poet.song.21000.json','["養道自安恬，霜毛一任添。", "且無官責咎，幸免世猜嫌。", "蓬戶能安分，藜羹固不厭。", "一般偏好處，曝背向前簷。"]'),
('478fb48d-ea44-44a0-9084-821355fadeba','安樂窩中四長吟','邵雍','宋','宋诗','song-poetry','','[]','安樂窩中快活人，閑來四物幸相親。',64,'全唐诗/poet.song.21000.json','["安樂窩中快活人，閑來四物幸相親。", "一編詩逸收花月，一部書嚴驚鬼神。", "一炷香清沖宇泰，一樽酒美湛天真。", "太平自慶何多也，唯願君王壽萬春。"]'),
('748a5401-646a-458a-80b9-b10b976bb356','安樂窩中詩一編','邵雍','宋','宋诗','song-poetry','','[]','安樂窩中詩一編，自歌自詠自怡然。',160,'全唐诗/poet.song.21000.json','["安樂窩中詩一編，自歌自詠自怡然。", "陶鎔水石閑勳業，銓擇風花靜事權。", "意去乍乘千里馬，興來初上九重天。", "忺時更改三兩字，醉後吟哦五七篇。", "直恐心通雲外月，又疑身是洞中仙。", "銀河洶湧翻晴浪，玉樹查牙生紫煙。", "萬物有情皆可狀，百骸無病不能蠲。", "命題濫被神相助，得句謬爲人所傳。", "肯讓貴家常奏樂，寧慙富室賸收錢。", "若條此過知何限，因甚臺官獨未言。"]'),
('26f1d291-ec10-42b8-ad2e-a00a79637ce4','安樂窩中一部書','邵雍','宋','宋诗','song-poetry','','[]','安樂窩中一部書，號云皇極意何如。',160,'全唐诗/poet.song.21000.json','["安樂窩中一部書，號云皇極意何如。", "春秋禮樂能遺則，父子君臣可廢乎。", "浩浩羲軒開闢後，巍巍堯舜協和初。", "炎炎湯武干戈外，恟恟桓文弓劍餘。", "日月星辰高照耀，皇王帝伯大鋪舒。", "幾千百主出規制，數億萬年成楷模。", "治久便憂强跋扈，患深仍念惡驅除。", "才堪命世有時有，智可濟時無世無。", "既往盡歸閑指點，未來須俟別枝梧。", "不知造化誰爲主，生得許多奇丈夫。"]'),
('05f5bc8e-cf74-4c80-9e1c-c9fa7ff8ddc3','安樂窩中一炷香','邵雍','宋','宋诗','song-poetry','','[]','安樂窩中一炷香，凌晨焚意豈尋常。',160,'全唐诗/poet.song.21000.json','["安樂窩中一炷香，凌晨焚意豈尋常。", "禍如許免人須諂，福若待求天可量。", "且異緇黄徼廟貌，又殊兒女裊衣裳。", "中孚起信寧煩禱，无妄生灾未易禳。", "虛室清泠都是白，靈臺瑩靜別生光。", "觀風禦寇心方醉，對景顔淵坐正忘。", "赤水有珠涵造化，泥丸無物隔青蒼。", "生爲男子仍身健，時遇昌辰更歲穰。", "日月照臨功自大，君臣庇廕效何長。", "非徒聞道至於此，金玉誰家不滿堂。"]'),
('6c918936-9f9f-4751-b9eb-850b8de7162f','安樂窩中酒一樽','邵雍','宋','宋诗','song-poetry','','[]','安樂窩中酒一罇，非唯養氣又頤真。',160,'全唐诗/poet.song.21000.json','["安樂窩中酒一罇，非唯養氣又頤真。", "頻頻到口微成醉，拍拍滿懷都是春。", "何異君臣初際會，又同天地乍絪紜。", "醺酣情味難名狀，醖釀功夫莫指陳。", "斟有淺深存燮理，飲無多少寄經綸。", "鳳凰樓下逍遥客，郟鄏城中自在人。", "高閣望時花似錦，小車行處草如茵。", "卷舒萬世興亡手，出入千重雲水身。", "雨後靜觀山意思，風前閑看月精神。", "這般事業權衡別，振古英雄恐未聞。"]'),
('93cb012f-3b2d-4b0e-b057-b12c592d82f7','謝富相公見示新詩一軸  其一','邵雍','宋','宋诗','song-poetry','','[]','通衢選地半松筠，元老辭榮向盛辰。',64,'全唐诗/poet.song.21000.json','["通衢選地半松筠，元老辭榮向盛辰。", "多種好花觀物體，每斟醇酒發天真。", "清朝將相當年事，碧洞神仙今日身。", "更出新詩二十首，其間字字敵陽春。"]'),
('cd1d761b-c98a-49ae-887a-668d2309675f','謝富相公見示新詩一軸  其二','邵雍','宋','宋诗','song-poetry','','[]','文章天下稱公器，詩在文章更不疎。',64,'全唐诗/poet.song.21000.json','["文章天下稱公器，詩在文章更不疎。", "到性始知真氣味，入神方見妙功夫。", "閑將歲月觀消長，靜把乾坤照有無。", "辭比離騷更溫潤，離騷其柰少寬舒。"]'),
('55f789dc-6d99-45ee-b041-92c484bd370e','安樂窩中好打乖吟','邵雍','宋','宋诗','song-poetry','','[]','安樂窩中好打乖，打乖年紀合挨排。',64,'全唐诗/poet.song.21000.json','["安樂窩中好打乖，打乖年紀合挨排。", "重寒盛暑多閉戶，輕暖初凉時出街。", "風月煎催親筆硯，鶑花引惹傍樽罍。", "問君何故能如此，祗被才能養不才。"]'),
('c0784b85-88fe-497e-8275-d6caccc3a0e9','和君實端明登石閣','邵雍','宋','宋诗','song-poetry','','[]','平地雖然遠，那知物物新。',24,'全唐诗/poet.song.21000.json','["平地雖然遠，那知物物新。", "危樓一百尺，別有萬般春。"]'),
('827a9125-1f8b-473d-9fdd-4487fa7f41b5','和君實端明副酒之什','邵雍','宋','宋诗','song-poetry','','[]','洛陽花木滿城開，更送東都雙榼來。',32,'全唐诗/poet.song.21000.json','["洛陽花木滿城開，更送東都雙榼來。", "遂使閑人轉狂亂，柰何紅日又西頹。"]'),
('933e86fe-01d5-434f-8db2-1f4d70379805','對花吟','邵雍','宋','宋诗','song-poetry','','[]','春在花爭好，春歸花遂殘。',48,'全唐诗/poet.song.21000.json','["春在花爭好，春歸花遂殘。", "好花留不住，好客會亦難。", "酒既對花飲，花宜把酒看。", "如何更斟滿，乃盡此時歡。"]'),
('7bbe8f0f-d45c-4faf-83c7-987419a62bd6','依韻寄成都李希淳屯田','邵雍','宋','宋诗','song-poetry','','[]','思君君未還，君戀蜀中官。',48,'全唐诗/poet.song.21000.json','["思君君未還，君戀蜀中官。", "白首雖知倦，清衷宜自寬。", "花時難得會，蠶市易成歡。", "莫歎歸休晚，生涯苦未完。"]'),
('605ddc00-81b4-4cc5-a264-95704d6205b8','代書寄廣信李遵度承制','邵雍','宋','宋诗','song-poetry','','[]','薊北更千里，漢唐爲極邊。',48,'全唐诗/poet.song.21000.json','["薊北更千里，漢唐爲極邊。", "柰何今境土，不復舊山川。", "虎帳兵家重，雕弓嗣子傳。", "佗年勒功處，無使後燕然。"]'),
('571785d8-3955-4178-ab57-17811c63bea7','自和打乖吟','邵雍','宋','宋诗','song-poetry','','[]','安樂窩中好打乖，自知元沒出人才。',64,'全唐诗/poet.song.21000.json','["安樂窩中好打乖，自知元沒出人才。", "老年多病不服藥，少日壯心都已灰。", "庭草剗除終未盡，檻花擡舉尚難開。", "輕風吹動半醺酒，此樂直從天外來。"]'),
('6c354104-8639-4f95-9a2d-c05c5deac49f','年老逢春十三首  其一','邵雍','宋','宋诗','song-poetry','','[]','年老逢春春莫猜，老年方自少年迴。',64,'全唐诗/poet.song.21000.json','["年老逢春春莫猜，老年方自少年迴。", "人情少悅酒不解，天氣却寒花未開。", "堤外有風斜送柳，牆陰經雨半生苔。", "去年波水東流去，舊淥柰何新又來。"]'),
('c9be2341-b6ee-464e-8bc2-93680caceb82','年老逢春十三首  其二','邵雍','宋','宋诗','song-poetry','','[]','年老逢春春正妍，春妍況在禁煙前。',64,'全唐诗/poet.song.21000.json','["年老逢春春正妍，春妍況在禁煙前。", "纔寒却暖養花日，行雨便晴消酒天。", "進退樽罍宜有主，栽培桃李豈無權。", "清談已是歡情極，更把狂詩當管絃。"]'),
('c0bc5a89-55e9-4142-a9bf-9ba157f04df4','年老逢春十三首  其三','邵雍','宋','宋诗','song-poetry','','[]','年老逢春雨乍晴，雨晴況復近清明。',64,'全唐诗/poet.song.21000.json','["年老逢春雨乍晴，雨晴況復近清明。", "天低宮殿初長日，風暖園林未囀鶑。", "花似錦時高閣望，草如茵處小車行。", "東君見賜何多也，又復人間久太平。"]'),
('7d69db88-d9f8-40b2-9eab-b0da3d89ed2f','年老逢春十三首  其四','邵雍','宋','宋诗','song-poetry','','[]','年老逢春莫厭春，住家況復在天津。',64,'全唐诗/poet.song.21000.json','["年老逢春莫厭春，住家況復在天津。", "既將水竹爲生計，須與風花作主人。", "故宅費功除瓦礫，新畦加意種蘭薰。", "未知去此閑田地，何地更能容此身。"]'),
('54b0fe95-fa19-41b0-89a3-45f2a68c45ac','年老逢春十三首  其五','邵雍','宋','宋诗','song-poetry','','[]','年老逢春始識春，春妍都恐屬閑身。',64,'全唐诗/poet.song.21000.json','["年老逢春始識春，春妍都恐屬閑身。", "能知青帝功夫大，肯逐後生撩亂頻。", "酒趁嫩醅嘗格韻，花承曉露看精神。", "大凡尤物難分付，造化從來不負人。"]'),
('0b0bd8a6-5940-40bd-ab7b-e4a9c7d625e9','年老逢春十三首  其六','邵雍','宋','宋诗','song-poetry','','[]','年老逢春春意多，波光誰染柳誰搓。',64,'全唐诗/poet.song.21000.json','["年老逢春春意多，波光誰染柳誰搓。", "池亭正好愛不徹，草木向榮情柰何。", "便把樽罍通意思，須防風雨害清和。", "千紅萬翠中間裏，似我閑人更有麽。"]'),
('de1ed37c-cf5b-4a75-a36a-e24312be3ea6','年老逢春十三首  其七','邵雍','宋','宋诗','song-poetry','','[]','年老逢春春莫厭，春工慎勿致猜嫌。',64,'全唐诗/poet.song.21000.json','["年老逢春春莫厭，春工慎勿致猜嫌。", "紅芳若得眼前過，白髮任從頭上添。", "雨後艷花零淚顆，風餘新月露眉尖。", "輕醇酒面斟來凸，舉盞長憂不易拈。"]'),
('da8d8679-1975-436d-b732-d0745da2c0a2','年老逢春十三首  其八','邵雍','宋','宋诗','song-poetry','','[]','年老逢春春莫慳，春慳不當世艱難。',64,'全唐诗/poet.song.21000.json','["年老逢春春莫慳，春慳不當世艱難。", "四時只有三春好，一歲都無十日間。", "酒盞不煩人討免，花枝須念雨摧殘。", "却愁千片飄零後，多少金能買此歡。"]'),
('3dd307b0-321e-4974-b6e3-9a6d7602caf2','年老逢春十三首  其九','邵雍','宋','宋诗','song-poetry','','[]','年老逢春莫厭頻，更頻能見幾迴春。',64,'全唐诗/poet.song.21000.json','["年老逢春莫厭頻，更頻能見幾迴春。", "須將酒盞强留客，却恐花枝解笑人。", "世態不堪新間舊，物情難免假疑真。", "誰云梁燕多言語，此箇深冤都未伸。"]'),
('13a3f543-8fc0-4779-be6a-b2a7f1526676','年老逢春十三首  其一○','邵雍','宋','宋诗','song-poetry','','[]','年老逢春興未收，願春慈造少遲留。',64,'全唐诗/poet.song.21000.json','["年老逢春興未收，願春慈造少遲留。", "既稱好事愁花老，須與多情秉燭遊。", "酒裏功勞閑汗馬，詩中罪過靜風流。", "東君不柰人嘲戲，僝僽花枝惡未休。"]'),
('448513a2-ae0a-471a-801e-476cff2e89fe','年老逢春十三首  其一一','邵雍','宋','宋诗','song-poetry','','[]','年老逢春莫惜狂，惜狂無那興難當。',64,'全唐诗/poet.song.21000.json','["年老逢春莫惜狂，惜狂無那興難當。", "園林恰到惡明媚，風雨便多閑中傷。", "花等半開宜速賞，酒聞纔熟便先嘗。", "大都美物天長惜，非是吾儕曲主張。"]'),
('bab12e79-f9f2-40d1-893b-11af5f13bd7b','年老逢春十三首  其一二','邵雍','宋','宋诗','song-poetry','','[]','年老逢春春不任，不任緣被老來侵。',64,'全唐诗/poet.song.21000.json','["年老逢春春不任，不任緣被老來侵。", "一身老去惡足惜，滿眼春歸何處尋。", "紅日墜時風更急，落花流處水仍深。", "流鶑不悟芳菲歇，猶向枝頭送好音。"]'),
('e9318e57-7c87-4740-a850-dfa2ee512f72','年老逢春十三首  其一三','邵雍','宋','宋诗','song-poetry','','[]','年老逢春認破春，破春不用苦傷神。',64,'全唐诗/poet.song.21000.json','["年老逢春認破春，破春不用苦傷神。", "身心自有安存地，草木焉能媚惑人。", "此日榮爲佗日瘁，今年陳是去年新。", "世間憂喜常相逐，多少酒能平得君。"]'),
('77f9b7ba-04a7-4c2e-a688-e977ef1a6daf','和  其一','邵雍','宋','宋诗','song-poetry','','[]','君家梁上年時燕，過社今年尚未迴。',32,'全唐诗/poet.song.21000.json','["君家梁上年時燕，過社今年尚未迴。", "請罰誤君凝竚久，萬花深處小車來。"]'),
('0e51ee3b-56b1-4b89-af81-c84ce615ce65','和  其二','邵雍','宋','宋诗','song-poetry','','[]','天啟夫君八斗才，野人中路必須迴。',32,'全唐诗/poet.song.21000.json','["天啟夫君八斗才，野人中路必須迴。", "神仙一句難忘處，花外小車猶未來。"]'),
('09fb3b7b-56b3-4480-9b4e-8fe217641af7','別兩絕  其一','邵雍','宋','宋诗','song-poetry','','[]','樓外花深礙小車，難忘有德見思多。',32,'全唐诗/poet.song.21000.json','["樓外花深礙小車，難忘有德見思多。", "欲憑桃李爲之謝，桃李無言爭柰何。"]'),
('432e92a3-3202-46b2-96bd-7f1c8d4fa6f4','別兩絕  其二','邵雍','宋','宋诗','song-poetry','','[]','賞花高閣上，負約罪難迴。',24,'全唐诗/poet.song.21000.json','["賞花高閣上，負約罪難迴。", "若許將詩贖，何時不可陪。"]'),
('b7e5e7b9-e340-4b65-904b-0fa85f0f1f46','春日登石閣','邵雍','宋','宋诗','song-poetry','','[]','滿洛城中將相家，廣栽桃李作生涯。',32,'全唐诗/poet.song.21000.json','["滿洛城中將相家，廣栽桃李作生涯。", "年年二月凭高處，不見人家只見花。"]'),
('f4e80e0c-5783-4117-809f-343fff941429','六十三吟','邵雍','宋','宋诗','song-poetry','','[]','行年六十有三歲，齒髮雖衰志未衰。',64,'全唐诗/poet.song.21000.json','["行年六十有三歲，齒髮雖衰志未衰。", "恥把精神虛作弄，肯將才力妄施爲。", "愁聞刮骨聲音切，悶見吹毛智數卑。", "珍重至人嘗有語，落便宜是得便宜。"]'),
('f57f8794-49ff-45f6-b7f2-a46546cff116','感事吟','邵雍','宋','宋诗','song-poetry','','[]','古人不見面，止可觀其心。',84,'全唐诗/poet.song.21000.json','["古人不見面，止可觀其心。", "其心固無佗，而多顧義深。", "今人不見心，正可觀其面。", "其面固無佗，而多顧利淺。", "顧義則利人，顧利則害民。", "利人與害民，而卒反其身。", "其身幸而免，亦須殃子孫。"]'),
('9c8911f2-dad9-4d54-b600-c2ba1eaaa6fe','偶書','邵雍','宋','宋诗','song-poetry','','[]','天生萬物，各遂其一。',100,'全唐诗/poet.song.21000.json','["天生萬物，各遂其一。", "唯人最靈，萬物能并。", "芝蘭芬芳，麒麟鳳凰。", "此類之人，鮮有不臧。", "狼毒冶葛，梟鴆蛇蝎。", "此類之人，鮮有不孽。", "臧唯思安，孽唯思殘。", "日夜無息，相代于前。", "天無私覆，地無私載。", "俱能含養，始知廣大。"]'),
('75e98ed7-1445-47e5-a1bf-20f64f901f89','偶得吟','邵雍','宋','宋诗','song-poetry','','[]','蛙蜢泥中走，鳳凰雲外飛。',24,'全唐诗/poet.song.21000.json','["蛙蜢泥中走，鳳凰雲外飛。", "雲泥相去遠，自是難相知。"]'),
('eaf22078-b1e0-44b8-89e1-f0450cb7db10','太和湯吟','邵雍','宋','宋诗','song-poetry','','[]','二味相和就甕頭，一般收口效偏優。',64,'全唐诗/poet.song.21000.json','["二味相和就甕頭，一般收口效偏優。", "同斟祗却因無事，獨酌何嘗爲有愁。", "纔沃便從真宰辟，半醺仍約伏羲遊。", "人間盡愛醉時好，未到醉時誰肯休。"]'),
('f4103532-81d8-4ec7-af74-193b79a5c396','洗竹','邵雍','宋','宋诗','song-poetry','','[]','歲寒松柏共經秋，叢剉無端蔽翳稠。',64,'全唐诗/poet.song.21000.json','["歲寒松柏共經秋，叢剉無端蔽翳稠。", "遍地冗枝都與去，倚天高幹一齊留。", "應龍吟後聲能效，儀鳳來時功可收。", "未說其佗爲用處，此般風格最難儔。"]'),
('219ca3f1-944e-4d93-8fd9-88c8d9ab3f91','天意吟','邵雍','宋','宋诗','song-poetry','','[]','天意無佗只自然，自然之外更無天。',64,'全唐诗/poet.song.21000.json','["天意無佗只自然，自然之外更無天。", "不欺誰怕居暗室，絕利須求在一源。", "未喫力時猶有說，到收功處更何言。", "聖人能事人難繼，無價明珠正在淵。"]'),
('d65b1560-b080-403e-bf5c-8ce39f0d8160','代書戲祖龍圖','邵雍','宋','宋诗','song-poetry','','[]','祖兄同甲申，二十七日長。',48,'全唐诗/poet.song.21000.json','["祖兄同甲申，二十七日長。", "無怨可低眉，有歡能抵掌。", "交情日更深，道義久相尚。", "但欠書丹人，黄金八百兩。"]'),
('4592c855-a5ff-4656-b5a9-0443e3515811','把酒','邵雍','宋','宋诗','song-poetry','','[]','把酒囑兒男，吾今六十三。',48,'全唐诗/poet.song.21000.json','["把酒囑兒男，吾今六十三。", "處身雖未至，講道固無慙。", "世上榮都謝，林間樂尚貪。", "語其貪一也，且免世猜嫌。"]'),
('9f53510b-81f6-41f3-8281-82be0a48bc7b','對花','邵雍','宋','宋诗','song-poetry','','[]','花枝照酒巵，把酒囑花枝。',48,'全唐诗/poet.song.21000.json','["花枝照酒巵，把酒囑花枝。", "酒盡錢能買，花殘藥不醫。", "人無先酩酊，花莫便離披。", "慢慢對花飲，況春能幾時。"]'),
('26d4b5ad-ce97-450e-9e32-055e6fe82145','四道吟','邵雍','宋','宋诗','song-poetry','','[]','天道有消長，地道有險夷。',48,'全唐诗/poet.song.21000.json','["天道有消長，地道有險夷。", "人道有興廢，物道有盛衰。", "興廢不同世，盛衰不同時。", "柰何人當之，許多喜與悲。"]'),
('476419fb-859d-4874-8790-c10ea209568d','林下吟','邵雍','宋','宋诗','song-poetry','','[]','林下一般奇，俗人那得知。',48,'全唐诗/poet.song.21000.json','["林下一般奇，俗人那得知。", "乍圓明月夜，纔放好花枝。", "美酒未斟滿，佳賓莫放歸。", "世間優我輩，幸有這些兒。"]'),
('0f3e9d0c-d017-4117-bf5d-f7461885323d','春陰  其一','邵雍','宋','宋诗','song-poetry','','[]','日日是春陰，春陰又復沉。',48,'全唐诗/poet.song.21000.json','["日日是春陰，春陰又復沉。", "養花雖有力，愛月豈無心。", "月滿方能看，花開始可吟。", "柰何花與月，殊不諒人深。"]'),
('5a94f8ea-9f0f-49d7-8601-0ef2434bd64b','春陰  其二','邵雍','宋','宋诗','song-poetry','','[]','花好難久觀，月好難久看。',48,'全唐诗/poet.song.21000.json','["花好難久觀，月好難久看。", "花能五七日，月止十二圓。", "圓時仍齟齬，開處足摧殘。", "風雨尋常事，人心何不安。"]'),
('f7d4ed41-c908-466e-b1b7-449cacea1f5e','囑花吟','邵雍','宋','宋诗','song-poetry','','[]','把酒囑花枝，花枝亦要知。',48,'全唐诗/poet.song.21000.json','["把酒囑花枝，花枝亦要知。", "花無十日盛，人有百年期。", "據此銷魂處，寧思中酒時。", "若非詩斷割，難解一生迷。"]'),
('10388a55-63f0-4faa-98cc-b670c96686f3','懶起吟','邵雍','宋','宋诗','song-poetry','','[]','半記不記夢覺後，似愁無愁情倦時。',32,'全唐诗/poet.song.21000.json','["半記不記夢覺後，似愁無愁情倦時。", "擁衾側卧未忺起，簾外落花撩亂飛。"]'),
('26fc5886-b071-478a-9b15-e00ab9a26bf4','感事吟','邵雍','宋','宋诗','song-poetry','','[]','君子小人正相反，上智下愚誠不移。',32,'全唐诗/poet.song.21000.json','["君子小人正相反，上智下愚誠不移。", "冶葛根非連靈芝，柰何生與天地齊。"]'),
('313d2fc7-e050-4efe-999f-dff30156d536','三惑','邵雍','宋','宋诗','song-poetry','','[]','老而不歇是一惑，安而不樂是二惑。',32,'全唐诗/poet.song.21000.json','["老而不歇是一惑，安而不樂是二惑。", "閑而不清是三惑，三者之惑自戕賊。"]'),
('83b63df3-be3a-4a16-9f08-d5a03a359e2c','四喜','邵雍','宋','宋诗','song-poetry','','[]','一喜長年爲壽域，二喜豐年爲樂國。',32,'全唐诗/poet.song.21000.json','["一喜長年爲壽域，二喜豐年爲樂國。", "三喜清閑爲福德，四喜安康爲福力。"]'),
('e279c02f-81ce-4d47-8922-fa5c7550433e','何如吟','邵雍','宋','宋诗','song-poetry','','[]','立身須作真男子，臨事無爲淺丈夫。',32,'全唐诗/poet.song.21000.json','["立身須作真男子，臨事無爲淺丈夫。", "料得人生皆素定，空多計較竟何如。"]'),
('9fb9bfff-d444-4b8c-b90c-50611024daa9','問春吟','邵雍','宋','宋诗','song-poetry','','[]','自古言花須說鶑，鶑花本合一時行。',64,'全唐诗/poet.song.21000.json','["自古言花須說鶑，鶑花本合一時行。", "因何花謝鶑纔至，浪得鶑花相與名。", "輒欲問春春不應，私於蜂蝶有何情。", "流鶑不伏春辜負，啼了千聲又萬聲。"]'),
('d3be4f29-d4b5-4dc9-a906-586900e4297b','樓上寄友人','邵雍','宋','宋诗','song-poetry','','[]','有客常輕平地春，夫春不得不云云。',64,'全唐诗/poet.song.21000.json','["有客常輕平地春，夫春不得不云云。", "能安陋巷無如我，既上高樓還憶君。", "滿眼雲林都是綠，萬家煙瓦半來新。", "憑欄須是心無事，誰是憑欄無事人。"]'),
('545419c6-dedb-481d-a275-ac5db076cddd','所失吟','邵雍','宋','宋诗','song-poetry','','[]','所失彌多所得微，中間贏得一歔欷。',64,'全唐诗/poet.song.21000.json','["所失彌多所得微，中間贏得一歔欷。", "人榮人悴乃常理，花謝花開何足追。", "偶爾相逢却相別，乍然同喜又同悲。", "只消照破都無事，何必區區更辨爲。"]'),
('f2246261-6ae4-487e-a529-b15b2a72327e','插花吟','邵雍','宋','宋诗','song-poetry','','[]','頭上花枝照酒巵，酒巵中有好花枝。',64,'全唐诗/poet.song.21000.json','["頭上花枝照酒巵，酒巵中有好花枝。", "身經兩世太平日，眼見四朝全盛時。", "況復筋骸粗康健，那堪時節正芳菲。", "酒涵花影紅光溜，爭忍花前不醉歸。"]'),
('426069f6-a710-461c-af59-b7c616e741d2','閑居吟','邵雍','宋','宋诗','song-poetry','','[]','閑居須是洛中居，天下閑居皆莫如。',64,'全唐诗/poet.song.21000.json','["閑居須是洛中居，天下閑居皆莫如。", "文物四主賢俊地，山川千古帝王都。", "絕奇花畔持芳醑，最軟草間移小車。", "只有堯夫負親舊，交親殊不負堯夫。"]'),
('f4306d0b-c300-421e-a428-0ac3feebf45a','依韻和張子堅太博','邵雍','宋','宋诗','song-poetry','','[]','八載相逢恨未平，如何別酒又還傾。',64,'全唐诗/poet.song.21000.json','["八載相逢恨未平，如何別酒又還傾。", "雖慙坦率珠多纇，却識清和玉有聲。", "處世當爲天下士，賞花須是洛陽城。", "也知今古真男子，造化功夫不易生。"]'),
('2ffef3c9-6765-40e7-b552-be3adb5611c2','還鞠十二著作見示共城詩卷','邵雍','宋','宋诗','song-poetry','','[]','寫像丹青未易偕，丹青難寫像情懷。',64,'全唐诗/poet.song.21000.json','["寫像丹青未易偕，丹青難寫像情懷。", "覽君十首詩三遍，勝我再遊鄉一迴。", "故國不知新想望，家山如見舊崔嵬。", "功名時事人休問，只有兩行清淚揩。"]'),
('fb60ac2f-08f6-4dff-8bb2-eb50f0ea1859','樂物吟','邵雍','宋','宋诗','song-poetry','','[]','日月星辰天之明，耳目口鼻人之靈。',64,'全唐诗/poet.song.21000.json','["日月星辰天之明，耳目口鼻人之靈。", "皇王帝伯由之生，天意不遠人之情。", "飛走草木類既別，士農工商品自成。", "安得歲豐時長平，樂與萬物同其榮。"]'),
('8bf72330-dc13-4e0c-bfba-d33f6912cc35','喜春吟','邵雍','宋','宋诗','song-poetry','','[]','春至已將詩探伺，春歸更用酒追尋。',64,'全唐诗/poet.song.21000.json','["春至已將詩探伺，春歸更用酒追尋。", "酒因春至春歸飲，詩爲花開化謝吟。", "花謝花開詩屢作，春歸春至酒頻斟。", "情多不是强年少，和氣衝心何可任。"]'),
('78088901-951f-49f6-ab3c-7d6f950e66e4','暮春吟','邵雍','宋','宋诗','song-poetry','','[]','多情潘佑羨楊花，出入千家復萬家。',64,'全唐诗/poet.song.21000.json','["多情潘佑羨楊花，出入千家復萬家。", "少日壯心都失去，老年新事不知佗。", "詩中罪過人多恕，酒裏功勞我自誇。", "猶有一般牢落處，交親太半在天涯。"]'),
('981f3f69-3fa5-4244-ba7a-4926a3739651','和王中美大卿致政二首  其一','邵雍','宋','宋诗','song-poetry','','[]','等候人間七十年，便如平子賦歸田。',64,'全唐诗/poet.song.21000.json','["等候人間七十年，便如平子賦歸田。", "知時所得誠多矣，養志其誰曰不然。", "況有林泉情悅樂，却無官守事拘牽。", "小車近日曾馳謁，正值夫君春晝眠。"]'),
('d5fd5cce-2994-406d-89ea-d238ec66adcb','和王中美大卿致政二首  其二','邵雍','宋','宋诗','song-poetry','','[]','自古有才思奮飛，夫君何故獨知時。',64,'全唐诗/poet.song.21000.json','["自古有才思奮飛，夫君何故獨知時。", "平生懷抱未少屈，盛世掛冠良得宜。", "入格柳挼風細細，壓春花笑日遲遲。", "傳呼震地門前過，更不令人問是誰。"]'),
('ac3341d4-d2b8-4c7d-93b3-b7e44044ff64','和北京王郎中見訪留詩','邵雍','宋','宋诗','song-poetry','','[]','車從賞春來北京，耿君先期已馳情。',64,'全唐诗/poet.song.21000.json','["車從賞春來北京，耿君先期已馳情。", "此時殞霜柰何重，今歲花開徒有聲。", "既辱佳章仍墜刺，寧無累句代通名。", "天之才美應自惜，料得不爲時虛生。"]'),
('47ea3148-9f55-45b8-bf45-a360d7084102','喜樂吟','邵雍','宋','宋诗','song-poetry','','[]','生身有五樂，居洛有五喜。',48,'全唐诗/poet.song.21000.json','["生身有五樂，居洛有五喜。", "人多輕習常，殊不以爲事。", "吾才無所長，吾識無所紀。", "其心之泰然，柰何人了此。"]'),
('13e16d0b-3ac6-4fdd-b5d5-f246dd7e07fc','歡喜吟','邵雍','宋','宋诗','song-poetry','','[]','歡喜又歡喜，喜歡更喜歡。',48,'全唐诗/poet.song.21000.json','["歡喜又歡喜，喜歡更喜歡。", "吉士爲我友，好景爲我觀。", "美酒爲我飲，美食爲我餐。", "此身生長老，盡在太平間。"]'),
('c2093c49-b594-449d-89ac-d024fdb52b88','天道吟','邵雍','宋','宋诗','song-poetry','','[]','天道不難知，人情未易窺。',48,'全唐诗/poet.song.21000.json','["天道不難知，人情未易窺。", "雖聞言語處，更看作爲時。", "隠几功夫大，揮戈事業卑。", "春秋頼乘興，出用小車兒。"]'),
('ff576f92-9a9c-4502-8653-eb963a6e8fa7','室吟','邵雍','宋','宋诗','song-poetry','','[]','一室可容身，四時長有春。',48,'全唐诗/poet.song.21000.json','["一室可容身，四時長有春。", "何嘗無美酒，未始絕佳賓。", "洞裏賞花者，天邊泛月人。", "相逢應有語，笑我太因循。"]'),
('1926a964-6538-4447-a3d4-06cf5fc95fc9','依韻和君實端明洛濱獨步  其一','邵雍','宋','宋诗','song-poetry','','[]','冠蓋紛紛塞九衢，聲名相軋在前呼。',32,'全唐诗/poet.song.21000.json','["冠蓋紛紛塞九衢，聲名相軋在前呼。", "獨君都不將爲事，始信人間有丈夫。"]'),
('9c41a69b-0bb6-4bff-8f96-cf1a9584b76d','依韻和君實端明洛濱獨步  其二','邵雍','宋','宋诗','song-poetry','','[]','風背河聲近亦微，斜陽淡泊隔雲依。',32,'全唐诗/poet.song.21000.json','["風背河聲近亦微，斜陽淡泊隔雲依。", "一雙白鷺來煙外，將下沙頭又却飛。"]'),
('c1cd1622-4625-4c6b-b94d-fbb3123cd4bf','雨後天津獨步','邵雍','宋','宋诗','song-poetry','','[]','洛陽宮殿鏁晴煙，唐漢以來書可傳。',32,'全唐诗/poet.song.21000.json','["洛陽宮殿鏁晴煙，唐漢以來書可傳。", "多少升沉都不見，空餘四面舊出川。"]'),
('1adf1baa-3ac4-4d2f-a139-ca84d878627d','春色','邵雍','宋','宋诗','song-poetry','','[]','去歲春歸留不住，今年春色來何處。',32,'全唐诗/poet.song.21000.json','["去歲春歸留不住，今年春色來何處。", "洛陽處處是桃源，小車漸轉東街去。"]'),
('f890c76a-cdcf-4db7-9a81-90eedbd81cfd','太平吟','邵雍','宋','宋诗','song-poetry','','[]','天下太平日，人生安樂時。',24,'全唐诗/poet.song.21000.json','["天下太平日，人生安樂時。", "更逢花爛漫，爭忍不開眉。"]'),
('693f9ea5-312f-4e46-ac71-0ead2e8222f5','禁煙留題錦幈山下四首  其一','邵雍','宋','宋诗','song-poetry','','[]','滿川桃李弄芳妍，不忍重爲風所殘。',32,'全唐诗/poet.song.21000.json','["滿川桃李弄芳妍，不忍重爲風所殘。", "忍使一年春遂去，儘憑高處與盤桓。"]'),
('f89b51b3-4b1d-4b2d-96ce-953bf8d68635','禁煙留題錦幈山下四首  其二','邵雍','宋','宋诗','song-poetry','','[]','寒食風煙錦幈下，凭高把酒興何如。',32,'全唐诗/poet.song.21000.json','["寒食風煙錦幈下，凭高把酒興何如。", "滿川桃李方妍媚，不忍重爲風破除。"]'),
('929469af-1d54-4981-bd93-5174e6f77c70','禁煙留題錦幈山下四首  其三','邵雍','宋','宋诗','song-poetry','','[]','無涯桃李待清明，經歲方能開得成。',32,'全唐诗/poet.song.21000.json','["無涯桃李待清明，經歲方能開得成。", "不念化工曾著力，狂風何故苦相凌。"]'),
('d4a2f723-257b-4f3c-9584-bce1a480b25c','禁煙留題錦幈山下四首  其四','邵雍','宋','宋诗','song-poetry','','[]','春半花開百萬般，東風近日惡摧殘。',32,'全唐诗/poet.song.21000.json','["春半花開百萬般，東風近日惡摧殘。", "可憐桃李性溫厚，吹盡都無一句言。"]'),
('59342353-d86e-43ab-837c-3e5e85924c8b','兩歲錦幈之遊不克見鄭令因以寄之','邵雍','宋','宋诗','song-poetry','','[]','歲歲羣芳正爛開，錦幈山下賞春來。',32,'全唐诗/poet.song.21000.json','["歲歲羣芳正爛開，錦幈山下賞春來。", "兩年不得陪山躅，洞裏仙人出未迴。"]'),
('de39ca5f-29b3-4574-92c2-450127f4f5e3','東軒前添色牡丹一株開二十四枝成兩絕呈諸公  其一','邵雍','宋','宋诗','song-poetry','','[]','牡丹一株開絕倫，二十四枝嬌娥顰。',32,'全唐诗/poet.song.21000.json','["牡丹一株開絕倫，二十四枝嬌娥顰。", "天下唯洛十分春，邵家獨得七八分。"]'),
('70f86f48-5d9d-4e2d-9fee-b63eb26b73aa','東軒前添色牡丹一株開二十四枝成兩絕呈諸公  其二','邵雍','宋','宋诗','song-poetry','','[]','牡丹一株開絕奇，二十四枝嬌娥圍。',32,'全唐诗/poet.song.21000.json','["牡丹一株開絕奇，二十四枝嬌娥圍。", "滿洛城人都不知，邵家獨占春風時。"]'),
('eafa3232-a9e2-4aaf-99ad-c2ce95861c67','花時阻雨不出','邵雍','宋','宋诗','song-poetry','','[]','三月洛城春半時，鞦韆未拆楊花飛。',32,'全唐诗/poet.song.21000.json','["三月洛城春半時，鞦韆未拆楊花飛。", "小車不出閑春泥，亂紅翻處流鶑啼。"]'),
('dff482b4-0932-44cd-a5f1-4e6ccfe7c4b7','安樂窩中吟  其一','邵雍','宋','宋诗','song-poetry','','[]','安樂窩中職分脩，分脩之外更何求。',128,'全唐诗/poet.song.21000.json','["安樂窩中職分脩，分脩之外更何求。", "滿天下士情能接，遍洛陽園身可遊。", "行己當行誠盡處，看人莫看力生頭。", "因思平地春言語，使我嘗登百尺樓。", "安樂窩中事事無，唯存一卷伏羲書。", "倦時就枕不必睡，忺後携筇任所趨。", "淮備點茶收露水，隄防合藥種魚蘇。", "苟非先聖開蒙悋，幾作人間淺丈夫。"]'),
('1f0c1dc1-13dd-4126-b825-97dc9bb5d680','安樂窩中吟  其二','邵雍','宋','宋诗','song-poetry','','[]','安樂窩中弄舊編，舊編將絕又重聯。',64,'全唐诗/poet.song.21000.json','["安樂窩中弄舊編，舊編將絕又重聯。", "燈前燭下三千日，水畔花間二十年。", "有主山河難占籍，無爭風月任收權。", "閑吟閑咏人休問，此箇功夫世不傳。"]'),
('f1bf1539-15a4-4d5c-83d3-127ac8876054','安樂窩中吟  其三','邵雍','宋','宋诗','song-poetry','','[]','安樂窩中萬戶侯，良辰美景忍虛休。',64,'全唐诗/poet.song.21000.json','["安樂窩中萬戶侯，良辰美景忍虛休。", "已曾得手春深日，更欲披衣年老頭。", "曉露重時花滿檻，暖醅浮處酒盈甌。", "聖人喫緊些兒事，又省工夫又省憂。"]'),
('e80506a4-4d29-41bc-8a18-1b5ca7faacd1','安樂窩中吟  其四','邵雍','宋','宋诗','song-poetry','','[]','安樂窩中春夢迴，略無塵事可裝懷。',64,'全唐诗/poet.song.21000.json','["安樂窩中春夢迴，略無塵事可裝懷。", "輕風一霎座中過，安樂窩中天外來。", "日影轉時從杖屨，花陰交處傍樽罍。", "人間未若吾鄉好，又況吾鄉多美才。"]'),
('ff9118e3-a9ab-47c7-909d-7ddfd0001dcc','安樂窩中吟  其五','邵雍','宋','宋诗','song-poetry','','[]','安樂窩中春不虧，山翁出入小車兒。',64,'全唐诗/poet.song.21000.json','["安樂窩中春不虧，山翁出入小車兒。", "水邊平轉綠楊岸，花外就移芳草堤。", "明快眼看三月景，康强身歷四朝時。", "鳳凰樓下天津畔，仰面迎風倒載歸。"]'),
('8b2aceac-4f32-4fb9-bc6d-b606e08cf8ac','安樂窩中吟  其六','邵雍','宋','宋诗','song-poetry','','[]','安樂窩中三月期，老不纔會惜芳菲。',64,'全唐诗/poet.song.21000.json','["安樂窩中三月期，老不纔會惜芳菲。", "自知一賞有分付，誰讓黄金無孑遺。", "美酒飲教微醉後，好花看到半開時。", "這般意思難名狀，只恐人間都未知。"]'),
('30237f08-f5a6-4b7f-b98a-1f74fb5dfae7','安樂窩中吟  其七','邵雍','宋','宋诗','song-poetry','','[]','安樂窩中春暮時，閉門慵坐客來稀。',64,'全唐诗/poet.song.21000.json','["安樂窩中春暮時，閉門慵坐客來稀。", "蕭蕭微雨竹間霽，嘒嘒翠禽花上飛。", "好景盡將詩記錄，歡情須用酒維持。", "自餘身外無窮事，皆可掉頭稱不知。"]'),
('49105150-a91d-45e5-91ca-e1637a4d1586','安樂窩中吟  其八','邵雍','宋','宋诗','song-poetry','','[]','安樂窩中甚不貧，中間有榻可容身。',64,'全唐诗/poet.song.21000.json','["安樂窩中甚不貧，中間有榻可容身。", "儒風一變至於道，和氣四時長若春。", "日月作明明主日，人言成信信由人。", "唯人與日不相遠，過此何嘗更語真。"]'),
('3e1901a6-6701-454a-ba06-637613a533fc','安樂窩中吟  其九','邵雍','宋','宋诗','song-poetry','','[]','安樂窩中設不安，略行湯劑自能痊。',64,'全唐诗/poet.song.21000.json','["安樂窩中設不安，略行湯劑自能痊。", "居常無病不服藥，就使有災宜俟天。", "理到昧時須索講，情於盡處更何言。", "自餘虛費閑思慮，都可易之爲晝眠。"]'),
('9c10aed4-8311-46b6-a3de-347c8f416324','安樂窩中吟  其一○','邵雍','宋','宋诗','song-poetry','','[]','安樂窩中春欲歸，春歸忍賦送春詩。',64,'全唐诗/poet.song.21000.json','["安樂窩中春欲歸，春歸忍賦送春詩。", "雖然春老難牽復，却有夏初能就移。", "飲酒莫教成酩酊，賞花慎勿至離披。", "人能知得此般事，焉有閑愁到兩眉。"]'),
('6961cbbe-fb12-4e25-9276-7de72ca38837','安樂窩中吟  其一一','邵雍','宋','宋诗','song-poetry','','[]','生爲男子偶昌辰，安樂窩中富貴身。',64,'全唐诗/poet.song.21000.json','["生爲男子偶昌辰，安樂窩中富貴身。", "大字寫詩誇壯健，小盃飲酒惜輕醇。", "山川澄凈初經雨，草木暄妍正遇春。", "造化功夫精妙處，都宜分付與閑人。"]'),
('d3f4f165-a082-4c6b-8f8f-c3ddcbf03081','安樂窩中吟  其一二','邵雍','宋','宋诗','song-poetry','','[]','安樂窩中雖不拘，不拘終不失吾儒。',64,'全唐诗/poet.song.21000.json','["安樂窩中雖不拘，不拘終不失吾儒。", "輕醇酒用小盞飲，豪壯詩將大字書。", "花木暄妍春雨後，山川澄淨九秋餘。", "閑中意思長多少，無忝人間一丈夫。"]'),
('ac3b1431-3068-46ec-a33c-50a93ba5c5e7','食梨吟','邵雍','宋','宋诗','song-poetry','','[]','願君莫愛金花梨，願君須愛紅消梨。',64,'全唐诗/poet.song.21000.json','["願君莫愛金花梨，願君須愛紅消梨。", "金花紅消兩般味，一般顔色如烟脂。", "紅消食之甘如飴，金花食之先顰眉。", "似此誤人事不少，未食之前宜辨之。"]'),
('50d46647-f5a0-4754-bc3c-178e12e1fcc4','依韻答安之少卿','邵雍','宋','宋诗','song-poetry','','[]','疊巘如幈四面開，可堪虛使亂雲堆。',64,'全唐诗/poet.song.21000.json','["疊巘如幈四面開，可堪虛使亂雲堆。", "已曾同賞花無限，須約共遊山幾迴。", "未老秋光詩擁筆，乍凉天氣酒盈盃。", "輕風早是得人喜，更向芰荷深處來。"]'),
('a4099b50-969c-4657-8c1f-5e0d63d8305f','上巳觀花思友人','邵雍','宋','宋诗','song-poetry','','[]','上巳觀花花意穠，今年正與昔年同。',32,'全唐诗/poet.song.21000.json','["上巳觀花花意穠，今年正與昔年同。", "當時同賞知何處，把酒猶能對遠風。"]'),
('cdb59bdc-7863-4aa3-9af5-0f915fc09556','戲呈王郎中','邵雍','宋','宋诗','song-poetry','','[]','近年好花人輕之，東君惡怒人不知。',64,'全唐诗/poet.song.21000.json','["近年好花人輕之，東君惡怒人不知。", "直與增價一百倍，滿洛城春都買歸。", "一株二十有四枝，枝枝皆有傾城姿。", "又恐冷地狂風吹，盛時都與籍入詩。"]'),
('6d998e4e-a2d4-47b5-b9ae-41d875c32ba7','流鶑吟','邵雍','宋','宋诗','song-poetry','','[]','遷喬固有之，出谷未多時。',72,'全唐诗/poet.song.21000.json','["遷喬固有之，出谷未多時。", "正嫩簧爲舌，初新金作衣。", "替花言灼灼，代柳說依依。", "柳外晚猶囀，花前曉又啼。", "啼多因雨過，囀少爲春歸。", "莫遣行人聽，行人路正迷。"]'),
('77096a4f-d1a6-409c-8a9e-773a3bfeddb4','善賞花吟','邵雍','宋','宋诗','song-poetry','','[]','人不善賞花，只愛花之貌。',48,'全唐诗/poet.song.21000.json','["人不善賞花，只愛花之貌。", "人或善賞花，只愛花之妙。", "花貌在顔色，顔色人可效。", "花妙在精神，精神人莫造。"]'),
('666eafa5-da6f-4897-8785-75935f4a7ca3','善飲酒吟','邵雍','宋','宋诗','song-poetry','','[]','人不善飲酒，唯喜飲之多。',48,'全唐诗/poet.song.21000.json','["人不善飲酒，唯喜飲之多。", "人或善飲酒，唯喜飲之和。", "飲多成酩酊，酩酊身遂疴。", "飲和成醺酣，醺酣顔遂酡。"]'),
('5c49aa6c-896e-480e-af94-14a847afe47e','省事吟','邵雍','宋','宋诗','song-poetry','','[]','慮少夢自少，言稀過亦稀。',48,'全唐诗/poet.song.21000.json','["慮少夢自少，言稀過亦稀。", "簾垂知日永，柳靜覺風微。", "但見花開謝，不聞人是非。", "何須尋洞府，度歲也應遲。"]'),
('ceec9978-e255-48cc-8b8e-daeac11e4107','一春吟','邵雍','宋','宋诗','song-poetry','','[]','一春九十日，風雨占幾半。',24,'全唐诗/poet.song.21000.json','["一春九十日，風雨占幾半。", "花好不成觀，心狂未能按。"]'),
('a3617e36-3470-46df-a3d7-aee9afa26aab','舉世吟','邵雍','宋','宋诗','song-poetry','','[]','舉世自紛紛，誰爲無事人。',24,'全唐诗/poet.song.21000.json','["舉世自紛紛，誰爲無事人。", "吾生獨何幸，卧看洛陽春。"]'),
('0aa6f7d0-e56d-4043-887e-dc70f277af29','春水吟','邵雍','宋','宋诗','song-poetry','','[]','春水淥成波，成波無柰何。',24,'全唐诗/poet.song.21000.json','["春水淥成波，成波無柰何。", "難將染佗物，止可染輕羅。"]'),
('24e4b30a-6448-4e7b-b7a2-3497a75d275e','春雨吟','邵雍','宋','宋诗','song-poetry','','[]','春雨細如絲，如絲霢霂時。',24,'全唐诗/poet.song.21000.json','["春雨細如絲，如絲霢霂時。", "如何一霶霈，萬物盡熙熙。"]'),
('214132d3-1195-4a87-9510-f2b2765c9a57','可惜吟','邵雍','宋','宋诗','song-poetry','','[]','可惜熙熙一片春，不多時節覓無因。',32,'全唐诗/poet.song.21000.json','["可惜熙熙一片春，不多時節覓無因。", "眼前園苑知何限，只見鶑啼不見人。"]'),
('d19d3509-0c2c-4c2a-8aac-3c80f53bdb90','簪花吟','邵雍','宋','宋诗','song-poetry','','[]','簪花猶且强年少，訴酒固非佯小心。',32,'全唐诗/poet.song.21000.json','["簪花猶且强年少，訴酒固非佯小心。", "花好酒嘉情更好，柰何明日病還深。"]'),
('6de7640a-b35b-4d3d-a69c-60a5f841c4c3','春去吟','邵雍','宋','宋诗','song-poetry','','[]','春去休驚晚，夏來還喜初。',24,'全唐诗/poet.song.21000.json','["春去休驚晚，夏來還喜初。", "殘芳雖有在，得似錄陰無。"]'),
('be3a993a-a52a-4b09-bf86-0c07f14cf1bd','和大尹李君錫龍圖留別詩','邵雍','宋','宋诗','song-poetry','','[]','多情大尹辭春去，正是羣芳爛漫時。',32,'全唐诗/poet.song.21000.json','["多情大尹辭春去，正是羣芳爛漫時。", "自古英豪重恩意，羣芳慎勿便離披。"]'),
('4390ada1-145c-41c5-a463-800b8960b8e9','答李希淳屯田三首  其一','邵雍','宋','宋诗','song-poetry','','[]','去歲嘗蒙遠寄詩，當時已歎友朋希。',32,'全唐诗/poet.song.21000.json','["去歲嘗蒙遠寄詩，當時已歎友朋希。", "如今存者殆非半，不縱歡遊待幾時。"]'),
('3d5ce996-ccc9-458f-9ab8-4ed15cc34149','答李希淳屯田三首  其二','邵雍','宋','宋诗','song-poetry','','[]','竹間水際情懷好，月下風前意思多。',32,'全唐诗/poet.song.21000.json','["竹間水際情懷好，月下風前意思多。", "洛社過從無事日，非吾數輩更誰何。"]'),
('2db30abe-6a27-4384-a8cd-e0fb6d5ae271','答李希淳屯田三首  其三','邵雍','宋','宋诗','song-poetry','','[]','胸中日月時舒慘，筆下風雲旋合離。',32,'全唐诗/poet.song.21000.json','["胸中日月時舒慘，筆下風雲旋合離。", "老去無成尚如此，不知成後更何爲。"]'),
('285b68b1-1cd7-45ec-accb-85139bd58d6f','箋年老逢春八首 年老逢春春莫疑','邵雍','宋','宋诗','song-poetry','','[]','箋云：物理窺開後，人情照破時。',27,'全唐诗/poet.song.21000.json','["箋云：物理窺開後，人情照破時。", "且無形可見，只有意能知。"]'),
('7da331f7-d1de-4d26-a86c-0b411d0633e1','箋年老逢春八首 老年纔會惜芳菲','邵雍','宋','宋诗','song-poetry','','[]','箋云：一歲正榮處，三春特盛時。',27,'全唐诗/poet.song.21000.json','["箋云：一歲正榮處，三春特盛時。", "是花堪愛惜，況見好花枝。"]'),
('3f8b30ec-54ba-47e1-b022-bc8452e5bb65','箋年老逢春八首 自知一賞有分付','邵雍','宋','宋诗','song-poetry','','[]','箋云：羣卉爭妍處，奇花獨異時。',27,'全唐诗/poet.song.21000.json','["箋云：羣卉爭妍處，奇花獨異時。", "東君深意思，亦恐要人知。"]'),
('54a40ce3-0396-4fb5-8e6d-efc25348d907','箋年老逢春八首 誰讓萬金無孑遺','邵雍','宋','宋诗','song-poetry','','[]','箋云：白日偏催處，黄金欲盡時。',27,'全唐诗/poet.song.21000.json','["箋云：白日偏催處，黄金欲盡時。", "侈心都用了，始得一開眉。"]'),
('31604212-345d-4e84-8f71-7a3c20d1fb47','箋年老逢春八首 美酒飲教微醉後','邵雍','宋','宋诗','song-poetry','','[]','箋云：甕頭噴液處，盞面起花時。',27,'全唐诗/poet.song.21000.json','["箋云：甕頭噴液處，盞面起花時。", "有客來相訪，通名曰伏羲。"]'),
('3249b5b9-23b5-4ef4-8b3a-5b503edf9fb9','箋年老逢春八首 好花看到半開時','邵雍','宋','宋诗','song-poetry','','[]','箋云：風輕如笑處，露重似啼時。',27,'全唐诗/poet.song.21000.json','["箋云：風輕如笑處，露重似啼時。", "只向笑啼處，濃香惹滿衣。"]'),
('fe246d4a-dab5-4443-a735-0816e624cda8','箋年老逢春八首 這般意思難名狀','邵雍','宋','宋诗','song-poetry','','[]','箋云：陰陽初感處，天地未分時。',27,'全唐诗/poet.song.21000.json','["箋云：陰陽初感處，天地未分時。", "言語既難到，丹青何處施。"]'),
('3888ae62-aa72-4a53-963c-9191cf02da51','箋年老逢春八首 只恐人間都未知','邵雍','宋','宋诗','song-poetry','','[]','箋云：酒到醺酣處，花當爛漫時。',27,'全唐诗/poet.song.21000.json','["箋云：酒到醺酣處，花當爛漫時。", "醺酣歸酩酊，爛漫入離披。"]'),
('afc3f4c1-d5f1-4704-86a2-7b079138ff9d','謝彥國相公和詩用醉和風雨夜深歸','邵雍','宋','宋诗','song-poetry','','[]','道堂閑話儘多時，塵外盃觴不浪飛。',32,'全唐诗/poet.song.21000.json','["道堂閑話儘多時，塵外盃觴不浪飛。", "初上小車人已靜，醉和風雨夜深歸。"]'),
('008f399c-d62d-41d3-b3f3-500d94c0fdd0','謝君實端明用只將花卉記冬春','邵雍','宋','宋诗','song-poetry','','[]','有時自問自家身，莫是羲皇已上人。',32,'全唐诗/poet.song.21000.json','["有時自問自家身，莫是羲皇已上人。", "日往月來都不記，只將花卉記冬春。"]'),
('290cf8a6-15b1-4e0c-be7e-f700597a744f','謝君貺宣徽用少微今已應星文','邵雍','宋','宋诗','song-poetry','','[]','一字詩中義未分，少微今已應星文。',32,'全唐诗/poet.song.21000.json','["一字詩中義未分，少微今已應星文。", "閑人早是無憑據，更與閑人開後門。"]'),
('a9e524fb-3045-4c37-b330-b85153f80281','謝安之少卿用始知安是道梯階','邵雍','宋','宋诗','song-poetry','','[]','窩名安樂直堪咍，臂痛頭風接續來。',32,'全唐诗/poet.song.21000.json','["窩名安樂直堪咍，臂痛頭風接續來。", "恰見安之便安樂，始知安是道梯階。"]'),
('e704cfb2-ff23-4ab6-b815-82631fac90e5','謝開叔司封用無事無求得最多','邵雍','宋','宋诗','song-poetry','','[]','客問人間事若何，堯夫對曰不知佗。',32,'全唐诗/poet.song.21000.json','["客問人間事若何，堯夫對曰不知佗。", "居林之下行林下，無事無求得最多。"]'),
('b9f3d01d-1eaf-4829-ad4a-0e12a48c2493','謝伯淳察院用先生不是打乖人','邵雍','宋','宋诗','song-poetry','','[]','經綸事業須才者，燮理功夫有巨臣。',32,'全唐诗/poet.song.21000.json','["經綸事業須才者，燮理功夫有巨臣。", "安樂窩中閑偃仰，焉知不是打乖人。"]'),
('ab752cee-db65-4d73-997c-f87823161fee','自謝用此樂直從天外來','邵雍','宋','宋诗','song-poetry','','[]','得自苦時終入苦，來從哀處卒歸哀。',32,'全唐诗/poet.song.21000.json','["得自苦時終入苦，來從哀處卒歸哀。", "既非哀苦中間得，此樂直從天外來。"]'),
('78cc37e7-4c70-4e02-8754-9f9233ed9f8c','別謝彥國相公三首  其一','邵雍','宋','宋诗','song-poetry','','[]','和詩韓國老，見比以宣尼。',48,'全唐诗/poet.song.21000.json','["和詩韓國老，見比以宣尼。", "引彼返魯事，指予來西畿。", "日星功共大，麋鹿分同微。", "華衮承褒借，將何答所知。"]'),
('7f11db56-3fd4-4fd3-9c0d-cda227d70c0b','別謝彥國相公三首  其二','邵雍','宋','宋诗','song-poetry','','[]','仲尼天縱自誠明，造化功夫發得成。',32,'全唐诗/poet.song.21000.json','["仲尼天縱自誠明，造化功夫發得成。", "見比當初歸魯事，堯夫才業若爲情。"]'),
('75939d02-bd60-4496-a293-92e14f9d46ed','別謝彥國相公三首  其三','邵雍','宋','宋诗','song-poetry','','[]','嘗走狂詩到座前，座前仍是洞中仙。',32,'全唐诗/poet.song.21000.json','["嘗走狂詩到座前，座前仍是洞中仙。", "無涯風月供才思，清潤何人敢比肩。"]'),
('d13e9d9b-ec96-42c6-b997-c013cfe90fbe','別謝君實端明','邵雍','宋','宋诗','song-poetry','','[]','曹王八斗才，今日爲余催。',48,'全唐诗/poet.song.21000.json','["曹王八斗才，今日爲余催。", "錦繡佳章裏，芝蘭秀句開。", "煩痾熸軀體，溽暑爍樓臺。", "宜把君詩諷，清風當自來。"]'),
('01d98b22-4dd5-4f6f-8aea-f94112197c69','大字吟','邵雍','宋','宋诗','song-poetry','','[]','詩成半醉正陶陶，更用如椽大筆抄。',64,'全唐诗/poet.song.21000.json','["詩成半醉正陶陶，更用如椽大筆抄。", "儘得意時仍放手，到凝情處略濡毫。", "魯陽却日功猶淺，宗慤乘風志未高。", "寫出太平難狀意，任佗天下頌功勞。"]'),
('ac41b41f-f3c5-4d36-aa9b-d48cf750b80c','教子吟','邵雍','宋','宋诗','song-poetry','','[]','爲人能了自家身，千萬人中有一人。',64,'全唐诗/poet.song.21000.json','["爲人能了自家身，千萬人中有一人。", "雖用知如未知說，在乎行與不行分。", "該通始謂才中秀，傑出方名席上珍。", "善惡一何相去遠，也由資性也由勤。"]'),
('285a9be2-550b-478b-807d-ac56d861753c','臂痛吟','邵雍','宋','宋诗','song-poetry','','[]','先苦頭風已病軀，新添臂痛又何如。',64,'全唐诗/poet.song.21000.json','["先苦頭風已病軀，新添臂痛又何如。", "無妨把盞只妨拜，雖廢梳頭未廢書。", "不向醫方求效驗，唯將談笑且消除。", "大凡物老須生病，人老何由不病乎。"]'),
('797e0c7f-3077-46b3-ba19-b7b155872c95','世上吟','邵雍','宋','宋诗','song-poetry','','[]','世上偷閑始得閑，我生長在不忙間。',64,'全唐诗/poet.song.21000.json','["世上偷閑始得閑，我生長在不忙間。", "光陰有限同歸老，風月無涯可慰顔。", "坐卧遶身唯水竹，登臨滿目但雲山。", "醉眠只就花陰下，轉破花陰夢始還。"]'),
('bdaf39a7-e108-4784-bcc8-000886d5512a','逸書吟','邵雍','宋','宋诗','song-poetry','','[]','丹山誰道鳳爲巢，事下吾能見九苞。',64,'全唐诗/poet.song.21000.json','["丹山誰道鳳爲巢，事下吾能見九苞。", "逸句得時如虎變，大篇成處若神交。", "千端蜀錦新番樣，萬樹春華暖弄稍。", "天馬無蹤周八極，但臨風月鐙相敲。"]'),
('266c7179-665c-48b1-b938-f1f1e4ad6996','旋風吟二首  其一','邵雍','宋','宋诗','song-poetry','','[]','安有太平人不平，人心平處固無爭。',64,'全唐诗/poet.song.21000.json','["安有太平人不平，人心平處固無爭。", "棋中機械不願看，琴裏語言時喜聽。", "少日掛心唯帝典，老年留意只羲經。", "自知別得收功處，松桂隆冬始見青。"]'),
('a9b2b1e5-c9c0-419b-9b89-70dc3b28528b','旋風吟二首  其二','邵雍','宋','宋诗','song-poetry','','[]','松桂隆冬始見青，蒿萊盛夏亦能榮。',64,'全唐诗/poet.song.21000.json','["松桂隆冬始見青，蒿萊盛夏亦能榮。", "光陰去後繩難繫，利害在前人必爭。", "萬事莫於疑處動，一身常向吉中行。", "人心相去無多遠，安有太平人不平。"]'),
('2b7820f1-6eab-473c-a262-2fff44014d56','又二首  其一','邵雍','宋','宋诗','song-poetry','','[]','近日衰軀有病侵，如何醫藥不求尋。',64,'全唐诗/poet.song.21000.json','["近日衰軀有病侵，如何醫藥不求尋。", "軒前密葉自成幄，砌下黄花空散金。", "閑看蜜蜂收蜜意，靜觀巢燕壘巢心。", "非關天下知音少，自是堯夫不善琴。"]'),
('2aca770d-6251-4e59-8a5f-2dd36b052bc1','又二首  其二','邵雍','宋','宋诗','song-poetry','','[]','自是堯夫不善琴，非關天下少知音。',64,'全唐诗/poet.song.21000.json','["自是堯夫不善琴，非關天下少知音。", "老年難做少年事，年少不知年老心。", "將養精神便靜坐，調停意思喜清吟。", "如何醫藥不尋訪，近日衰軀有病侵。"]'),
('cb398bca-8f4b-4f94-a250-b405b1f65c04','頭風吟','邵雍','宋','宋诗','song-poetry','','[]','近日頭風不奈何，未妨談笑與高歌。',64,'全唐诗/poet.song.21000.json','["近日頭風不奈何，未妨談笑與高歌。", "人才相去不甚遠，事體所爭能許多。", "閉目面前都是暗，開懷天外更無佗。", "若由智數經營得，大有英雄善揣摩。"]'),
('7a4b5850-e9b0-4397-b19b-929fe919866e','答客吟','邵雍','宋','宋诗','song-poetry','','[]','說者從來太過乎，道須能卷又能舒。',64,'全唐诗/poet.song.21000.json','["說者從來太過乎，道須能卷又能舒。", "人間好事不常有，天下奇才何處無。", "年近從心唯策杖，詩逢得意便操觚。", "快心亦恐詩拘束，更把狂詩大字書。"]'),
('e0d3e78a-21b1-431d-9510-71460b935246','老去吟  其一','邵雍','宋','宋诗','song-poetry','','[]','老去無成不入時，中年養病只吟詩。',64,'全唐诗/poet.song.21000.json','["老去無成不入時，中年養病只吟詩。", "因乘意思要舒放，肯把語言生事治。", "世上閑愁都一致，人間何務更能爲。", "携筇晚步天津畔，爲報沙鷗慎勿飛。"]'),
('53530207-bfa9-4274-a9aa-70db80d25dcf','老去吟  其二','邵雍','宋','宋诗','song-poetry','','[]','行年六十有三歲，二十五年居洛陽。',64,'全唐诗/poet.song.21000.json','["行年六十有三歲，二十五年居洛陽。", "林靜城中得山景，池平坐上見江鄉。", "賞花長被盃盤苦，愛月屢爲風露傷。", "看了太平無限好，此身老去又何妨。"]'),
('7ed158cb-9c51-4eee-af9d-3da5e1755524','依韻和王安之判監少卿','邵雍','宋','宋诗','song-poetry','','[]','人行一善已爲優，何況夫君百行修。',64,'全唐诗/poet.song.21000.json','["人行一善已爲優，何況夫君百行修。", "曩日慈闈貪眷戀，多年官路不追求。", "官纔少列辜清德，職異上庠尊白頭。", "洛社逾時阻相見，許多歡意却還休。"]'),
('6be915d3-86c7-4770-b1b7-bcbc3a090eae','曉事吟','邵雍','宋','宋诗','song-poetry','','[]','曉物情人爲曉事，知時態者號知人。',32,'全唐诗/poet.song.21000.json','["曉物情人爲曉事，知時態者號知人。", "知人失後却成害，曉事過時還不淳。"]'),
('8572d58e-232e-41a8-a561-40fa8c87aac2','鮮歡吟','邵雍','宋','宋诗','song-poetry','','[]','生不爭名與爭利，夫君何故鮮歡意。',64,'全唐诗/poet.song.21000.json','["生不爭名與爭利，夫君何故鮮歡意。", "以道自重固有之，非理相干是無謂。", "白日升天恐虛傳，金貂換酒可曾醉。", "誰云憂撓大於山，亦是人間常式事。"]'),
('2d067d7d-1771-4773-a6c3-c1b7af22e710','病起吟','邵雍','宋','宋诗','song-poetry','','[]','病作因循一月前，豈期爲苦稍淹延。',64,'全唐诗/poet.song.21000.json','["病作因循一月前，豈期爲苦稍淹延。", "朝昏飲食是難進，軀體虛羸不可言。", "既勸佳賓持酒盞，更將大筆寫詩篇。", "始知心者氣之帥，心快沉痾自釋然。"]'),
('b220b070-d859-4d24-9e2f-1ef89a94ed57','半醉吟  其一','邵雍','宋','宋诗','song-poetry','','[]','半醉上車兒，車兒穩碾歸。',48,'全唐诗/poet.song.21000.json','["半醉上車兒，車兒穩碾歸。", "輕風迎面處，翠柳拂頭時。", "意若兼三事，情如擁九麾。", "這般閑富貴，料得沒人知。"]'),
('c0f9e003-f66e-4616-8e58-5f400e41abda','半醉吟  其二','邵雍','宋','宋诗','song-poetry','','[]','半醉小車行，世間無此榮。',48,'全唐诗/poet.song.21000.json','["半醉小車行，世間無此榮。", "凉風迎面細，垂柳拂頭輕。", "意若兼三事，情如擁萬兵。", "這般閑富貴，料得沒人爭。"]'),
('5454a042-6c5f-4b8d-a61d-ca4adad5a4a0','覽照吟','邵雍','宋','宋诗','song-poetry','','[]','凌晨覽照見皤然，自喜皤然一叟仙。',64,'全唐诗/poet.song.21000.json','["凌晨覽照見皤然，自喜皤然一叟仙。", "慷慨敢開天下口，分明高道世間言。", "雖然天下本無事，不那世間長有賢。", "自問此身何所用，此身唯稱老林泉。"]'),
('6161278e-83a6-4fe0-841d-b06a9d44e93b','人壽吟','邵雍','宋','宋诗','song-poetry','','[]','人壽百年間，其間多少難。',48,'全唐诗/poet.song.21000.json','["人壽百年間，其間多少難。", "予今六十三，何止于一半。", "骨瘦固非清，髮白豈謂筭。", "便化不爲夭，況且粗康健。"]'),
('6c978e08-b449-45da-ac99-7b5c37b0f815','太平吟','邵雍','宋','宋诗','song-poetry','','[]','身老太平間，身閑心更閑。',48,'全唐诗/poet.song.21000.json','["身老太平間，身閑心更閑。", "非貴亦非賤，不饑兼不寒。", "有賓須置酒，無日不開顔。", "第一條平路，何人伴往還。"]'),
('b4bd8d6d-13a1-402d-a77c-f9999a733d1f','古琴吟','邵雍','宋','宋诗','song-poetry','','[]','長隨書與棋，貧亦久藏之。',48,'全唐诗/poet.song.21000.json','["長隨書與棋，貧亦久藏之。", "碧玉琢爲軫，黄金拍作徽。", "典多因待客，彈少爲求知。", "近日僮奴惡，須防煮鶴時。"]'),
('a3559162-3b48-4f0a-9f10-6db43ba893b5','求信吟','邵雍','宋','宋诗','song-poetry','','[]','始則求人信，有知有不知。',48,'全唐诗/poet.song.21000.json','["始則求人信，有知有不知。", "既而求自信，人或多知之。", "今我不求信，何人更起疑。", "無可無不可，安往不熙熙。"]'),
('511a9142-ebbd-4571-a866-255f9b92fd6c','蝎蛇吟','邵雍','宋','宋诗','song-poetry','','[]','蛇毒遠于生，蝎毒近于死。',48,'全唐诗/poet.song.21000.json','["蛇毒遠于生，蝎毒近于死。", "蛇蝎雖不同，其毒固無異。", "蛇以首中人，蝎以尾用事。", "柰何天地間，畏首又畏尾。"]'),
('8356c31a-de6e-4ee4-abd7-084ff9733411','自在吟','邵雍','宋','宋诗','song-poetry','','[]','心不過一寸，兩手何拘拘。',48,'全唐诗/poet.song.21000.json','["心不過一寸，兩手何拘拘。", "身不過數尺，兩足何區區。", "何人不飲酒，何人不讀書。", "柰何天地間，自在獨堯夫。"]'),
('fa2f373c-13b9-456f-a406-fef9168615be','心安吟','邵雍','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','心安身自安，身安室自寬。',48,'全唐诗/poet.song.21000.json','["心安身自安，身安室自寬。", "心與身俱安，何事能相干。", "誰謂一身小，其安若泰山。", "誰謂一室小，寬如天地間。"]'),
('1328f7f7-a386-4f2f-8f7f-cf023920d346','論詩吟','邵雍','宋','宋诗','song-poetry','','[]','何故謂之詩，詩者言其志。',48,'全唐诗/poet.song.21000.json','["何故謂之詩，詩者言其志。", "既用言成章，遂道心中事。", "不止鍊其辭，抑亦鍊其意。", "鍊辭得奇句，鍊意得餘味。"]'),
('d48a0756-bbae-48dd-9beb-87f2a453ed66','爲善吟','邵雍','宋','宋诗','song-poetry','','[]','人之爲善事，善事義當爲。',48,'全唐诗/poet.song.21000.json','["人之爲善事，善事義當爲。", "金石猶能動，鬼神其可欺。", "事須安義命，言必道肝脾。", "莫問身之外，人知與不知。"]'),
('297f21b8-acfb-4980-b9ae-becc831343d2','即事吟','邵雍','宋','宋诗','song-poetry','','[]','事到患來頻，何由得任真。',48,'全唐诗/poet.song.21000.json','["事到患來頻，何由得任真。", "就新須果敢，從善莫因循。", "盜亦自有道，人而或不仁。", "義緣無定體，安處是行身。"]'),
('4d72a179-3dd0-4706-80b7-be6085f37ad5','偶得吟','邵雍','宋','宋诗','song-poetry','','[]','日爲萬象精，人爲萬物靈。',48,'全唐诗/poet.song.21000.json','["日爲萬象精，人爲萬物靈。", "萬象與萬物，由天然後生。", "言由人而信，月由日而明。", "由人與由日，何嘗不太平。"]'),
('ea036ec2-5e62-45bf-a83b-28859249a9e5','靜坐吟','邵雍','宋','宋诗','song-poetry','','[]','人生固有命，物生固有定。',72,'全唐诗/poet.song.21000.json','["人生固有命，物生固有定。", "豈謂人最靈，不如物正性。", "或聞陰有鬼，善能致人死。", "致死設有由，死外何所求。", "又況人之命，繫天不繫佗。", "陰鬼設有靈，獨且柰天何。"]'),
('7541b4b2-6565-49f4-a84d-1d25e43371bb','靜樂吟','邵雍','宋','宋诗','song-poetry','','[]','和氣四時均，何時不是春。',48,'全唐诗/poet.song.21000.json','["和氣四時均，何時不是春。", "都將無事樂，變作有形身。", "靜把詩評物，閑將理告人。", "雖然無鼓吹，此樂世難倫。"]'),
('cd1e0062-b98e-4b32-8ed1-3e888760b95c','男子吟','邵雍','宋','宋诗','song-poetry','','[]','欲作一男子，須了四般事。',48,'全唐诗/poet.song.21000.json','["欲作一男子，須了四般事。", "財能使人貪，色能使人嗜。", "名能使人矜，勢能使人倚。", "四患既都去，豈在塵埃裏。"]'),
('9c55e943-ff2b-4836-b884-59aea5cd070b','望雨  其一','邵雍','宋','宋诗','song-poetry','','[]','盛夏久不雨，滿天下愁苦。',24,'全唐诗/poet.song.21000.json','["盛夏久不雨，滿天下愁苦。", "安得一片雲，救取人間否。"]'),
('ff6db946-6236-48df-a886-9536c4ae91ad','望雨  其二','邵雍','宋','宋诗','song-poetry','','[]','久旱偶成雨，方喜慰愁苦。',24,'全唐诗/poet.song.21000.json','["久旱偶成雨，方喜慰愁苦。", "雖能斂塵土，不能救禾黍。"]'),
('0e76889c-6dc6-4399-b53a-27d2e0ece6f5','思義吟','邵雍','宋','宋诗','song-poetry','','[]','小人固無知，唯以利爲視。',48,'全唐诗/poet.song.21000.json','["小人固無知，唯以利爲視。", "君子固不欺，見得還思義。", "思義不顧死，見利或忘生。", "二者之所起，平之與不平。"]'),
('6757a00b-c12a-4c27-8919-544a916c4ca7','金帛吟','邵雍','宋','宋诗','song-poetry','','[]','金帛一種物，所用固不常。',48,'全唐诗/poet.song.21000.json','["金帛一種物，所用固不常。", "聘則謂之幣，賮則謂之將。", "貿則謂之貨，積則謂之藏。", "賂則謂之賄，竊則謂之贓。"]'),
('eb71b094-173f-4799-9ca5-d5e6e2a0b793','盜伯吟  其一','邵雍','宋','宋诗','song-poetry','','[]','盜伯窺財物，其心不慮佗。',24,'全唐诗/poet.song.21000.json','["盜伯窺財物，其心不慮佗。", "取時唯恐少，敗後只嫌多。"]'),
('262a96fe-36bd-4480-830c-9712e935d7f3','盜伯吟  其二','邵雍','宋','宋诗','song-poetry','','[]','盜伯窺財物，其心只慮添。',24,'全唐诗/poet.song.21000.json','["盜伯窺財物，其心只慮添。", "安得取時貪，却似敗時嫌。"]'),
('dc50495e-887a-4d65-a906-7cb090df8d4b','待物吟','邵雍','宋','宋诗','song-poetry','','[]','待物莫如誠，誠真天下行。',48,'全唐诗/poet.song.21000.json','["待物莫如誠，誠真天下行。", "物情無遠近，天道自分明。", "義理須宜顧，才能不用矜。", "世間閑緣飾，到了是虛名。"]'),
('e230dccd-b117-4f54-892a-acaf2a7ab854','唐虞吟','邵雍','宋','宋诗','song-poetry','','[]','天下目爲目，謂之明四目。',48,'全唐诗/poet.song.21000.json','["天下目爲目，謂之明四目。", "天下耳爲耳，謂之達四聰。", "前旒與黈纊，所貴無近情。", "無爲無不爲，知此非虛生。"]'),
('5d7fd558-8287-4990-b635-4a38fc3b576d','曝書吟','邵雍','宋','宋诗','song-poetry','','[]','蟲蠹書害少，人蠹書害多。',24,'全唐诗/poet.song.21000.json','["蟲蠹書害少，人蠹書害多。", "蟲蠹曝已去，人蠹當如何。"]'),
('c221822c-72fd-4cdb-901e-4f40bc1d3999','兩犯吟','邵雍','宋','宋诗','song-poetry','','[]','這般事業人難繼，此箇功夫世莫傳。',32,'全唐诗/poet.song.21000.json','["這般事業人難繼，此箇功夫世莫傳。", "窺牖知天乃常事，不窺牖見是知天。"]'),
('43302dbb-e08f-406b-8f9a-5b92caa71c49','憫旱','邵雍','宋','宋诗','song-poetry','','[]','正要雨時須不雨，已成災處更成災。',32,'全唐诗/poet.song.21000.json','["正要雨時須不雨，已成災處更成災。", "如何百穀欲焦爛，遍地止存蒿與萊。"]'),
('8aee94c5-04ac-4b7c-93ed-d377aacec991','無事吟','邵雍','宋','宋诗','song-poetry','','[]','人間萬事若磨持，叢入柘榮利害機。',32,'全唐诗/poet.song.21000.json','["人間萬事若磨持，叢入柘榮利害機。", "祗有一般無對處，都如天地未分時。"]'),
('8a757f6c-563b-47d6-b29f-27c5e51c319b','閣上招友人','邵雍','宋','宋诗','song-poetry','','[]','清風正藹如，小閣枕通衢。',24,'全唐诗/poet.song.21000.json','["清風正藹如，小閣枕通衢。", "不欲久獨擅，能來同享無。"]'),
('69c73bbf-74a8-4263-a594-41bd44985367','憶夢吟','邵雍','宋','宋诗','song-poetry','','[]','心足而家貧，體疎而情親。',24,'全唐诗/poet.song.21000.json','["心足而家貧，體疎而情親。", "開襟知骨瘦，發語見天真。"]'),
('679089f4-7c46-4888-ad5d-65d982e9fab8','大筆吟  其一','邵雍','宋','宋诗','song-poetry','','[]','詩成大字書，意快有誰如。',24,'全唐诗/poet.song.21000.json','["詩成大字書，意快有誰如。", "巨浪銀山立，風檣百尺餘。"]'),
('ddec9fbf-a1e2-4739-95ce-fb6e262e730e','大筆吟  其二','邵雍','宋','宋诗','song-poetry','','[]','酒喜小盃飲，詩快大字書。',24,'全唐诗/poet.song.21000.json','["酒喜小盃飲，詩快大字書。", "不知人世上，此樂更誰如。"]'),
('5ee0e7f4-3c61-4aac-b689-3b089db5f828','自慶吟','邵雍','宋','宋诗','song-poetry','','[]','俗阜知君德，時和見帝功。',24,'全唐诗/poet.song.21000.json','["俗阜知君德，時和見帝功。", "況吾生長老，俱在太平中。"]'),
('ae3eba16-3c02-4ae1-ad16-38d374b2fe16','心耳吟','邵雍','宋','宋诗','song-poetry','','[]','意亦心所至，言須耳所聞。',24,'全唐诗/poet.song.21000.json','["意亦心所至，言須耳所聞。", "誰云天地外，別有好乾坤。"]'),
