('14bb2878-41af-4134-85b1-64d2d06ca1ea','觀陳希夷先生真及墨跡  其二','邵雍','宋','宋诗','song-poetry','','[]','及見希夷蹟，又見希夷真。',24,'全唐诗/poet.song.21000.json','["及見希夷蹟，又見希夷真。", "始知今與古，天下長有人。"]'),
('f4c039e5-fe99-41fd-941d-13edb549c853','觀陳希夷先生真及墨跡  其三','邵雍','宋','宋诗','song-poetry','','[]','希夷真可觀，希夷墨可傳。',24,'全唐诗/poet.song.21000.json','["希夷真可觀，希夷墨可傳。", "希夷心一片，不可得而言。"]'),
('bec4fc2c-346b-47fc-875f-65b48c4baacb','答君實端明遊壽安神林','邵雍','宋','宋诗','song-poetry','','[]','占得幽樓一片山，都離塵土利名間。',32,'全唐诗/poet.song.21000.json','["占得幽樓一片山，都離塵土利名間。", "四時分定所遊處，不爲移文便往還。"]'),
('024e9ba5-1ca8-45ec-a3f1-88345cd88833','杏香花','邵雍','宋','宋诗','song-poetry','','[]','客說河州事，經營杳未涯。',24,'全唐诗/poet.song.21000.json','["客說河州事，經營杳未涯。", "訝予獨無語，貪嗅杏香花。"]'),
('c9deed1d-ef1e-441b-b5c4-34125ca435a1','天津晚步','邵雍','宋','宋诗','song-poetry','','[]','芝蓋久稀疎，暮雲空坱圠。',72,'全唐诗/poet.song.21000.json','["芝蓋久稀疎，暮雲空坱圠。", "千年舊都城，一片閑宮闕。", "禁籞尚連延，觚稜猶巀嶭。", "橋勢橫雌霓，堤形偃初月。", "瀍澗岸已深，漢唐時既歇。", "危亭獨坐人，浪把興亡閱。"]'),
('030a290c-61cc-4394-9e61-df85939f92c6','歡喜吟','邵雍','宋','宋诗','song-poetry','','[]','日往月來，終則有始。',40,'全唐诗/poet.song.21000.json','["日往月來，終則有始。", "半行天上，半下地底。", "照臨之間，不憂則喜。", "予何人哉，歡喜不已。"]'),
('fb444754-b560-4c1c-a45f-98816c8942c7','自作真贊','邵雍','宋','宋诗','song-poetry','','[]','松桂操行，鶑花文才。',40,'全唐诗/poet.song.21000.json','["松桂操行，鶑花文才。", "江山氣度，風月情懷。", "借爾面貌，假爾形骸。", "弄丸餘暇，閑往閑來。"]'),
('4fdae084-5c3c-46e4-96d8-5914023007aa','奢侈吟','邵雍','宋','宋诗','song-poetry','','[]','侈不可極，奢不可窮。',20,'全唐诗/poet.song.21000.json','["侈不可極，奢不可窮。", "極則有禍，窮則有凶。"]'),
('de8a5bb3-7b3c-4077-9068-5b09ebc0a0f0','多多吟','邵雍','宋','宋诗','song-poetry','','[]','天下居常，害多于利。',40,'全唐诗/poet.song.21000.json','["天下居常，害多于利。", "亂多于治，憂多于喜。", "柰何人生，不能免此。", "柰何予生，皆爲外事。"]'),
('66741866-4d30-4cf7-915e-ac913864028f','畏愛吟','邵雍','宋','宋诗','song-poetry','','[]','人有正性，事事皆齊。',80,'全唐诗/poet.song.21000.json','["人有正性，事事皆齊。", "人無正性，事事皆隳。", "失于用恩，以非爲是。", "失于用威，以是爲非。", "恩威既失，畏愛何知。", "不知畏愛，何用恩威。", "喜怒不節，鮮不至斯。", "婦人男子，宜用戒之。"]'),
('0fb78968-8777-46d4-936b-9ac7bc708006','秋閣吟','邵雍','宋','宋诗','song-poetry','','[]','秋閣一凭欄，人心何悄然。',48,'全唐诗/poet.song.21000.json','["秋閣一凭欄，人心何悄然。", "乾坤今歲月，唐漢舊山川。", "淡泊霜前日，蕭疎雨後天。", "丹青空妙手，此意有誰傳。"]'),
('0b7e6f9b-2ce0-4d94-9990-0fd869d402ac','浮生吟','邵雍','宋','宋诗','song-poetry','','[]','浮生曉露邊，且喜又添年。',48,'全唐诗/poet.song.21000.json','["浮生曉露邊，且喜又添年。", "動悔須有悔，求全未必全。", "處人心上事，道物性中言。", "寰宇雖然廣，其誰曰不然。"]'),
('80540187-40ca-4f7d-9163-2cb659f9fbb4','力外吟','邵雍','宋','宋诗','song-poetry','','[]','以少爲多，以無爲有。',20,'全唐诗/poet.song.21000.json','["以少爲多，以無爲有。", "力外周旋，不能長久。"]'),
('7ab2ccb0-bf30-48f0-9ac7-84d01558ff3e','謝傅欽之學士見訪','邵雍','宋','宋诗','song-poetry','','[]','長莫長于天，大莫大於地。',96,'全唐诗/poet.song.21000.json','["長莫長于天，大莫大於地。", "天地尚有極，自餘安足計。", "世態非一朝，人情止于是。", "以至立殊功，無非借巨勢。", "適會在其間，慎勿强生事。", "雖嚴似雪霜，無改如松桂。", "方惜久離闊，却喜由道義。", "相別二十年，猶能記憔悴。"]'),
('06a6a667-b003-4f25-9bec-fb46e0734cb3','賞雪吟','邵雍','宋','宋诗','song-poetry','','[]','一片兩片雪紛紛，三盃五盃酒醺醺。',32,'全唐诗/poet.song.21000.json','["一片兩片雪紛紛，三盃五盃酒醺醺。", "此時情狀不可論，直疑天地纔絪紜。"]'),
('df4f1a0a-43a1-4a18-80aa-227f84dd6cb2','答傅欽之','邵雍','宋','宋诗','song-poetry','','[]','欽之謂我曰：詩似多吟，不如少吟。',92,'全唐诗/poet.song.21000.json','["欽之謂我曰：詩似多吟，不如少吟。", "詩欲少吟，不如不吟。", "我謂欽之曰：亦不多吟，亦不少吟，亦不不吟。", "亦不必吟，芝蘭在室，不能無臭。", "金石振地，不能無聲。", "惡則哀之，哀而不傷。", "善則樂之，樂而不淫。"]'),
('fc3278ab-d361-400f-b67a-afbd4db698f3','月陂閑步','邵雍','宋','宋诗','song-poetry','','[]','因隨芳草行來遠，爲愛清波歸去遲。',32,'全唐诗/poet.song.21000.json','["因隨芳草行來遠，爲愛清波歸去遲。", "獨步獨吟仍獨坐，初凉天氣未寒時。"]'),
('8b428dc3-18b1-4922-b8db-cbec465ff9d9','仲尼吟','邵雍','宋','宋诗','song-poetry','','[]','仲尼生魯在吾先，去聖千餘五百年。',64,'全唐诗/poet.song.21000.json','["仲尼生魯在吾先，去聖千餘五百年。", "今日誰能知此道，當時人自比于天。", "皇王帝伯中原主，父子君臣萬世權。", "河不出圖吾已矣，脩經意思豈徒然。"]'),
('c1ba85ff-8800-4222-ab9a-c50e7ae2fa79','謝圓益上人惠詩一卷','邵雍','宋','宋诗','song-poetry','','[]','覽公詩十首，起我意何多。',48,'全唐诗/poet.song.21000.json','["覽公詩十首，起我意何多。", "似藥驅疑疾，如茶滌睡魔。", "月當松皎潔，山隔水嵯峨。", "明日如無事，天津可再過。"]'),
('d6e97bea-d2d6-45b2-920f-914363cd238b','自述二乎  其一','邵雍','宋','宋诗','song-poetry','','[]','何者堪名席上珍，都緣當日得師真。',64,'全唐诗/poet.song.21000.json','["何者堪名席上珍，都緣當日得師真。", "是知佚我無如老，惟喜放懷長似春。", "得志當爲天下事，退居聊作水雲身。", "胸中一點分明處，不負高天不負人。"]'),
('9a548996-4efc-43df-8d3b-9660d54b0713','自述二乎  其二','邵雍','宋','宋诗','song-poetry','','[]','陸海卧龍收爪甲，遼天老鶴戢毛衣。',64,'全唐诗/poet.song.21000.json','["陸海卧龍收爪甲，遼天老鶴戢毛衣。", "難攀騏驥日千里，易足鷦鷯巢一枝。", "最好朋儕同放適，博高臺榭與登躋。", "雲山勝處追尋遍，似我清閑更有誰。"]'),
('526aa798-5652-4779-9656-75f760968df2','答會計杜孝錫寺丞見贈','邵雍','宋','宋诗','song-poetry','','[]','四方多善人，予善未毫分。',48,'全唐诗/poet.song.21000.json','["四方多善人，予善未毫分。", "有意空求志，無功漫愛君。", "閑行觀止水，靜坐看歸雲。", "老向太平裏，朝廷正右文。"]'),
('db8add22-0821-4dee-8dd6-01ce0d2afd64','天津弊居蒙諸公共爲成買作詩以謝','邵雍','宋','宋诗','song-poetry','','[]','重謝諸公爲買園，買園城裏占林泉。',192,'全唐诗/poet.song.21000.json','["重謝諸公爲買園，買園城裏占林泉。", "七千來步平流水，二十餘家爭出錢。", "嘉祐卜居終是僦，熙寧受券遂能專。", "鳳凰樓下新閑客，道德坊中舊散仙。", "洛浦清風朝滿袖，嵩岑皓月夜盈軒。", "接䍦倒戴芰荷畔，談麈輕摇楊柳邊。", "陌徹銅駝花爛熳，堤連金谷草芊綿。", "青春未老尚可出，紅日已高猶自眠。", "洞號長生宜有主，窩名安樂豈無權。", "敢於世上明開眼，會向人間別看天。", "盡送光陰歸酒盞，都移造化入詩篇。", "也知此片好田地，消得堯夫筆似椽。"]'),
('8081f5e5-4851-4c86-a388-66a26e8ad1e1','同諸友城南張園賞梅十首  其一','邵雍','宋','宋诗','song-poetry','','[]','東風一夜折梅枝，舞蝶遊蜂都不知。',32,'全唐诗/poet.song.21000.json','["東風一夜折梅枝，舞蝶遊蜂都不知。", "插了滿頭仍漬酒，任他人道拙於時。"]'),
('cd0da9d8-a849-4429-bdc3-a89802e5caa6','同諸友城南張園賞梅十首  其二','邵雍','宋','宋诗','song-poetry','','[]','折來嗅了依前嗅，重惜清香難久留。',32,'全唐诗/poet.song.21000.json','["折來嗅了依前嗅，重惜清香難久留。", "多謝主人情意切，未殘仍許客重遊。"]'),
('af7db845-643f-466d-9d97-dc492bf0dc12','同諸友城南張園賞梅十首  其三','邵雍','宋','宋诗','song-poetry','','[]','清香冷艷偏多處，猛雨狂風未有前。',32,'全唐诗/poet.song.21000.json','["清香冷艷偏多處，猛雨狂風未有前。", "賞意正濃紅日墜，如何既去遂經年。"]'),
('c239ad57-972b-495f-85b2-5fdd063b697f','同諸友城南張園賞梅十首  其四','邵雍','宋','宋诗','song-poetry','','[]','紅日墜時情更切，玉山頹處興還深。',32,'全唐诗/poet.song.21000.json','["紅日墜時情更切，玉山頹處興還深。", "攀條時揀繁枝折，不插滿頭辜此心。"]'),
('737799fb-3d09-4cc0-baff-3c2a7b1a707c','同諸友城南張園賞梅十首  其五','邵雍','宋','宋诗','song-poetry','','[]','梅臺賞罷意何如，歸插梅花登小車。',32,'全唐诗/poet.song.21000.json','["梅臺賞罷意何如，歸插梅花登小車。", "陌上行人應見笑，風情不薄是堯夫。"]'),
('9d4e8143-f674-497b-b755-ad4e17c9e753','同諸友城南張園賞梅十首  其六','邵雍','宋','宋诗','song-poetry','','[]','酒中漬後香尤烈，笛裏吹來韻更清。',32,'全唐诗/poet.song.21000.json','["酒中漬後香尤烈，笛裏吹來韻更清。", "此韻此香來處好，此時消得一凝情。"]'),
('14ef8297-d5a9-427d-834f-baf111178748','同諸友城南張園賞梅十首  其七','邵雍','宋','宋诗','song-poetry','','[]','春早梅花正爛開，生平不飲亦銜盃。',32,'全唐诗/poet.song.21000.json','["春早梅花正爛開，生平不飲亦銜盃。", "城南盡日高臺上，恰似江南去一迴。"]'),
('5a4e21d3-2042-4eaa-95ea-aa73c1348d4b','同諸友城南張園賞梅十首  其八','邵雍','宋','宋诗','song-poetry','','[]','梅花四種或紅黄，顔色不同香頗同。',32,'全唐诗/poet.song.21000.json','["梅花四種或紅黄，顔色不同香頗同。", "更遠也須重一到，看看隨水又隨風。"]'),
('40b10108-5b38-44aa-813e-9035cad08185','同諸友城南張園賞梅十首  其九','邵雍','宋','宋诗','song-poetry','','[]','五嶺雖多何足觀，三川縱少須重去。',32,'全唐诗/poet.song.21000.json','["五嶺雖多何足觀，三川縱少須重去。", "臺邊況有數十株，仍在名園最深處。"]'),
('c1fe3982-cebc-4949-8bb4-936ee3c5ae29','同諸友城南張園賞梅十首  其一○','邵雍','宋','宋诗','song-poetry','','[]','人間好物尤宜惜，天下奇才非易得。',32,'全唐诗/poet.song.21000.json','["人間好物尤宜惜，天下奇才非易得。", "他日相逢他處時，始知此會重難覓。"]'),
('1eefc791-6293-4990-b361-ec81452f59b4','答人吟  其一','邵雍','宋','宋诗','song-poetry','','[]','誰道閑人無事權，事權唯只是詩篇。',32,'全唐诗/poet.song.21000.json','["誰道閑人無事權，事權唯只是詩篇。", "四時雪月風花景，都與收來入近編。"]'),
('db7825ee-b380-4b8b-8d13-387c3734c327','答人吟  其二','邵雍','宋','宋诗','song-poetry','','[]','初春洛城梅開時，賞梅更吟梅花詩。',32,'全唐诗/poet.song.21000.json','["初春洛城梅開時，賞梅更吟梅花詩。", "梅花雖開難遠寄，唯寄梅詩伸所思。"]'),
('da70766f-ad53-4eb2-a322-e2dce32cf1db','依韻和君實端明惠酒','邵雍','宋','宋诗','song-poetry','','[]','春風吹雪亂飄颻，林下如何更寂寥。',32,'全唐诗/poet.song.21000.json','["春風吹雪亂飄颻，林下如何更寂寥。", "霜憲威稜正難犯，小人當貺是難消。"]'),
('e3191589-ceb5-4d2d-9a3f-9f0c1b479615','謝壽安簿寄錦幈山下民失剪刀','邵雍','宋','宋诗','song-poetry','','[]','江夏尚能悲墜履，少原唯解泣遺簪。',32,'全唐诗/poet.song.21000.json','["江夏尚能悲墜履，少原唯解泣遺簪。", "一刀所失安足繫，不那久經人用心。"]'),
('0bd33047-ec9d-4917-84b4-64bd2b18a622','謝君實端明惠山蔬八品','邵雍','宋','宋诗','song-poetry','','[]','八品山蔬盡藥萌，何山採得各標名。',32,'全唐诗/poet.song.21000.json','["八品山蔬盡藥萌，何山採得各標名。", "山翁驚受霜臺貺，即命山妻親自烹。"]'),
('442ffd28-2e02-4077-86e9-40cbf17f3ac9','謝君實端明惠牡丹','邵雍','宋','宋诗','song-poetry','','[]','霜臺何處得奇葩，分送天津小隠家。',32,'全唐诗/poet.song.21000.json','["霜臺何處得奇葩，分送天津小隠家。", "初訝山妻忽驚走，尋常只慣插葵花。"]'),
('00e098d4-5a6e-4253-958c-df7a8e577f07','謝判府王宣徽惠酒','邵雍','宋','宋诗','song-poetry','','[]','自得花枝向遠鄰，只憂輕負一番春。',32,'全唐诗/poet.song.21000.json','["自得花枝向遠鄰，只憂輕負一番春。", "無何寵貺酒雙榼，少室山人遂不貧。"]'),
('66a70b4b-51f0-4ceb-abc2-e2919179268c','和君實端明洛陽看花  其一','邵雍','宋','宋诗','song-poetry','','[]','洛陽最得中和氣，一草一木皆入看。',32,'全唐诗/poet.song.21000.json','["洛陽最得中和氣，一草一木皆入看。", "飲水也須無限樂，況能時復舉盃盤。"]'),
('bcaeaafb-98a6-4bd1-9f6c-a8eb1545c05d','和君實端明洛陽看花  其二','邵雍','宋','宋诗','song-poetry','','[]','洛陽花木誇天下，吾輩遊勝庶士遊。',32,'全唐诗/poet.song.21000.json','["洛陽花木誇天下，吾輩遊勝庶士遊。", "重念東君分付意，忍於佳處不遲留。"]'),
('fe3dd50e-0dd3-40de-9fe4-3fbceb230c8f','和君實端明洛陽看花  其三','邵雍','宋','宋诗','song-poetry','','[]','洛陽交友皆奇傑，遞賞名園只似家。',32,'全唐诗/poet.song.21000.json','["洛陽交友皆奇傑，遞賞名園只似家。", "却笑孟郊窮不慣，一日看盡長安花。"]'),
('b0195423-243d-4978-94af-3ec90ce3fefe','和君實端明洛陽看花  其四','邵雍','宋','宋诗','song-poetry','','[]','南園一色栽桃李，春到且圖花早開。',32,'全唐诗/poet.song.21000.json','["南園一色栽桃李，春到且圖花早開。", "多謝主人情意厚，天津客不等閑來。"]'),
('425c56ec-8f9b-4d87-abfb-b244f84b2ec2','和君實端明送酒','邵雍','宋','宋诗','song-poetry','','[]','大凡人意易爲驕，雙榼何如水一瓢。',32,'全唐诗/poet.song.21000.json','["大凡人意易爲驕，雙榼何如水一瓢。", "亦恐孟光心漸侈，自茲微厭紫芝苗。"]'),
('a3fc87a5-d0e7-4563-8b90-267e2cb7ca72','暮春吟','邵雍','宋','宋诗','song-poetry','','[]','林下居常睡起遲，那堪車馬近來稀。',32,'全唐诗/poet.song.21000.json','["林下居常睡起遲，那堪車馬近來稀。", "春深晝永簾垂地，庭院無風花自飛。"]'),
('cec76d00-24f3-481b-9ec1-5a7787983a18','依韻和鎮戎倅龔章屯田','邵雍','宋','宋诗','song-poetry','','[]','十五年前初見君，見君情意便如親。',64,'全唐诗/poet.song.21000.json','["十五年前初見君，見君情意便如親。", "雖然林下無他事，不那心間思故人。", "萬物比之論至底，丹誠到了總輸真。", "過從洛社勝諸處，何日能來共卜鄰。"]'),
('59f99a51-59a0-4535-9f3a-700f534953db','安樂窩銘','邵雍','宋','宋诗','song-poetry','','[]','安莫安于王政平，樂莫樂于年穀登。',32,'全唐诗/poet.song.21000.json','["安莫安于王政平，樂莫樂于年穀登。", "王政不平年不登，窩中何由得康寧。"]'),
('9dff089f-d310-48d0-8531-44985c8b3c05','愁恨吟','邵雍','宋','宋诗','song-poetry','','[]','城裏住煙霞，天津小隠家。',48,'全唐诗/poet.song.21000.json','["城裏住煙霞，天津小隠家。", "經書爲事業，水竹是生涯。", "恨爲雲遮月，愁因風損花。", "恨愁花月外，何暇更知他。"]'),
('bb783f3f-ca76-490c-9c28-3a741566c267','悲喜吟','邵雍','宋','宋诗','song-poetry','','[]','吳起初辭魏，張儀乍入秦。',24,'全唐诗/poet.song.21000.json','["吳起初辭魏，張儀乍入秦。", "西河蒙惠久，南楚受欺頻。"]'),
('f83c933e-2f63-43d8-9f8f-529699c09282','善惡吟','邵雍','宋','宋诗','song-poetry','','[]','君子學道則務本，小人見利則忘生。',32,'全唐诗/poet.song.21000.json','["君子學道則務本，小人見利則忘生。", "務本則非禮不動，見利則非賄不行。"]'),
('4f16fc98-1a79-4a6f-a27c-7fd1c837e27a','所學吟','邵雍','宋','宋诗','song-poetry','','[]','人之所學，本學人事。',20,'全唐诗/poet.song.21000.json','["人之所學，本學人事。", "人事不脩，無學何異。"]'),
('b18d32a8-4bb3-49d7-955f-6461d0f70b0f','君子行','邵雍','宋','宋诗','song-poetry','','[]','何者爲君子，君子固可修。',48,'全唐诗/poet.song.21000.json','["何者爲君子，君子固可修。", "是知君子途，使人從之遊。", "與義不與利，記恩不記讎。", "揚善不揚惡，主喜不主憂。"]'),
('cd8c74a3-6d05-4121-9de7-3509fd789910','思省吟','邵雍','宋','宋诗','song-poetry','','[]','仲尼再思，魯子三省。',20,'全唐诗/poet.song.21000.json','["仲尼再思，魯子三省。", "予何人哉，敢忘修整。"]'),
('34bb30c1-b9f5-44ae-a946-4eaa2a6bb6fd','梁燕吟','邵雍','宋','宋诗','song-poetry','','[]','物情誰道爾無知，秋去春來不失期。',32,'全唐诗/poet.song.21000.json','["物情誰道爾無知，秋去春來不失期。", "今歲新雛又成就，去時寧不重依依。"]'),
('ed6a4ef0-c170-4e97-8db4-3a8371db175b','鄒田二忌','邵雍','宋','宋诗','song-poetry','','[]','鄒田二忌不相能，買卜之言惡足明。',32,'全唐诗/poet.song.21000.json','["鄒田二忌不相能，買卜之言惡足明。", "利害傷真至于此，姓田人去恨難平。"]'),
('dd52f098-733c-4b8e-86ca-b753d6cfdf1d','孫龐二將','邵雍','宋','宋诗','song-poetry','','[]','孫臏伏兵稱有法，龐涓鑽火一何愚。',32,'全唐诗/poet.song.21000.json','["孫臏伏兵稱有法，龐涓鑽火一何愚。", "兵家詭詐盡如此，利害今人自不殊。"]'),
('677358d3-7de4-4c8a-8551-e2fee9eb05fc','一言感人','邵雍','宋','宋诗','song-poetry','','[]','爲女不嫁，爲士不官。',20,'全唐诗/poet.song.21000.json','["爲女不嫁，爲士不官。", "齊人一言，田子辭焉。"]'),
('c6fc0b68-2e4e-4fde-a847-b7b7b25dba1c','四公子吟','邵雍','宋','宋诗','song-poetry','','[]','時去三王，事歸五霸。',40,'全唐诗/poet.song.21000.json','["時去三王，事歸五霸。", "七雄既爭，四子乃詫。", "孟嘗居先，信陵居亞。", "平原居中，春申居下。"]'),
('d14f14fb-9af2-432d-983c-c2b10ad2555e','淳于髠酒諫','邵雍','宋','宋诗','song-poetry','','[]','賜酒于君，飲不知味。',180,'全唐诗/poet.song.21000.json','["賜酒于君，飲不知味。", "執法在前，恐懼無既。", "當此之時，一斗而醉。", "宗族滿堂，既孝且悌。", "尊卑以親，少長有齒。", "當此之時，二斗而醉。", "賓之初筵，蹌蹌濟濟。", "獻酬百拜，升降有禮。", "當此之時，三斗而醉。", "里閈過從，如兄如弟。", "時和歲豐，情懷歡喜。", "當此之時，五斗而醉。", "朋友往還，講道求義。", "樂事賞心，登山臨水。", "當此之時，八斗而醉。", "男女雜坐，盃觴不記。", "燈燭明滅，衣冠傾圯。", "當此之時，一石而醉。"]'),
('bb9e06c9-c5b0-4df6-b4d5-832806843206','東海有大魚','邵雍','宋','宋诗','song-poetry','','[]','東海有大魚，罔罟無能近。',24,'全唐诗/poet.song.21000.json','["東海有大魚，罔罟無能近。", "碭然一失水，螻蟻得而困。"]'),
('66bbd7b3-7aba-4a42-b2fb-2601e0229015','土木偶人','邵雍','宋','宋诗','song-poetry','','[]','土木偶人，慎無相笑。',20,'全唐诗/poet.song.21000.json','["土木偶人，慎無相笑。", "天將大雨，止可相弔。"]'),
('6cc76b80-f342-47d5-9a85-4328aa764501','辨謗吟','邵雍','宋','宋诗','song-poetry','','[]','田丹功蓋國，貂勃語迴君。',24,'全唐诗/poet.song.21000.json','["田丹功蓋國，貂勃語迴君。", "謗者古來有，猶能殺九人。"]'),
('c9af445c-2f6f-4d1c-90a2-3e164e1de23d','三皇吟','邵雍','宋','宋诗','song-poetry','','[]','三皇之世正熙熙，烏鵲之巢俯可窺。',32,'全唐诗/poet.song.21000.json','["三皇之世正熙熙，烏鵲之巢俯可窺。", "當日一般情味好，初春天氣早晨時。"]'),
('a29d3995-da4b-45a6-985a-b560511f82f5','五帝','邵雍','宋','宋诗','song-poetry','','[]','五帝之時似日中，聲明文物正融融。',32,'全唐诗/poet.song.21000.json','["五帝之時似日中，聲明文物正融融。", "古今世盛無如此，過此其來便不同。"]'),
('ca123232-3440-44ec-9448-e9d59d340673','三王','邵雍','宋','宋诗','song-poetry','','[]','三王之世正如秋，權重權輕事有由。',32,'全唐诗/poet.song.21000.json','["三王之世正如秋，權重權輕事有由。", "深谷爲陵岸爲谷，陵遷谷變不知休。"]'),
('a2ca65f1-4dd1-41e8-beff-9cb846ad6bc4','五伯','邵雍','宋','宋诗','song-poetry','','[]','五伯之時正似冬，雖然三代莫同風。',32,'全唐诗/poet.song.21000.json','["五伯之時正似冬，雖然三代莫同風。", "當初管晏權輕重，父子君臣尚且宗。"]'),
('98305f00-19de-4b67-8981-be826244dc8b','七國','邵雍','宋','宋诗','song-poetry','','[]','七國縱橫事可明，蘇張得路信非平。',32,'全唐诗/poet.song.21000.json','["七國縱橫事可明，蘇張得路信非平。", "當初天下如何爾，市井之人爲正卿。"]'),
('db41535a-69ec-4b87-9383-abfb4873996a','掃地吟','邵雍','宋','宋诗','song-poetry','','[]','管晏治時猶有體，蘇張用處更無名。',32,'全唐诗/poet.song.21000.json','["管晏治時猶有體，蘇張用處更無名。", "三皇五帝從何出，掃地中原俟太平。"]'),
('afdc63e4-8c42-4fb1-9aa7-649a3b1d2ef5','天人吟','邵雍','宋','宋诗','song-poetry','','[]','羲軒堯舜雖難復，湯武桓文尚可循。',32,'全唐诗/poet.song.21000.json','["羲軒堯舜雖難復，湯武桓文尚可循。", "事既不同時又異，也由天道也由人。"]'),
('37e76bb5-39ad-4435-94aa-a0b61ffa952f','利害吟','邵雍','宋','宋诗','song-poetry','','[]','兔犬俱斃，蚌鷸相持。',20,'全唐诗/poet.song.21000.json','["兔犬俱斃，蚌鷸相持。", "田漁老父，坐而利之。"]'),
('d4533524-10f9-42bc-9807-bcb1d22161fa','時吟','邵雍','宋','宋诗','song-poetry','','[]','騏驥壯時，千里莫追。',40,'全唐诗/poet.song.21000.json','["騏驥壯時，千里莫追。", "及其衰也，駑馬先之。", "時與事會，談笑指揮。", "時移事去，雖死奚爲。"]'),
('20b2b9b6-4368-4cfc-b7a0-7013e19ee1ad','二說吟','邵雍','宋','宋诗','song-poetry','','[]','治不變俗，教不易民。',40,'全唐诗/poet.song.21000.json','["治不變俗，教不易民。", "甘龍之說，亦或可循。", "常人習俗，學者溺聞。", "商鞅之說，異乎所云。"]'),
('e1188a0d-51fd-4c20-934d-b56eaf8d7559','言行吟','邵雍','宋','宋诗','song-poetry','','[]','言不失仁，行不失義。',76,'全唐诗/poet.song.21000.json','["言不失仁，行不失義。", "自天祐之，吉無不利。", "言與仁背，行與義乖。", "天且不祐，人能行哉。", "有商君者，賊義殘仁。", "爲法自弊，車分其身。", "始知行義脩仁者，便是延年益壽人。"]'),
('39f8e834-4ff7-4489-8fa6-2d8e22e0d6ce','治亂吟','邵雍','宋','宋诗','song-poetry','','[]','財利爲先，筆舌用事。',40,'全唐诗/poet.song.21000.json','["財利爲先，筆舌用事。", "饑饉相仍，盜賊蜂起。", "孝悌爲先，日月長久。", "時和歲豐，延年益壽。"]'),
('1b0ac949-906e-4efb-bf10-2ceb04788058','太平吟','邵雍','宋','宋诗','song-poetry','','[]','老者得其養，幼者得其仰。',24,'全唐诗/poet.song.21000.json','["老者得其養，幼者得其仰。", "勞者得其餉，死者得其葬。"]'),
('a0a07308-8fe3-4ab9-9073-a4aa7719c126','商君吟','邵雍','宋','宋诗','song-poetry','','[]','商鞅得君持法處，趙良終日正言時。',32,'全唐诗/poet.song.21000.json','["商鞅得君持法處，趙良終日正言時。", "當其命令炎如火，車裂如何都不知。"]'),
('14f1ad2b-b079-492e-b145-ddc41c225da4','能懷天下心','邵雍','宋','宋诗','song-poetry','','[]','能懷天下心，肯了人間事。',24,'全唐诗/poet.song.21000.json','["能懷天下心，肯了人間事。", "豈止求于今，求古亦未易。"]'),
('8966765d-d12b-408b-ae29-1a5ec6c38152','始皇吟','邵雍','宋','宋诗','song-poetry','','[]','并吞天下九千日，一統寰中十五年。',32,'全唐诗/poet.song.21000.json','["并吞天下九千日，一統寰中十五年。", "坑血未乾高祖至，驪山丘壠已蕭然。"]'),
('ab44b6a8-c160-4728-a18c-b99f75c45856','有妄吟','邵雍','宋','宋诗','song-poetry','','[]','作僞少陰德，飾非多隠情。',36,'全唐诗/poet.song.21000.json','["作僞少陰德，飾非多隠情。", "人心雖曖昧，天道自分明。", "手足既皆露，語言安足憑。"]'),
('b878b336-4f10-4222-80c4-e4bfd985a80f','乾坤吟','邵雍','宋','宋诗','song-poetry','','[]','用九見羣龍，首能出庶物。',60,'全唐诗/poet.song.21000.json','["用九見羣龍，首能出庶物。", "用六利永貞，因乾以爲利。", "四象以九成，遂爲三十六。", "四象以六成，遂成二十四。", "如何九與六，能盡人間事。"]'),
('043c9b22-15ae-4276-8bf4-484fa25dfd9b','皇極經世一元吟','邵雍','宋','宋诗','song-poetry','','[]','天地如蓋軫，覆載何高極。',96,'全唐诗/poet.song.21000.json','["天地如蓋軫，覆載何高極。", "日月如磨蟻，往來無休息。", "上下之歲年，其數難窺測。", "且以一元言，其理尚可識。", "一十有二萬，九千餘六百。", "中間三千年，迄今之陳迹。", "治亂與廢興，著見于方策。", "吾能一貫之，皆如身所歷。"]'),
('b27d416c-7ed8-4f00-8298-3a517d24541e','應龍吟','邵雍','宋','宋诗','song-poetry','','[]','龍者陽類，與時相須。',40,'全唐诗/poet.song.21000.json','["龍者陽類，與時相須。", "首出庶物，同遊六虛。", "能潜能見，能吸能呼。", "能大能小，能有能無。"]'),
('27fb7443-4cbf-4496-81b0-6f0db87aff6a','何處是仙鄉','邵雍','宋','宋诗','song-poetry','','[]','何處是仙鄉，仙鄉不離房。',48,'全唐诗/poet.song.21000.json','["何處是仙鄉，仙鄉不離房。", "眼前無冗長，心下有清凉。", "靜處乾坤大，閑中日月長。", "若能安得分，都勝別思量。"]'),
('cd2f369b-167d-4de5-a97b-5ef7d6709ef1','謝宋推官惠白牛','邵雍','宋','宋诗','song-poetry','','[]','毛如霜雪眼如朱，耳角方齊三尺餘。',64,'全唐诗/poet.song.21000.json','["毛如霜雪眼如朱，耳角方齊三尺餘。", "狀異不將耕曠土，性馴宜用駕安車。", "水邊牧處龍能擾，月下牽時兔可驅。", "從此洛陽圖㡠上，丹青人更著功夫。"]'),
('6059f08c-a4d7-4e91-8067-25c71a72bb07','依韻和王安之少卿六老詩仍見率成七  其一','邵雍','宋','宋诗','song-poetry','','[]','六老皤然鬢似霜，縱心年至又非狂。',64,'全唐诗/poet.song.21000.json','["六老皤然鬢似霜，縱心年至又非狂。", "園池共避何妨勝，樽俎相歡未始忙。", "杖屨爛遊千載運，衣巾濃惹萬花香。", "過從見率添成七，況復秋來亦漸凉。"]'),
('8901677f-ad6d-49c3-adb2-3016fe3d92da','依韻和王安之少卿六老詩仍見率成七  其二','邵雍','宋','宋诗','song-poetry','','[]','六老相陪卿與郎，閑曹饒却不清狂。',64,'全唐诗/poet.song.21000.json','["六老相陪卿與郎，閑曹饒却不清狂。", "過從無事易成樂，職局向人難道忙。", "煙柳嫩垂低更綠，露桃紅裛暖仍香。", "乘春醉卧花陰下，恰到花陰別是凉。"]'),
('7c42e258-2612-484f-a8c7-e5a6ce5b1223','依韻和王安之少卿六老詩仍見率成七  其三','邵雍','宋','宋诗','song-poetry','','[]','六翁誰讓少年場，老不羞人任意狂。',64,'全唐诗/poet.song.21000.json','["六翁誰讓少年場，老不羞人任意狂。", "同向靜中觀物動，共於閑處看人忙。", "天心月滿蟾蜍動，水面風微菡萏香。", "肯信人間有憂事，新醅正熟景初凉。"]'),
('d18c39b4-4dda-4546-847f-bd4988364d55','依韻和王安之少卿六老詩仍見率成七  其四','邵雍','宋','宋诗','song-poetry','','[]','六人相聚會時康，著甚來由不放狂。',64,'全唐诗/poet.song.21000.json','["六人相聚會時康，著甚來由不放狂。", "遍地園林同己有，滿天風月助詩忙。", "文章高摘漢唐艷，騷雅濃薰李杜香。", "水際竹邊閑適處，更無塵事只清凉。"]'),
('83f1556c-f7d0-4810-b1a4-75bd7db4193f','依韻和王安之少卿六老詩仍見率成七  其五','邵雍','宋','宋诗','song-poetry','','[]','六客同遊一醉鄉，又非流俗所言狂。',64,'全唐诗/poet.song.21000.json','["六客同遊一醉鄉，又非流俗所言狂。", "追遊共喜清平久，唱和爭尋驚策忙。", "薦酒月陂林果熟，發茶金谷井泉香。", "千年松下麾談麈，襟袖無風亦自凉。"]'),
('3acea00e-bb64-404e-b7ef-a9f71fe5a5bd','依韻和王安之少卿六老詩仍見率成七  其六','邵雍','宋','宋诗','song-poetry','','[]','見率野人成七老，野人唯解野疎狂。',64,'全唐诗/poet.song.21000.json','["見率野人成七老，野人唯解野疎狂。", "編排每日清吟苦，趁辦遞年閑適忙。", "夏末喜嘗新酒味，春初愛嗅早梅香。", "問君何故須如此，不柰心頭一點凉。"]'),
('5443fa49-1a4a-4220-b70e-5126883fdb0c','依韻和王安之少卿六老詩仍見率成七  其七','邵雍','宋','宋诗','song-poetry','','[]','林下狂歌不帖腔，帖腔安得謂之狂。',64,'全唐诗/poet.song.21000.json','["林下狂歌不帖腔，帖腔安得謂之狂。", "小車行處鶑花鬧，大筆落時神鬼忙。", "門掩柴荆闤闠遠，牆開甕牖薜蘿香。", "一般天下難尋物，洛浦清風拂面凉。"]'),
('0efc725e-9094-4eda-9e96-b04543090152','依韻和張靜之少卿惠文房三物','邵雍','宋','宋诗','song-poetry','','[]','文房三物品皆精，報謝愁無秀句成。',32,'全唐诗/poet.song.21000.json','["文房三物品皆精，報謝愁無秀句成。", "欲狀升平在歌頌，柰何才不逮升平。"]'),
('9072b457-21ac-4a8d-b409-0081e38c9179','依韻和王安之少卿謝富相公詩','邵雍','宋','宋诗','song-poetry','','[]','寵辱見多惡足驚，出塵還喜自誠明。',64,'全唐诗/poet.song.21000.json','["寵辱見多惡足驚，出塵還喜自誠明。", "閑中氣象乾坤大，靜處光陰宇宙清。", "素業經綸無少愧，全功天地不虛生。", "野人何幸逢昌運，一百餘年天下平。"]'),
('ce4c3e59-9ec4-465f-ac6c-cc1b5b0a02b6','安樂窩前蒲柳吟','邵雍','宋','宋诗','song-poetry','','[]','安樂窩前小曲江，新蒲細柳年年綠。',32,'全唐诗/poet.song.21000.json','["安樂窩前小曲江，新蒲細柳年年綠。", "眼前隨分好光陰，誰道人生多不足。"]'),
('c9f2dece-7380-4506-bab8-eb970e6355e6','甕牖吟','邵雍','宋','宋诗','song-poetry','','[]','甕破已甘棄，言收用有方。',48,'全唐诗/poet.song.21000.json','["甕破已甘棄，言收用有方。", "用時須藉口，照處便安牀。", "不假軒窗力，能迴日月光。", "清平卧其下，自可比羲皇。"]'),
('2fb5d58c-13d0-43dc-babb-7a0a09b6bd64','人生長有兩般愁','邵雍','宋','宋诗','song-poetry','','[]','人生長有兩般愁，愁死愁生未易休。',64,'全唐诗/poet.song.21000.json','["人生長有兩般愁，愁死愁生未易休。", "或向利中窮力取，或于名上盡心求。", "多思唯恐晚得手，未老已聞先白頭。", "我有何功居彼上，其間掉臂獨無憂。"]'),
('4d736730-e555-4461-976c-4d5656ba4e41','自詠','邵雍','宋','宋诗','song-poetry','','[]','天下更無雙，無知無所長。',48,'全唐诗/poet.song.21000.json','["天下更無雙，無知無所長。", "年顔李文爽，風度賀知章。", "靜坐多茶飲，閑行或道裝。", "傍人休用笑，安樂是吾鄉。"]'),
('8d485a52-6239-48b5-ab0f-daec0ba7d767','中秋月','邵雍','宋','宋诗','song-poetry','','[]','一年一度中秋夜，十度中秋九度陰。',64,'全唐诗/poet.song.21000.json','["一年一度中秋夜，十度中秋九度陰。", "求滿直須當夜半，要明仍候到天心。", "無雲照處情非淺，不睡觀時意更深。", "徒愛古人詩句好，何堪千里共如今。"]'),
('7b868582-3db4-4b4c-a2da-f371318355b7','小車吟','邵雍','宋','宋诗','song-poetry','','[]','春暖秋凉兼景好，年豐身健更時和。',32,'全唐诗/poet.song.21000.json','["春暖秋凉兼景好，年豐身健更時和。", "如茵草上輕輕碾，似錦花間慢慢拕。"]'),
('e23f5232-1a56-4156-b6d7-631ad045f67a','晝夢','邵雍','宋','宋诗','song-poetry','','[]','夢裏到鄉關，鄉關二十年。',48,'全唐诗/poet.song.21000.json','["夢裏到鄉關，鄉關二十年。", "依稀新國土，隠約舊山川。", "身已煙霞外，人家道路邊。", "覺來猶在目，一餉但蕭然。"]'),
('eb91e816-e4a8-408c-b1b8-bb7673ea3673','晚步洛河灘','邵雍','宋','宋诗','song-poetry','','[]','晚步洛河灘，河灘石萬般。',48,'全唐诗/poet.song.21000.json','["晚步洛河灘，河灘石萬般。", "青黄有長短，大小或方圓。", "考彼多無數，求其用實難。", "琅玕在何處，止可使人歎。"]'),
('d3cb8054-90da-43b2-9fb3-328ac2f4aaa2','和李文思早秋五首  其一','邵雍','宋','宋诗','song-poetry','','[]','一雨洗觚稜，三川氣象清。',48,'全唐诗/poet.song.21000.json','["一雨洗觚稜，三川氣象清。", "林風傳顥氣，林葉送商聲。", "忽忽蓮生的，看看菊吐英。", "太平時裏老，何以報虛生。"]'),
('fed15a14-1293-49d2-aced-57af4ce33610','和李文思早秋五首  其二','邵雍','宋','宋诗','song-poetry','','[]','徑小新經雨，庭幽遍有苔。',48,'全唐诗/poet.song.21000.json','["徑小新經雨，庭幽遍有苔。", "風前閑意思，階下靜徘徊。", "不分筋骸老，難甘歲月催。", "時時藉芳草，頼有酒同盃。"]'),
('f4e8eb65-b34e-4450-9ec6-b74e23a4c6fc','和李文思早秋五首  其三','邵雍','宋','宋诗','song-poetry','','[]','王金秋已至，爍石景方蘭。',48,'全唐诗/poet.song.21000.json','["王金秋已至，爍石景方蘭。", "直養能希孟，閑居肯讓潘。", "竹間風彗彗，松罅月團團。", "洛社多賢友，人人可共歡。"]'),
('5ac2fcec-5ce1-412e-9ea5-c090f9e26fc4','和李文思早秋五首  其四','邵雍','宋','宋诗','song-poetry','','[]','池畔拖垂柳，欄邊笑晚花。',48,'全唐诗/poet.song.21000.json','["池畔拖垂柳，欄邊笑晚花。", "敗荷傾弊蓋，老檜露枯槎。", "歲暮驚時態，年高惜物華。", "東陵風未替，解憶故園瓜。"]'),
('5dc788b3-e608-49e3-904c-7f28b3d85eed','和李文思早秋五首  其五','邵雍','宋','宋诗','song-poetry','','[]','日脚雲微淡，林梢葉漸黄。',48,'全唐诗/poet.song.21000.json','["日脚雲微淡，林梢葉漸黄。", "可堪須變色，徹了爲侵霜。", "酒到難成醉，風來易得凉。", "老年何所欲，唯願且平康。"]'),
('76dd4728-445f-40b3-a14c-a2cf7652835b','堯夫何所有','邵雍','宋','宋诗','song-poetry','','[]','堯夫何所有，一色得天和。',48,'全唐诗/poet.song.21000.json','["堯夫何所有，一色得天和。", "夏住長生洞，冬居安樂窩。", "鶑花供放適，風月助吟哦。", "竊料人間樂，無如我最多。"]'),
('5adc361e-0786-479c-9224-41ded53e3ef7','長憶乍能言','邵雍','宋','宋诗','song-poetry','','[]','長憶乍能言，朝遊父母前。',48,'全唐诗/poet.song.21000.json','["長憶乍能言，朝遊父母前。", "方行初下膝，既老遂華顛。", "在昔四五歲，于今六十年。", "却看兒女戲，又喜又潸然。"]'),
('4872a7ac-d6d1-4217-b93c-4d153723e517','答友人','邵雍','宋','宋诗','song-poetry','','[]','何者名爲善處身，非唯能武又能文。',96,'全唐诗/poet.song.21000.json','["何者名爲善處身，非唯能武又能文。", "可行可止存諸己，或是或非繫在人。", "遍數古來賢所得，歷觀天下事須真。", "吉凶悔吝生乎動，剛毅木訥近於仁。", "易地皆然休計較，不言而信省開陳。", "雖居蠻貊亦行矣，無患鄉閭情未親。"]'),
('dc5b6e17-e79e-41f9-aa6c-6e986df978eb','獨坐吟  其一','邵雍','宋','宋诗','song-poetry','','[]','天告自丁寧，人多不肯聽。',48,'全唐诗/poet.song.21000.json','["天告自丁寧，人多不肯聽。", "四時皆有景，萬物豈無情。", "禍福眼前事，是非身後名。", "誰能事閑氣，浪與世人爭。"]'),
('6749bde0-afa9-4364-9039-a6bfe798de82','獨坐吟  其二','邵雍','宋','宋诗','song-poetry','','[]','天意自分明，人多不肯行。',48,'全唐诗/poet.song.21000.json','["天意自分明，人多不肯行。", "鶑花春乍暖，風月雨初晴。", "靜坐澄思慮，閑吟樂性情。", "誰能事閑氣，浪與世人爭。"]'),
('1e6cc38b-8123-45e4-b30e-874e827d8295','意未萌于心','邵雍','宋','宋诗','song-poetry','','[]','意未萌于心，言未出諸口。',48,'全唐诗/poet.song.21000.json','["意未萌于心，言未出諸口。", "神莫得而窺，人莫得而咎。", "君子貴慎獨，上不愧屋漏。", "人神亦吾心，口自處其後。"]'),
('c0d89faa-58fd-47bf-a358-d3bdcaebad0c','自適吟','邵雍','宋','宋诗','song-poetry','','[]','郟鄏城中，鳳凰樓下。',40,'全唐诗/poet.song.21000.json','["郟鄏城中，鳳凰樓下。", "風月庭除，鶑花臺榭。", "時和歲豐，閑行靜坐。", "朋好身安，清吟雅話。"]'),
('eacaef18-e1b4-46b7-aa20-baee52290a9e','老翁吟','邵雍','宋','宋诗','song-poetry','','[]','皤然一老翁，凡百事皆慵。',48,'全唐诗/poet.song.21000.json','["皤然一老翁，凡百事皆慵。", "舊物不盡記，故人難得逢。", "幽花渾在霧，殘夢半隨風。", "只且願天下，時和與歲豐。"]'),
('cc7e871f-6ab1-4fe7-b679-0706e07ea6d0','鐵如意吟','邵雍','宋','宋诗','song-poetry','','[]','此物鐵爲之，何嘗肯妄持。',48,'全唐诗/poet.song.21000.json','["此物鐵爲之，何嘗肯妄持。", "長隨大𤮕子，永伴小車兒。", "擊碎珊瑚處，敲殘牙齒時。", "誰能學此輩，纔始人鞭笞。"]'),
('9caf1192-11c9-4a9a-bed4-19beab5fd0cc','道裝吟  其一','邵雍','宋','宋诗','song-poetry','','[]','道家儀用此衣巾，只拜星辰不拜人。',32,'全唐诗/poet.song.21000.json','["道家儀用此衣巾，只拜星辰不拜人。", "何故堯夫須用拜，安知人不是星辰。"]'),
('ddcbc36c-5485-40ad-9680-312f3234a2f1','道裝吟  其二','邵雍','宋','宋诗','song-poetry','','[]','道家儀用此巾衣，師外曾聞更拜誰。',32,'全唐诗/poet.song.21000.json','["道家儀用此巾衣，師外曾聞更拜誰。", "何故堯夫須用拜，安知人不是吾師。"]'),
('a3806779-a102-4cfe-9877-e6fe6b04f182','道裝吟  其三','邵雍','宋','宋诗','song-poetry','','[]','安車麈尾道衣裝，里閈過從乃是常。',32,'全唐诗/poet.song.21000.json','["安車麈尾道衣裝，里閈過從乃是常。", "聞說洞天多似此，吾鄉殊不異仙鄉。"]'),
('cce33531-25e0-4f55-b353-fcd8b7afa46b','道裝吟  其四','邵雍','宋','宋诗','song-poetry','','[]','如知道只在人心，造化功夫自可尋。',32,'全唐诗/poet.song.21000.json','["如知道只在人心，造化功夫自可尋。", "若說衣巾便爲道，堯夫何者敢披襟。"]'),
('9fb011ab-8947-44f9-ac00-edac538899a3','四者吟','邵雍','宋','宋诗','song-poetry','','[]','目時然後視，耳時然後聽。',48,'全唐诗/poet.song.21000.json','["目時然後視，耳時然後聽。", "口時然後言，身時然後行。", "前不見厚祿，後不見重兵。", "惟其義所在，安知利與名。"]'),
('7baa90af-1a19-44b3-9f8a-935670c81b7a','偶得吟','邵雍','宋','宋诗','song-poetry','','[]','壯歲若奔馳，隨分受官職。',48,'全唐诗/poet.song.21000.json','["壯歲若奔馳，隨分受官職。", "所得唯錙銖，所喪無紀極。", "今日度一朝，明日過一夕。", "不免如路人，區區被勞役。"]'),
('574cb8a3-d15f-4b40-a619-31773c46451c','四事吟','邵雍','宋','宋诗','song-poetry','','[]','會有四不赴，時有四不出。',48,'全唐诗/poet.song.21000.json','["會有四不赴，時有四不出。", "無貴亦無賤，無固亦無必。", "里閈閑過從，身安心自逸。", "如此三十年，幸逢太平日。"]'),
('2405af63-9327-4fc0-8923-a38bc76384ae','偶春  其一','邵雍','宋','宋诗','song-poetry','','[]','美食無使饜，饜則不能受。',48,'全唐诗/poet.song.21000.json','["美食無使饜，饜則不能受。", "善人無使倦，倦則不能久。", "官小拜人喜，官高拜人恥。", "官職自外來，中心何若此。"]'),
('92f54425-9627-42dc-bde0-bdb58e7e7de0','偶春  其二','邵雍','宋','宋诗','song-poetry','','[]','才高命寡人，恥居人下。',21,'全唐诗/poet.song.21000.json','["才高命寡人，恥居人下。", "若不固窮，非知道者。"]'),
('fd163112-09cf-41b6-8a4a-76fa729b27b4','偶春  其三','邵雍','宋','宋诗','song-poetry','','[]','賢德之人，所居之處。',40,'全唐诗/poet.song.21000.json','["賢德之人，所居之處。", "如芝如蘭，使人愛慕。", "凶惡之人，所居之處。", "如虎如狼，使人怕怖。"]'),
('70e4c2e9-d03c-42d2-a2cb-26259af7f118','偶春  其四','邵雍','宋','宋诗','song-poetry','','[]','妻强夫殃，奴强主殃，臣强君殃。',35,'全唐诗/poet.song.21000.json','["妻强夫殃，奴强主殃，臣强君殃。", "尾大于身，冰堅于霜。", "辨之不早，國破家亡。"]'),
('f3f2e926-bdf4-448d-b3c6-fce78ac873b6','王勝之諫議見惠文房四寶內有巨硯尤佳因以謝之','邵雍','宋','宋诗','song-poetry','','[]','銅雀或常聞，未嘗聞金雀。',168,'全唐诗/poet.song.21000.json','["銅雀或常聞，未嘗聞金雀。", "始愧林下人，識物不甚博。", "金雀出何所，必出自靈嶽。", "剪斷白雲根，分破蒼岑角。", "既爲之巨硯，遂登于綸閣。", "水貯見溫潤，墨發知瀺濯。", "窗下喜鑑開，案前驚月落。", "見贈何慇懃，欲報和知璞。", "胡爲不且留，洪化用斟酌。", "胡爲不且留，賢人用選擢。", "胡爲不且留，姦人用誅削。", "胡爲不且留，生靈用安泊。", "則予何人哉，拜貺徒驚矍。", "須是筆如椽，方能無厚怍。"]'),
('c1a626ab-a13c-41c9-bf33-ae785411f576','再用晴窗氣暖墨花春謝王勝之諫議惠金雀硯','邵雍','宋','宋诗','song-poetry','','[]','硯名金雀世難倫，用報慙無天下珍。',32,'全唐诗/poet.song.21000.json','["硯名金雀世難倫，用報慙無天下珍。", "國士有詩偏雅處，晴窗氣暖墨花春。"]'),
('c861ab66-5824-42e1-8ec7-7d3d0c93ed62','題范忠獻公真','邵雍','宋','宋诗','song-poetry','','[]','范邵居洛陽，希夷居華山。',48,'全唐诗/poet.song.21000.json','["范邵居洛陽，希夷居華山。", "陳邵爲逸人，忠獻爲顯官。", "邵在范之後，陳在范之前。", "三人貌相類，兩人名相連。"]'),
('6c7c286e-8b17-4d70-83f0-4c37d092298f','觀物吟','邵雍','宋','宋诗','song-poetry','','[]','時有代謝，物有枯榮。',20,'全唐诗/poet.song.21000.json','["時有代謝，物有枯榮。", "人有衰盛，事有廢興。"]'),
('47cf49bb-5f92-41fc-a969-ea55a937a792','對花吟','邵雍','宋','宋诗','song-poetry','','[]','美酒豈無留客飲，好花猶解向人開。',32,'全唐诗/poet.song.21000.json','["美酒豈無留客飲，好花猶解向人開。", "多情不忍阻花意，未醉何須辭滿盃。"]');
